# ==================== 辅助函数（需要在配置函数之前定义）====================
def has_app_context():
    """检查是否在 Flask 应用上下文中"""
    try:
        return flask_has_app_context()
    except:
        return False


def normalize_display_text(text):
    """尽量修正常见的乱码字符串（仅用于展示层）"""
    if not isinstance(text, str) or not text:
        return text

    # 正常中文/英文内容不动，避免误伤
    if any(ord(ch) > 255 for ch in text):
        return text

    suspicious = ('Ã', 'Â', '�', 'æ', 'ç', 'å', 'ä', 'ö', 'ü', 'ß')
    if not any(ch in text for ch in suspicious):
        return text

    candidates = []
    for encoding in ('utf-8', 'gbk', 'cp936', 'big5'):
        try:
            candidate = text.encode('latin1').decode(encoding)
            if candidate and candidate != text:
                candidates.append(candidate)
        except Exception:
            pass

    if not candidates:
        return text

    def score(value):
        cjk = len(re.findall(r'[\u4e00-\u9fff]', value))
        bad = sum(value.count(ch) for ch in suspicious) + value.count('�')
        return cjk * 4 - bad * 6 - len(value) * 0.01

    best = max(candidates, key=score)
    return best if score(best) > score(text) else text


def fix_text_filter(text):
    return normalize_display_text(text)


def to_db_safe_text(text, max_length=None):
    """将文本转换为数据库安全格式，避免 4 字节字符在 utf8/utf8mb3 环境写入异常。"""
    if text is None:
        return None

    safe_text = text if isinstance(text, str) else str(text)
    if any(ord(ch) > 0xFFFF for ch in safe_text):
        safe_text = ''.join(
            ch if ord(ch) <= 0xFFFF else f'\\U{ord(ch):08X}'
            for ch in safe_text
        )

    if isinstance(max_length, int) and max_length > 0 and len(safe_text) > max_length:
        safe_text = safe_text[:max_length]

    return safe_text


# ==================== 数据库配置缓存（在 db 初始化前定义）====================
_db_config_cache = {}  # 内存缓存，减少数据库查询
_db_config_cache_time = {}  # 缓存时间
DB_CONFIG_CACHE_TTL = 60  # 缓存有效期（秒）


def get_db_config(key: str, default=None, use_cache=True):
    """从数据库获取配置（带缓存）- 延迟加载"""
    global _db_config_cache, _db_config_cache_time
    
    # 检查缓存
    if use_cache and key in _db_config_cache:
        if time.time() - _db_config_cache_time.get(key, 0) < DB_CONFIG_CACHE_TTL:
            return _db_config_cache[key]
    
    try:
        # 确保在应用上下文中
        if not has_app_context():
            return default
        
        # 延迟导入，避免循环依赖
        from flask import current_app
        
        # 直接查询数据库（不依赖 SystemConfig 类）
        result = db.session.execute(
            db.text("SELECT config_value FROM system_config WHERE config_key = :key"),
            {'key': key}
        ).fetchone()
        
        if result and result[0]:
            value = json.loads(result[0])
            # 更新缓存
            _db_config_cache[key] = value
            _db_config_cache_time[key] = time.time()
            return value
        
        return default
    except Exception as e:
        # 表可能不存在，静默返回默认值
        return default


def set_db_config(key: str, value: dict, description: str = None):
    """保存配置到数据库 - 延迟加载"""
    global _db_config_cache, _db_config_cache_time
    
    try:
        if not has_app_context():
            return False
        
        preferred_config_value = json.dumps(value, ensure_ascii=False)
        ascii_safe_config_value = json.dumps(value, ensure_ascii=True)
        now = datetime.now()

        def _write_config(config_value):
            # 使用 UPSERT 操作（兼容 MySQL 和 SQLite）
            existing = db.session.execute(
                db.text("SELECT id FROM system_config WHERE config_key = :key"),
                {'key': key}
            ).fetchone()
            
            if existing:
                db.session.execute(
                    db.text("""UPDATE system_config 
                              SET config_value = :value, description = :desc, updated_at = :now 
                              WHERE config_key = :key"""),
                    {'key': key, 'value': config_value, 'desc': description, 'now': now}
                )
            else:
                db.session.execute(
                    db.text("""INSERT INTO system_config (config_key, config_value, description, updated_at) 
                              VALUES (:key, :value, :desc, :now)"""),
                    {'key': key, 'value': config_value, 'desc': description, 'now': now}
                )
            
            db.session.commit()

        # 某些 MySQL utf8/utf8mb3 环境在遇到 4 字节字符（常见于 emoji）时，
        # 可能不是普通报错，而是直接让上游连接异常。这里提前改用 ASCII 转义 JSON，
        # 读取时 json.loads 会自动还原原始字符，避免再次触发该类问题。
        contains_non_bmp = any(ord(ch) > 0xFFFF for ch in preferred_config_value)
        if contains_non_bmp:
            _write_config(ascii_safe_config_value)
        else:
            try:
                _write_config(preferred_config_value)
            except Exception as primary_error:
                db.session.rollback()
                # 兜底：如果不是显式检测到的 4 字节字符，但数据库仍拒绝原始 JSON，
                # 则再回退一次 ASCII 转义写法，尽量保证配置可保存。
                if ascii_safe_config_value == preferred_config_value:
                    raise
                print(f"[WARNING] 保存配置到数据库 {key} 首次失败，尝试 ASCII 转义重试: {primary_error}")
                _write_config(ascii_safe_config_value)
        
        # 更新缓存
        _db_config_cache[key] = value
        _db_config_cache_time[key] = time.time()
        
        return True
    except Exception as e:
        print(f"[WARNING] 保存配置到数据库 {key} 失败: {e}")
        db.session.rollback()
        return False


def clear_db_config_cache(key: str = None):
    """清除配置缓存"""
    global _db_config_cache, _db_config_cache_time
    
    if key:
        _db_config_cache.pop(key, None)
        _db_config_cache_time.pop(key, None)
    else:
        _db_config_cache.clear()
        _db_config_cache_time.clear()


def get_all_db_configs():
    """获取所有数据库配置"""
    try:
        if not has_app_context():
            return {}
        
        results = db.session.execute(
            db.text("SELECT config_key, config_value FROM system_config")
        ).fetchall()
        
        configs = {}
        for row in results:
            try:
                configs[row[0]] = json.loads(row[1]) if row[1] else None
            except:
                configs[row[0]] = row[1]
        
        return configs
    except Exception as e:
        print(f"[WARNING] 获取所有配置失败: {e}")
        return {}


def delete_db_config(key: str):
    """删除指定配置"""
    try:
        if not has_app_context():
            return False
        
        db.session.execute(
            db.text("DELETE FROM system_config WHERE config_key = :key"),
            {'key': key}
        )
        db.session.commit()
        clear_db_config_cache(key)
        return True
    except Exception as e:
        print(f"[WARNING] 删除配置 {key} 失败: {e}")
        db.session.rollback()
        return False


def get_all_db_configs(prefix: str = None):
    """获取所有配置（可选前缀过滤）"""
    try:
        if not has_app_context():
            return {}
        
        if prefix:
            result = db.session.execute(
                db.text("SELECT config_key, config_value FROM system_config WHERE config_key LIKE :prefix"),
                {'prefix': f'{prefix}%'}
            )
        else:
            result = db.session.execute(
                db.text("SELECT config_key, config_value FROM system_config")
            )
        
        configs = {}
        for row in result:
            key = row[0]
            try:
                value = json.loads(row[1]) if row[1] else {}
            except:
                value = row[1]
            configs[key] = value
        
        return configs
    except Exception as e:
        print(f"[WARNING] 获取配置列表失败: {e}")
        return {}


