# ==================== 剧集入库通知聚合 ====================
# 同一部剧的多集入库会聚合为一条通知，等待 AGGREGATE_DELAY 秒无新集后统一发送
AGGREGATE_DELAY = int(os.getenv('LIBRARY_NOTIFY_DELAY', '300'))  # 默认5分钟(300秒)
_library_notify_pending = {}   # key: series_key → {timer, data}
_library_notify_lock = threading.Lock()


def _flush_aggregated_notification(series_key):
    """定时器触发：发送聚合后的剧集入库通知"""
    with _library_notify_lock:
        pending = _library_notify_pending.pop(series_key, None)
    if not pending:
        return
    try:
        info = pending['data']
        episodes = sorted(info['episodes'])  # [(season, episode), ...]
        episode_names = info.get('episode_names', {})

        # 按季分组
        from collections import defaultdict
        seasons = defaultdict(list)
        for s, e in episodes:
            seasons[s].append(e)

        # 构建季集描述
        parts = []
        single_episode_name = None  # 单集时的集名
        for s_num in sorted(seasons.keys()):
            eps = seasons[s_num]
            if len(eps) == 1:
                ep_tag = f"S{s_num:02d}E{eps[0]:02d}"
                # 单集：尝试附带集名（如 "第十三集"）
                ep_name = episode_names.get((s_num, eps[0]))
                if ep_name:
                    single_episode_name = ep_name
                parts.append(ep_tag)
            else:
                eps_sorted = sorted(eps)
                # 检查是否连续
                if eps_sorted[-1] - eps_sorted[0] == len(eps_sorted) - 1:
                    parts.append(f"S{s_num:02d} E{eps_sorted[0]:02d}-E{eps_sorted[-1]:02d}")
                else:
                    ep_str = '、'.join(str(e) for e in eps_sorted)
                    parts.append(f"S{s_num:02d} 第{ep_str}集")

        season_episode = ' '.join(parts)
        # 如果只有一集且有集名，在季集描述后附加集名
        if len(episodes) == 1 and single_episode_name:
            season_episode = f"{season_episode} {single_episode_name}"
        file_count = len(episodes)

        with app.app_context():
            app.logger.info(f'发送聚合入库通知: {info["title"]} {season_episode} ({file_count}集)')
            send_general_library_notification(
                title=info['title'],
                year=info.get('year'),
                season_episode=season_episode,
                vote_average=info.get('vote_average'),
                category=info.get('category'),
                resource_quality=info.get('resource_quality'),
                file_count=file_count,
                total_size=info.get('total_size'),
                tmdb_id=info.get('tmdb_id'),
                release_group=None,
                time_usage=None,
                overview=info.get('overview'),
                poster_path=info.get('poster_path')
            )
    except Exception as e:
        try:
            with app.app_context():
                app.logger.error(f'聚合入库通知发送失败: {e}')
        except:
            pass


def _queue_episode_notification(series_key, title, year, season_num, episode_num,
                                 vote_average, category, resource_quality,
                                 total_size, tmdb_id, overview, poster_path,
                                 episode_name=None):
    """将单集入库事件加入聚合队列，重置定时器"""
    with _library_notify_lock:
        if series_key in _library_notify_pending:
            entry = _library_notify_pending[series_key]
            # 取消旧定时器
            entry['timer'].cancel()
            # 追加集数
            entry['data']['episodes'].append((season_num or 0, episode_num or 0))
            # 记录每集的集名（用于单集通知时显示）
            if episode_name:
                entry['data'].setdefault('episode_names', {})[(season_num or 0, episode_num or 0)] = episode_name
            # 累加文件大小
            if total_size and entry['data'].get('total_size'):
                try:
                    # 尝试把字符串大小转为数值累加
                    pass  # 大小格式复杂，保留最新值即可
                except:
                    pass
            if total_size:
                entry['data']['total_size'] = total_size
            # 更新画质（取最高）
            if resource_quality:
                entry['data']['resource_quality'] = resource_quality
        else:
            episode_names = {}
            if episode_name:
                episode_names[(season_num or 0, episode_num or 0)] = episode_name
            entry = {
                'data': {
                    'title': title,
                    'year': year,
                    'episodes': [(season_num or 0, episode_num or 0)],
                    'episode_names': episode_names,
                    'vote_average': vote_average,
                    'category': category,
                    'resource_quality': resource_quality,
                    'total_size': total_size,
                    'tmdb_id': tmdb_id,
                    'overview': overview,
                    'poster_path': poster_path,
                }
            }
            _library_notify_pending[series_key] = entry

        # 创建新定时器
        timer = threading.Timer(AGGREGATE_DELAY, _flush_aggregated_notification, args=[series_key])
        timer.daemon = True
        entry['timer'] = timer
        timer.start()

    app.logger.info(f'剧集入库已加入聚合队列: {title} S{season_num or 0:02d}E{episode_num or 0:02d}, '
                    f'当前累计 {len(entry["data"]["episodes"])} 集, {AGGREGATE_DELAY}秒后发送')


# ==================== 代理配置 ====================
# 支持 HTTP/HTTPS 和 SOCKS5 代理，用于中国大陆服务器访问外网
HTTP_PROXY = os.getenv('HTTP_PROXY', '') or os.getenv('http_proxy', '')
HTTPS_PROXY = os.getenv('HTTPS_PROXY', '') or os.getenv('https_proxy', '')
SOCKS5_PROXY = os.getenv('SOCKS5_PROXY', '') or os.getenv('socks5_proxy', '')
ALL_PROXY = os.getenv('ALL_PROXY', '') or os.getenv('all_proxy', '')
NO_PROXY = os.getenv('NO_PROXY', 'localhost,127.0.0.1') or os.getenv('no_proxy', 'localhost,127.0.0.1')


def get_proxy_config():
    """获取代理配置（统一入口）"""
    proxies = {}

    # 优先使用 SOCKS5 代理
    if SOCKS5_PROXY:
        proxies = {
            'http': SOCKS5_PROXY,
            'https': SOCKS5_PROXY
        }
    # 其次使用 ALL_PROXY
    elif ALL_PROXY:
        proxies = {
            'http': ALL_PROXY,
            'https': ALL_PROXY
        }
    # 兼容旧版 PROXY_URL（低优先级）
    elif PROXY_URL:
        proxies = {
            'http': PROXY_URL,
            'https': PROXY_URL
        }
    # 最后使用 HTTP/HTTPS 代理
    elif HTTP_PROXY or HTTPS_PROXY:
        # 若仅配置了其中一个，也同时兜底给 http/https，避免半代理状态
        fallback = HTTPS_PROXY or HTTP_PROXY
        proxies['http'] = HTTP_PROXY or fallback
        proxies['https'] = HTTPS_PROXY or fallback

    return proxies if proxies else None


def _extract_host(target: str) -> str:
    if not target:
        return ''
    value = target.strip()
    if not value:
        return ''
    if '://' in value:
        return (urlparse(value).hostname or '').strip().lower()
    # 兼容 host:port 输入
    if value.startswith('[') and ']' in value:
        return value[1:value.find(']')].strip().lower()
    return value.split(':', 1)[0].strip().lower()


def should_bypass_proxy(target: str) -> bool:
    """判断目标地址是否应绕过代理（NO_PROXY + 常见内网地址）"""
    host = _extract_host(target)
    if not host:
        return False

    if host == 'localhost':
        return True

    try:
        ip = ipaddress.ip_address(host)
        if ip.is_loopback or ip.is_private or ip.is_link_local:
            return True
    except ValueError:
        pass

    no_proxy_items = [item.strip().lower() for item in (NO_PROXY or '').split(',') if item.strip()]
    for rule in no_proxy_items:
        if rule == '*':
            return True

        normalized = _extract_host(rule) if '://' in rule else rule.split(':', 1)[0].strip()
        normalized = normalized.lstrip('.')
        if not normalized:
            continue

        if '/' in normalized:
            try:
                ip = ipaddress.ip_address(host)
                network = ipaddress.ip_network(normalized, strict=False)
                if ip in network:
                    return True
            except Exception:
                continue

        if host == normalized or host.endswith(f'.{normalized}'):
            return True

    return False


def apply_proxy_to_session(session: requests.Session, target: str = '') -> requests.Session:
    """按统一代理规则为 session 注入代理，并支持按目标地址绕过"""
    proxy_config = get_proxy_config()
    if not proxy_config:
        return session
    if target and should_bypass_proxy(target):
        return session
    session.proxies.update(proxy_config)
    return session


def get_proxied_session(target: str = ''):
    """获取按统一代理规则处理后的 requests Session"""
    session = requests.Session()
    return apply_proxy_to_session(session, target)


# 创建全局代理 Session（用于访问外网服务如 Telegram、TMDB）
PROXY_SESSION = get_proxied_session()

# 更新 http_session 以使用代理配置（用于 TMDB API 等外网请求）
