def load_system_config_from_file():
    """从文件加载系统配置（原始方法，作为回退）"""
    config = get_default_system_config()
    
    # 从环境变量读取（作为默认值）
    config['emby']['url'] = os.getenv('EMBY_URL', '')
    config['emby']['api_key'] = os.getenv('EMBY_API_KEY', '')
    config['emby']['webhook_secret'] = os.getenv('EMBY_WEBHOOK_SECRET', '')
    
    config['telegram']['bot_token'] = os.getenv('TELEGRAM_BOT_TOKEN', '')
    config['telegram']['chat_id'] = os.getenv('TELEGRAM_CHAT_ID', '')
    config['telegram']['group_id'] = os.getenv('TELEGRAM_GROUP_ID', '')
    
    config['search']['strategy'] = os.getenv('PT_SEARCH_STRATEGY', 'all')
    config['search']['poll_interval'] = int(os.getenv('DOWNLOAD_POLL_INTERVAL', '10'))
    
    config['tmdb']['api_key'] = os.getenv('TMDB_API_KEY', '')
    
    config['request_limit']['max_daily'] = int(os.getenv('MAX_DAILY_REQUESTS', '3'))
    
    # 从配置文件读取（优先级高于环境变量）
    if os.path.exists(SYSTEM_CONFIG_FILE):
        try:
            with open(SYSTEM_CONFIG_FILE, 'r', encoding='utf-8') as f:
                file_config = json.load(f)
                for section in config:
                    if section in file_config:
                        for key in config[section]:
                            if key in file_config[section]:
                                if isinstance(config[section][key], dict) and isinstance(file_config[section][key], dict):
                                    config[section][key].update(file_config[section][key])
                                elif file_config[section][key] not in ('', None):
                                    config[section][key] = file_config[section][key]
        except Exception as e:
            print(f"[WARNING] 读取系统配置文件失败: {e}")
    
    return config


def save_system_config(config, sections=None):
    """保存系统配置 - 同时保存到数据库和文件

    sections:
        指定仅保存的配置分区列表（例如 ['telegram', 'emby']）。
        为空时保持旧行为：尝试保存 config 中的全部已知分区。
    """
    db_success = True
    file_success = True
    _save_failures = []
    known_sections = [
        ('admin', CONFIG_KEY_ADMIN, '管理员配置'),
        ('emby', CONFIG_KEY_EMBY, 'Emby 服务器配置'),
        ('telegram', CONFIG_KEY_TELEGRAM, 'Telegram BOT配置'),
        ('search', CONFIG_KEY_SEARCH, '搜索策略配置'),
        ('tmdb', CONFIG_KEY_TMDB, 'TMDB API 配置'),
        ('request_limit', CONFIG_KEY_REQUEST_LIMIT, '求片限制配置'),
        ('category', CONFIG_KEY_CATEGORY, '二级分类策略'),
        ('checkin', CONFIG_KEY_CHECKIN, '签到系统配置'),
        ('subscription_expire', CONFIG_KEY_SUBSCRIPTION_EXPIRE, '订阅过期管理配置'),
        ('invite_reward', CONFIG_KEY_INVITE_REWARD, '邀请返利配置'),
        ('email', CONFIG_KEY_EMAIL, '邮件SMTP配置'),
        ('login_notify', CONFIG_KEY_LOGIN_NOTIFY, '登录通知配置'),
        ('expire_remind', CONFIG_KEY_EXPIRE_REMIND, '到期提醒配置'),
        ('ranking', CONFIG_KEY_RANKING, '播放排行配置'),
        ('upgrade', CONFIG_KEY_UPGRADE, '在线升级配置'),
    ]

    target_sections = None
    if sections:
        requested = {
            str(section).strip()
            for section in sections
            if isinstance(section, str) and section.strip()
        }
        if requested:
            target_sections = requested
    
    # 保存到数据库
    try:
        if has_app_context():
            for section_name, config_key, description in known_sections:
                if target_sections is not None and section_name not in target_sections:
                    continue
                if section_name not in config:
                    continue
                if not set_db_config(config_key, config[section_name], description):
                    _save_failures.append(section_name)
            
            if _save_failures:
                db_success = False
                print(f"[WARNING] 以下配置保存到数据库失败: {', '.join(_save_failures)}")
            else:
                print("[CONFIG] 配置已保存到数据库")
        else:
            print("[WARNING] 无应用上下文，跳过数据库保存")
            db_success = False
    except Exception as e:
        print(f"[ERROR] 保存配置到数据库失败: {e}")
        import traceback
        traceback.print_exc()
        db_success = False
    
    # 同时保存到文件（作为备份）
    try:
        os.makedirs(os.path.dirname(SYSTEM_CONFIG_FILE), exist_ok=True)
        with open(SYSTEM_CONFIG_FILE, 'w', encoding='utf-8') as f:
            json.dump(config, f, ensure_ascii=False, indent=2)
        print(f"[CONFIG] 配置已保存到文件: {SYSTEM_CONFIG_FILE}")
        file_success = True
    except Exception as e:
        print(f"[WARNING] 保存配置文件失败: {e}")
        file_success = False
    
    # 必须双写成功，避免“文件成功但数据库仍旧”造成后台显示已保存但实际回读旧值
    return db_success and file_success

def get_system_config():
    """获取当前系统配置"""
    return load_system_config()

