@app.before_request
def check_admin_permission():
    """基于URL路径的权限检查中间件"""
    path = request.path
    
    # 只检查管理后台相关路径
    if not (path.startswith('/admin') or path.startswith('/api/admin')):
        return
    
    # 跳过不需要权限检查的路径
    skip_paths = ['/admin', '/api/admin-login', '/api/admin-logout', 
                  '/api/admin/current-permissions', '/api/admin/admins']
    if path in skip_paths:
        return
    
    # 只有登录的管理员才需要检查权限
    if not session.get('admin_logged_in'):
        return

    def _deny_super_admin_only(message: str):
        if session.get('admin_user_id'):
            admin_user = db.session.get(AdminUser, session.get('admin_user_id'))
            if admin_user and admin_user.is_super:
                return None
        return jsonify({'error': message}), 403

    if path.startswith('/api/admin/admins'):
        denied = _deny_super_admin_only('仅超级管理员可管理管理员')
        if denied is not None:
            return denied
        return

    admin_id = session.get('admin_user_id')
    if not admin_id:
        return admin_access_denied('管理员会话已过期，请重新登录')

    # 检查是否超级管理员
    if session.get('admin_is_super'):
        return
    
    try:
        admin_user = db.session.get(AdminUser, admin_id)
        if not admin_user or not admin_user.is_active:
            return  # admin_required 会处理
        
        if admin_user.is_super:
            return
        
        # 匹配URL到权限
        required_perm = None
        for url_prefix, perm in ADMIN_URL_PERMISSION_MAP.items():
            if path.startswith(url_prefix):
                required_perm = perm
                break
        
        if required_perm and not admin_user.has_permission(required_perm):
            perm_name = ADMIN_PERMISSION_GROUPS.get(required_perm, required_perm)
            return jsonify({'error': f'无权限执行此操作（需要: {perm_name}）'}), 403
    except Exception as e:
        app.logger.warning(f'权限检查异常: {e}')


@app.after_request
def log_response(response):
    """记录响应状态和优化响应头"""
    # ===== 安全响应头 =====
    response.headers['X-Content-Type-Options'] = 'nosniff'
    response.headers['X-Frame-Options'] = 'SAMEORIGIN'
    response.headers['X-XSS-Protection'] = '1; mode=block'
    response.headers['Referrer-Policy'] = 'strict-origin-when-cross-origin'
    
    # 静态文件缓存（1小时）
    if request.path.startswith('/static/'):
        response.cache_control.max_age = 3600
        response.cache_control.public = True
        return response
    
    # API 响应不缓存（排除文件下载）
    if request.path.startswith('/api/') or request.is_json or request.method in ['POST', 'PUT', 'DELETE']:
        if not response.headers.get('Content-Disposition', '').startswith('attachment'):
            response.cache_control.no_cache = True
            response.cache_control.no_store = True
            response.cache_control.must_revalidate = True

    # HTML 页面也不缓存，避免模板更新后仍显示旧界面
    content_type = response.headers.get('Content-Type', '')
    if 'text/html' in content_type:
        response.cache_control.no_cache = True
        response.cache_control.no_store = True
        response.cache_control.must_revalidate = True
        response.cache_control.max_age = 0
        response.headers['Pragma'] = 'no-cache'
    
    # Gzip 压缩大响应（提升传输速度）
    # 跳过文件下载（Content-Disposition: attachment）和显式标记跳过的响应
    skip_gzip = (
        response.headers.get('X-Skip-Gzip') or
        (response.headers.get('Content-Disposition', '').startswith('attachment'))
    )
    if not skip_gzip and response.content_length and response.content_length > 1000:
        if 'gzip' in request.headers.get('Accept-Encoding', '').lower():
            response.direct_passthrough = False
            if response.data:
                gzip_buffer = gzip.compress(response.data, compresslevel=5)
                response.data = gzip_buffer
                response.headers['Content-Encoding'] = 'gzip'
                response.headers['Content-Length'] = len(gzip_buffer)
                response.headers['Vary'] = 'Accept-Encoding'
    # 清理内部标记头
    response.headers.pop('X-Skip-Gzip', None)
    
    # 记录错误响应（自动提取 JSON 中的 error 详情）
    if response.status_code >= 400:
        error_detail = ''
        try:
            if response.content_type and 'json' in response.content_type:
                resp_data = response.get_json(silent=True)
                if resp_data:
                    error_detail = resp_data.get('error', '') or resp_data.get('message', '')
        except Exception:
            pass
        if error_detail:
            app.logger.warning(f'{request.method} {request.path} - Status: {response.status_code} - {error_detail}')
        else:
            app.logger.warning(f'{request.method} {request.path} - Status: {response.status_code}')
    
    return response


# 全局错误处理
def _expects_json_error() -> bool:
    """判断当前请求是否应返回 JSON 错误响应。"""
    if request.path.startswith('/api/'):
        return True
    if request.is_json:
        return True
    if request.headers.get('X-Requested-With') == 'XMLHttpRequest':
        return True
    accept = (request.headers.get('Accept') or '').lower()
    return 'application/json' in accept


@app.errorhandler(400)
def bad_request_error(error):
    app.logger.warning(f'400 错误: {error}')
    if _expects_json_error():
        return jsonify({'success': False, 'error': '请求格式错误，请检查输入后重试'}), 400
    return jsonify({'error': '请求格式错误'}), 400


@app.errorhandler(415)
def unsupported_media_type_error(error):
    app.logger.warning(f'415 错误: {error}')
    if _expects_json_error():
        return jsonify({'success': False, 'error': '请求内容类型不正确，请重试'}), 415
    return jsonify({'error': '不支持的请求内容类型'}), 415


@app.errorhandler(404)
def not_found(error):
    # 静默忽略浏览器/旧SW缓存自动请求的资源文件
    ignored_paths = (
        '/favicon.ico',
        '/apple-touch-icon.png',
        '/apple-touch-icon-precomposed.png',
        '/static/logo.png',        # 旧版 Service Worker 缓存残留
        '/static/manifest.json',   # 旧版 Service Worker 缓存残留
    )
    if request.path in ignored_paths:
        return '', 204
    app.logger.warning(f'404 错误: {request.path}')
    if request.path.startswith('/api/') or request.is_json:
        return jsonify({'error': '请求的资源不存在'}), 404
    return jsonify({'error': '页面不存在'}), 404


@app.errorhandler(500)
def internal_error(error):
    app.logger.error(f'500 错误: {error}', exc_info=True)
    db.session.rollback()
    if request.is_json:
        return jsonify({'error': '服务器内部错误'}), 500
    return jsonify({'error': '服务器内部错误', 'detail': str(error)}), 500


# 数据库模型 - 映射到已存在的emby表
class User(db.Model):
    __tablename__ = 'emby'
    
    tg = db.Column(db.BigInteger, primary_key=True, autoincrement=False)  # 用户ID（主键，系统生成）
    telegram_id = db.Column(db.BigInteger, nullable=True, unique=True, index=True)  # Telegram ID（通过 /bind 命令绑定）
    embyid = db.Column(db.String(255), nullable=True)  # Emby用户ID
    name = db.Column(db.String(255), nullable=True)  # 网站用户名（登录用）
    emby_name = db.Column(db.String(255), nullable=True)  # Emby用户名（独立于网站用户名）
    pwd = db.Column(db.String(255), nullable=True)  # 密码
    pwd2 = db.Column(db.String(255), nullable=True)  # 备用密码
    lv = db.Column(db.String(1), default='d')  # 用户等级: a=旧白名单(已废弃,等同b), b=普通, c=禁用, d=无账号
    cr = db.Column(db.DateTime, nullable=True)  # 创建时间
    ex = db.Column(db.DateTime, nullable=True)  # 过期时间
    us = db.Column(db.Integer, default=1)  # 使用状态
    iv = db.Column(db.Integer, default=0)  # 邀请数
    ch = db.Column(db.DateTime, nullable=True)  # 签到时间
    coins = db.Column(db.Integer, default=0)  # 签到积分（货币）
    email = db.Column(db.String(255), nullable=True)  # 绑定邮箱（用于找回密码、接收通知）
    
    # 个性化邀请返利配置（管理员可为每个用户单独设置）
    invite_reward_mode = db.Column(db.String(20), nullable=True)  # once/recurring/None(跟随全局)
    invite_reward_percent = db.Column(db.Float, nullable=True)  # 0-100, None=跟随全局
    
    # 封禁前状态备份（用于解除封禁时恢复）
    ban_prev_lv = db.Column(db.String(1), nullable=True)  # 封禁前的等级
    ban_prev_ex = db.Column(db.DateTime, nullable=True)  # 封禁前的到期时间
    ban_time = db.Column(db.DateTime, nullable=True)  # 封禁时间
    ban_reason = db.Column(db.String(500), nullable=True)  # 封禁原因
    
    # 会话令牌（用于使用户退出登录）
    session_token = db.Column(db.String(64), nullable=True)  # 登录时生成，重置密码时更新
    
    # 关系
    requests = db.relationship('MovieRequest', backref='user', lazy=True, foreign_keys='MovieRequest.user_tg')

    @property
    def is_admin(self):
        """管理员判断：不再使用用户名列表，管理后台使用独立的安全入口登录"""
        # 此属性保留用于兼容性，但始终返回 False
        # 管理后台现在使用独立的账号密码认证
        return False
    
    @property
    def is_active(self):
        """检查用户是否可用：必须是A或B等级"""
        # C = 已禁用用户，D = 无账号用户，都不能使用
        if self.lv not in ['a', 'b']:
            return False
        
        # A = 白名单用户（ex=9999-12-31，永不过期）
        # B = 普通用户，按 ex 判断
        if self.ex:
            return datetime.now() < self.ex
        return False  # 没有过期时间视为非活跃
    
    @property
    def username(self):
        """返回网站用户名"""
        return self.name
    
    @property
    def display_name(self):
        """返回显示名称（优先Emby用户名，其次网站用户名）"""
        return self.emby_name or self.name
    
    def get_daily_limit(self):
        """根据用户类型返回每日求片限制
        - 管理员: 无限制（在 can_request 中单独处理）
        - 白名单用户 (套餐plan_type='whitelist'): 从配置读取 (默认3次/天)
        - 订阅用户 (有有效订阅): 从配置读取 (默认1次/天)
        - C级用户 (已禁用): 从配置读取 (默认0次/天)
        - 未订阅用户: 从配置读取 (默认0次/天)
        """
        # 读取配置
        config = load_system_config()
        limit_config = config.get('request_limit', {})
        
        # C级: 已禁用用户
        if self.lv == 'c':
            return limit_config.get('level_c', 0)
        
        if is_whitelist_user(self):
            return limit_config.get('level_a', 3)
        if self.lv == 'b' and self.ex and self.ex > datetime.now():
            return limit_config.get('level_b', 1)
        
        # 未订阅用户
        return limit_config.get('level_d', 0)

    def get_today_request_count(self):
        """获取今日求片次数（包括所有状态）"""
        # 使用本地时间计算今日范围（数据库存储的是本地时间）
        now_local = datetime.now()
        today_start = now_local.replace(hour=0, minute=0, second=0, microsecond=0)
        today_end = today_start + timedelta(days=1)
        
        return MovieRequest.query.filter(
            MovieRequest.user_tg == self.tg,
            MovieRequest.created_at >= today_start,
            MovieRequest.created_at < today_end
        ).count()

    def can_request(self):
        if not self.is_active:
            return False
        if self.is_admin:
            return True
        return self.get_today_request_count() < self.get_daily_limit()


class MovieRequest(db.Model):
    __tablename__ = 'movie_requests'
    
    id = db.Column(db.Integer, primary_key=True)
    user_tg = db.Column(db.BigInteger, db.ForeignKey('emby.tg'), nullable=False)  # 关联到emby表的tg字段
    tmdb_id = db.Column(db.Integer, nullable=False)
    title = db.Column(db.String(200), nullable=False)
    year = db.Column(db.String(10))
    poster_path = db.Column(db.String(200))
    overview = db.Column(db.Text)
    media_type = db.Column(db.String(20), default='movie')  # movie 或 tv
    # 剧集选择字段（仅对 tv 类型有效）
    request_type = db.Column(db.String(20), default='all')  # all=全剧, season=指定季, episode=指定集
    season_number = db.Column(db.Integer)  # 指定的季数
    episode_number = db.Column(db.Integer)  # 指定的集数
    total_seasons = db.Column(db.Integer)  # 总季数（用于显示）
    status = db.Column(db.String(20), default='pending')  # pending, approved, rejected, completed
    created_at = db.Column(db.DateTime, default=lambda: datetime.now())
    updated_at = db.Column(db.DateTime, default=lambda: datetime.now(), onupdate=lambda: datetime.now())
    admin_note = db.Column(db.Text)
    user_note = db.Column(db.Text)  # 用户备注
    download_task = db.relationship('DownloadTask', back_populates='request', uselist=False)
    
    def get_request_scope(self):
        """获取求片范围的可读描述"""
        if self.media_type == 'movie':
            return '电影'
        if self.request_type == 'all':
            return f'全剧 ({self.total_seasons}季)' if self.total_seasons else '全剧'
        elif self.request_type == 'season':
            return f'第{self.season_number}季'
        elif self.request_type == 'episode':
            return f'S{str(self.season_number).zfill(2)}E{str(self.episode_number).zfill(2)}'
        return ''


class DownloadTask(db.Model):
    __tablename__ = 'download_tasks'

    id = db.Column(db.Integer, primary_key=True)
    request_id = db.Column(db.Integer, db.ForeignKey('movie_requests.id'), nullable=False, unique=True)
    torrent_name = db.Column(db.String(255), nullable=False)
    torrent_hash = db.Column(db.String(64))
    source = db.Column(db.String(50), default='MoviePilot')
    download_url = db.Column(db.String(512))
    qb_tag = db.Column(db.String(128))
    status = db.Column(db.String(20), default='queued')
    progress = db.Column(db.Float, default=0.0)
    download_speed = db.Column(db.Integer, default=0)  # Bytes/s
    eta = db.Column(db.Integer, default=-1)
    error_message = db.Column(db.Text)
    retry_count = db.Column(db.Integer, default=0)  # 重试次数
    max_retries = db.Column(db.Integer, default=3)  # 最大重试次数
    last_retry_at = db.Column(db.DateTime)  # 最后重试时间
    created_at = db.Column(db.DateTime, default=lambda: datetime.now())
    updated_at = db.Column(db.DateTime, default=lambda: datetime.now(), onupdate=lambda: datetime.now())
    finished_at = db.Column(db.DateTime)

    request = db.relationship('MovieRequest', back_populates='download_task')

    def to_dict(self):
        """转换为字典格式"""
        return {
            'id': self.id,
            'request_id': self.request_id,
            'torrent_name': self.torrent_name,
            'torrent_hash': self.torrent_hash,
            'source': self.source,
            'status': self.status,
            'progress': self.progress or 0,
            'download_speed': self.download_speed or 0,
            'eta': self.eta if self.eta is not None else -1,
            'error_message': self.error_message,
            'retry_count': self.retry_count or 0,
            'max_retries': self.max_retries or 3,
            'created_at': self.created_at.isoformat() if self.created_at else None,
            'updated_at': self.updated_at.isoformat() if self.updated_at else None,
            'finished_at': self.finished_at.isoformat() if self.finished_at else None,
        }

    def can_retry(self):
        """检查是否可以重试"""
        return (self.retry_count or 0) < (self.max_retries or 3) and self.status == 'failed'


def generate_next_user_id():
    """生成下一个可用的正整数用户 ID（从 1000 开始递增）"""
    max_tg = db.session.query(db.func.max(User.tg)).scalar()
    if max_tg is None or max_tg < 1000:
        return 1000
    return max_tg + 1


def get_latest_active_subscription(user):
    """获取用户最新的有效订阅记录"""
    if not user:
        return None
    return Subscription.query.filter_by(
        user_tg=user.tg,
        status='active'
    ).order_by(Subscription.end_date.desc(), Subscription.created_at.desc()).first()


def is_whitelist_user(user):
    """判断用户是否应视为白名单用户"""
    if not user:
        return False
    if user.lv == 'a':
        return True
    active_sub = get_latest_active_subscription(user)
    if not active_sub:
        return False
    if active_sub.plan_type == 'whitelist':
        return True
    plan = resolve_plan_config(active_sub.plan_type)
    return bool(plan and plan.get('is_whitelist'))


def get_effective_plan_type(user):
    """获取用户当前生效的套餐类型"""
    if not user:
        return None
    access_types = get_user_access_plan_types(user)
    return access_types[0] if access_types else None


def get_user_access_plan_types(user):
    """获取用户可访问的套餐匹配键（名称优先，兼容旧ID）"""
    if not user:
        return []

    plan_types = []
    seen = set()
    plans = load_plans_config()
    now = datetime.now()

    def add_key(value):
        key = normalize_plan_match_key(value, plans)
        if key and key not in seen:
            seen.add(key)
            plan_types.append(key)

    if user.lv == 'a':
        add_key('whitelist')

    active_subs = Subscription.query.filter_by(
        user_tg=user.tg,
        status='active'
    ).order_by(Subscription.end_date.desc(), Subscription.created_at.desc()).all()

    for sub in active_subs:
        plan_type = (sub.plan_type or '').strip()
        plan_name = (sub.plan_name or '').strip()
        add_key(plan_name)
        add_key(plan_type)
        plan = resolve_plan_config(plan_type, plans)
        if plan:
            add_key(plan.get('name'))

    # 额外兜底：如果用户仍有有效到期时间，尝试把最近订单/最近订阅的套餐名也并入。
    # 这样白名单 + 月付这类组合，不会只命中白名单一条。
    if user.ex and user.ex > now:
        recent_order = Order.query.filter_by(
            user_tg=user.tg,
            payment_status='paid'
        ).order_by(Order.payment_time.desc()).first()
        if recent_order:
            add_key(recent_order.plan_name)
            add_key(recent_order.plan_type)
            plan = resolve_plan_config(recent_order.plan_type, plans)
            if plan:
                add_key(plan.get('name'))

        latest_sub = Subscription.query.filter_by(
            user_tg=user.tg
        ).order_by(Subscription.end_date.desc(), Subscription.created_at.desc()).first()
        if latest_sub:
            add_key(latest_sub.plan_name)
            add_key(latest_sub.plan_type)
            plan = resolve_plan_config(latest_sub.plan_type, plans)
            if plan:
                add_key(plan.get('name'))

    return plan_types


def is_active_subscriber(user):
    """判断用户是否为订阅用户（仅 lv='b' 且 ex>当前时间）"""
    if not user:
        return False
    return user.lv == 'b' and bool(user.ex and user.ex > datetime.now())


def has_subscription_access(user):
    """判断用户是否有可用订阅权限（白名单用户或订阅用户）"""
    return is_whitelist_user(user) or is_active_subscriber(user)


class Subscription(db.Model):
    """订阅套餐表"""
    __tablename__ = 'subscriptions'
    
    id = db.Column(db.Integer, primary_key=True)
    user_tg = db.Column(db.BigInteger, db.ForeignKey('emby.tg'), nullable=False)
    plan_type = db.Column(db.String(50), nullable=False)  # basic, standard, premium, ultimate
    plan_name = db.Column(db.String(100), nullable=False)
    duration_months = db.Column(db.Integer, nullable=False)  # 订阅时长（月）
    price = db.Column(db.Float, nullable=False)  # 价格
    start_date = db.Column(db.DateTime, nullable=False)
    end_date = db.Column(db.DateTime, nullable=False)
    status = db.Column(db.String(20), default='active')  # active, expired, cancelled
    auto_renew = db.Column(db.Boolean, default=False)  # 自动续费
    source = db.Column(db.String(20), default='purchase')  # purchase=购买, gift=管理员赠送, manual=手动设置
    created_at = db.Column(db.DateTime, default=lambda: datetime.now())
    updated_at = db.Column(db.DateTime, default=lambda: datetime.now(), onupdate=lambda: datetime.now())
    
    def to_dict(self):
        # 计算剩余天数，使用不带时区的 datetime 进行比较
        days_remaining = 0
        if self.end_date:
            now = datetime.now()
            # 如果 end_date 有时区信息，移除它
            end_date = self.end_date.replace(tzinfo=None) if self.end_date.tzinfo else self.end_date
            days_remaining = (end_date - now).days
        
        # 获取用户信息
        user = User.query.filter_by(tg=self.user_tg).first()
        user_name = (user.emby_name or user.name) if user else f'用户{self.user_tg}'
        
        # 判断来源 - 兼容旧数据
        price = float(self.price) if self.price else 0
        source = self.source
        if not source:
            # 旧数据没有source字段，根据价格判断
            source = 'gift' if price == 0 else 'purchase'
        
        return {
            'id': self.id,
            'user_tg_id': self.user_tg,
            'user_name': user_name,
            'plan_type': self.plan_type,
            'plan_name': self.plan_name,
            'duration_months': self.duration_months,
            'price': price,
            'start_date': self.start_date.isoformat() if self.start_date else None,
            'end_date': self.end_date.isoformat() if self.end_date else None,
            'status': self.status,
            'auto_renew': self.auto_renew,
            'days_remaining': days_remaining,
            'source': source
        }


class Order(db.Model):
    """订单表"""
    __tablename__ = 'orders'
    
    id = db.Column(db.Integer, primary_key=True)
    order_no = db.Column(db.String(64), unique=True, nullable=False)  # 订单号
    user_tg = db.Column(db.BigInteger, db.ForeignKey('emby.tg'), nullable=False)
    plan_type = db.Column(db.String(50), nullable=False)
    plan_name = db.Column(db.String(100), nullable=False)
    duration_months = db.Column(db.Integer, nullable=False)  # 兼容旧数据
    duration_days = db.Column(db.Integer, nullable=True)  # 实际天数（新字段，优先使用）
    original_price = db.Column(db.Float, nullable=False)  # 原价
    discount = db.Column(db.Float, default=0)  # 折扣金额
    final_price = db.Column(db.Float, nullable=False)  # 实付金额
    payment_method = db.Column(db.String(50))  # alipay, wechat, paypal
    payment_status = db.Column(db.String(20), default='pending')  # pending, paid, failed, refunded
    payment_time = db.Column(db.DateTime)  # 支付时间
    trade_no = db.Column(db.String(128))  # 第三方交易号
    created_at = db.Column(db.DateTime, default=lambda: datetime.now())
    updated_at = db.Column(db.DateTime, default=lambda: datetime.now(), onupdate=lambda: datetime.now())
    
    def to_dict(self):
        actual_duration_days = self.duration_days if self.duration_days else (self.duration_months * 30)
        is_permanent_order = bool(
            is_whitelist_plan_key(self.plan_type) or ('永久' in str(self.plan_name or ''))
        )

        return {
            'id': self.id,
            'order_no': self.order_no,
            'plan_type': self.plan_type,
            'plan_name': self.plan_name,
            'duration_months': self.duration_months,
            'duration_days': actual_duration_days,
            'duration_text': '永久' if is_permanent_order else (f'{actual_duration_days}天' if actual_duration_days else f'{self.duration_months or 1}个月'),
            'is_permanent': is_permanent_order,
            'original_price': self.original_price,
            'discount': self.discount,
            'final_price': self.final_price,
            'payment_method': self.payment_method,
            'payment_status': self.payment_status,
            'payment_time': self.payment_time.isoformat() if self.payment_time else None,
            'created_at': self.created_at.isoformat() if self.created_at else None
        }


class InviteRecord(db.Model):
    """邀请记录表"""
    __tablename__ = 'invite_records'
    
    id = db.Column(db.Integer, primary_key=True)
    inviter_tg = db.Column(db.BigInteger, db.ForeignKey('emby.tg'), nullable=False)  # 邀请人
    invitee_tg = db.Column(db.BigInteger, db.ForeignKey('emby.tg'), nullable=False)  # 被邀请人
    invite_code = db.Column(db.String(32), nullable=False)  # 邀请码（移除 unique 约束，同一个邀请码可以被多人使用）
    reward_type = db.Column(db.String(50))  # days, discount, credits, pending
    reward_value = db.Column(db.Float)  # 奖励数值
    reward_claimed = db.Column(db.Boolean, default=False)  # 奖励是否已发放
    reward_mode = db.Column(db.String(20), nullable=True)  # once=一次性, recurring=循环, null=跟随全局
    custom_reward_percent = db.Column(db.Float, nullable=True)  # 个性化返利比例(0-100), null=跟随全局
    pending_reward = db.Column(db.Float, default=0)  # 待审核的返利天数
    created_at = db.Column(db.DateTime, default=lambda: datetime.now())
    claimed_at = db.Column(db.DateTime)  # 发放时间
    
    def to_dict(self):
        # 安全获取邀请人信息
        inviter = db.session.get(User, self.inviter_tg) if self.inviter_tg else None
        inviter_name = inviter.name if inviter else '未知用户'
        
        # 安全获取被邀请人信息
        invitee = db.session.get(User, self.invitee_tg) if self.invitee_tg else None
        invitee_name = invitee.name if invitee else '未知用户'
        
        # 状态判断
        if self.pending_reward and self.pending_reward > 0:
            status = 'pending'
            status_display = '待审核'
        elif self.reward_claimed:
            status = 'approved'
            status_display = '已发放'
        else:
            status = 'waiting'
            status_display = '等待购买'
        
        return {
            'id': self.id,
            'inviter_tg': self.inviter_tg,
            'inviter_name': inviter_name,
            'invitee_tg': self.invitee_tg,
            'invitee_name': invitee_name,
            'invite_code': self.invite_code,
            'reward_type': self.reward_type,
            'reward_type_display': {
                'pending': '待发放',
                'days': '天数奖励',
                'discount': '折扣奖励',
                'credits': '积分奖励'
            }.get(self.reward_type, self.reward_type),
            'reward_value': self.reward_value,
            'reward_claimed': self.reward_claimed,
            'pending_reward': self.pending_reward or 0,
            'status': status,
            'status_display': status_display,
            'reward_mode': self.reward_mode,
            'custom_reward_percent': self.custom_reward_percent,
            'created_at': self.created_at.isoformat() if self.created_at else None,
            'claimed_at': self.claimed_at.isoformat() if self.claimed_at else None
        }


def process_invite_reward(user, purchased_days, source='purchase'):
    """统一处理邀请返利逻辑
    
    仅限真实购买链路触发；不处理兑换码、手工标记付款等来源。
    购买后不直接到账，而是记录为"待审核"，管理员在后台确认后才发放到邀请人账户。
    
    Args:
        user: 被邀请人 User 对象
        purchased_days: 购买/兑换的天数
        source: 来源标识（易支付通知/支付回调/轮询确认 等），用于日志
    
    Returns:
        dict: {'success': bool, 'reward_days': int, 'status': 'pending'} 或 None
    """
    try:
        _invite_cfg = get_system_config().get('invite_reward', {})
        _invite_enabled = _invite_cfg.get('enabled', True)
        if not _invite_enabled:
            return None

        # 仅允许购买链路触发返利
        allowed_sources = {'purchase', '易支付通知', '支付回调', '轮询确认'}
        if source not in allowed_sources:
            return None
        
        invite_record = InviteRecord.query.filter_by(invitee_tg=user.tg).first()
        if not invite_record:
            return None
        
        inviter = db.session.get(User, invite_record.inviter_tg)
        if not inviter:
            return None
        
        # 确定返利模式：User表 > InviteRecord > 全局
        global_mode = _invite_cfg.get('reward_mode', 'recurring')
        effective_mode = inviter.invite_reward_mode or invite_record.reward_mode or global_mode

        # 一次性模式：已发放或已有待审核奖励时，直接跳过，避免审批前重复累积
        if effective_mode == 'once' and (invite_record.reward_claimed or (invite_record.pending_reward or 0) > 0):
            return None

        # 确定返利比例：User表 > InviteRecord > 全局
        global_pct = _invite_cfg.get('reward_percent', 10)
        user_pct = inviter.invite_reward_percent
        record_pct = invite_record.custom_reward_percent
        effective_pct = user_pct if user_pct is not None else (record_pct if record_pct is not None else global_pct)
        _reward_pct = effective_pct / 100.0
        _min_reward = _invite_cfg.get('min_reward_days', 1)
        
        # 计算返利天数
        if effective_pct <= 0:
            return None
        reward_days = max(_min_reward, int(purchased_days * _reward_pct))
        if reward_days <= 0:
            return None
        
        # 不直接到账，记录为待审核
        invite_record.reward_type = 'days'
        invite_record.pending_reward = (invite_record.pending_reward or 0) + reward_days
        
        app.logger.info(
            f'邀请返利待审核({source}): 邀请人={inviter.name}, 被邀请人={user.name}, '
            f'待审核天数={reward_days}(比例{effective_pct}%, 模式={effective_mode})'
        )
        
        return {
            'success': True,
            'inviter_name': inviter.name,
            'reward_days': reward_days,
            'effective_pct': effective_pct,
            'effective_mode': effective_mode,
            'status': 'pending'
        }
    except Exception as e:
        app.logger.error(f'邀请返利处理异常({source}): {e}')
        return None


