class ServerLine(db.Model):
    """服务器线路表"""
    __tablename__ = 'server_lines'
    
    id = db.Column(db.Integer, primary_key=True)
    name = db.Column(db.String(100), nullable=False)  # 线路名称，如：主线路、备用线路
    server_url = db.Column(db.String(255), nullable=False)  # 服务器地址
    port = db.Column(db.Integer, default=8096)  # 端口
    is_https = db.Column(db.Boolean, default=False)  # 是否HTTPS
    description = db.Column(db.String(500))  # 线路描述
    access_level = db.Column(db.String(20), default='whitelist')  # 访问级别(兼容旧数据)
    allowed_plan_types = db.Column(db.String(500), default='')  # 允许查看的套餐类型（逗号分隔，如 whitelist,basic,standard）
    sort_order = db.Column(db.Integer, default=0)  # 排序顺序
    is_active = db.Column(db.Boolean, default=True)  # 是否启用
    created_at = db.Column(db.DateTime, default=lambda: datetime.now())
    updated_at = db.Column(db.DateTime, default=lambda: datetime.now(), onupdate=lambda: datetime.now())

    @staticmethod
    def resolve_url(server_url, port=None, is_https=None):
        """将线路地址规范化为完整 URL，并兼容旧的 host+port+https 结构"""
        raw_url = str(server_url or '').strip()
        if not raw_url:
            return '', None, None

        if re.match(r'^[a-zA-Z][a-zA-Z0-9+.-]*://', raw_url):
            parsed = urlparse(raw_url)
            resolved_is_https = (parsed.scheme or '').lower() == 'https'
            resolved_port = parsed.port or (443 if resolved_is_https else 80)
            return raw_url, resolved_port, resolved_is_https

        resolved_is_https = bool(is_https)
        try:
            resolved_port = int(port) if port not in (None, '') else None
        except (TypeError, ValueError):
            resolved_port = None

        if resolved_port is None:
            resolved_port = 443 if resolved_is_https else 8096

        scheme = 'https' if resolved_is_https else 'http'
        return f'{scheme}://{raw_url}:{resolved_port}', resolved_port, resolved_is_https

    def get_full_url(self):
        """获取完整线路地址"""
        full_url, _, _ = self.resolve_url(self.server_url, self.port, self.is_https)
        return full_url
    
    def to_dict(self, include_sensitive=True):
        """转换为字典
        Args:
            include_sensitive: 是否包含敏感信息（完整URL）
        """
        plan_types_list = normalize_plan_match_keys(self.allowed_plan_types)
        base_dict = {
            'id': self.id,
            'name': self.name,
            'description': self.description,
            'access_level': self.access_level,
            'allowed_plan_types': plan_types_list,
            'sort_order': self.sort_order,
            'is_active': self.is_active,
        }
        
        if include_sensitive:
            full_url = self.get_full_url()
            base_dict['server_url'] = full_url
            base_dict['port'] = self.port
            base_dict['is_https'] = self.is_https
            base_dict['full_url'] = full_url
        
        return base_dict
    
    def get_access_level_name(self):
        """获取访问级别名称"""
        names = {
            'whitelist': '白名单用户',
            'subscriber': '订阅用户',
            'all': '所有用户'
        }
        return names.get(self.access_level, self.access_level)


