@app.route('/dashboard')
@login_required
def dashboard():
    try:
        user = db.session.get(User, session['user_id'])
        
        if not user:
            session.clear()
            return redirect(url_for('login'))
        
        # 检查用户是否被封禁（lv='c' 为全面封禁）
        is_banned = user.lv == 'c'
        # 检查 Emby 账号是否被黑名单规则禁用（lv 未变但 ban_reason 有值）
        emby_disabled_by_blacklist = bool(user.ban_reason and user.lv != 'c')
        
        today_count = user.get_today_request_count()
        
        # 管理员显示无限制
        if user.is_admin:
            daily_limit = '无限制'
            remaining = '无限制'
        else:
            daily_limit = user.get_daily_limit()
            remaining = daily_limit - today_count
        
        # 优化：使用单个查询获取求片记录和总数
        requests_query = MovieRequest.query.options(joinedload(MovieRequest.download_task)).filter_by(user_tg=user.tg).order_by(MovieRequest.created_at.desc())
        requests = requests_query.limit(100).all()  # 限制返回数量，提升性能
        total_requests = requests_query.count()
        
        # 用户等级显示名称 - 根据实际订阅状态判断
        _dash_wl = Subscription.query.filter_by(user_tg=user.tg, status='active', plan_type='whitelist').first()
        is_whitelist = is_whitelist_user(user)
        if user.lv == 'c':
            level_name = '账号已封禁'
        elif is_whitelist:
            level_name = '白名单用户'
        elif user.lv == 'b' and user.ex and user.ex > datetime.now():
            level_name = '订阅用户'
        else:
            level_name = '未订阅用户'
        
        # 检查用户是否已绑定 Telegram Bot
        user_has_bot = bool(user.tg)
        bot_username = os.getenv('BOT_USERNAME', 'YourBotUsername')
        
        # 获取Emby媒体库数量统计
        library_counts = emby_client.get_library_counts() if emby_client.is_enabled() else {'movies': 0, 'series': 0, 'episodes': 0, 'total': 0}

        # Emby 账号概览（我的信息卡片）
        emby_account_info = {
            'status_text': '未绑定',
            'status_class': 'unbound',
            'last_verified_time': '未验证',
            'server_name': '未配置',
            'account_type': '-',
            'accessible_libraries': '--',
        }
        if user.embyid:
            emby_account_info['status_text'] = '已绑定'
            emby_account_info['status_class'] = 'bound'
            emby_account_info['server_name'] = '未知服务器'

            # 黑名单禁用/全封禁优先展示为禁用状态
            if is_banned or emby_disabled_by_blacklist:
                emby_account_info['status_text'] = '已禁用'
                emby_account_info['status_class'] = 'disabled'

            if emby_client.is_enabled():
                overview = emby_client.get_user_account_overview(user.embyid)
                if overview.get('verified'):
                    emby_account_info['last_verified_time'] = overview.get('verified_at') or '刚刚'
                else:
                    emby_account_info['last_verified_time'] = '验证失败'

                server_name = (overview.get('server_name') or '').strip()
                if server_name:
                    emby_account_info['server_name'] = server_name

                account_type = (overview.get('account_type') or '').strip()
                if account_type:
                    emby_account_info['account_type'] = account_type

                lib_count = overview.get('accessible_libraries')
                if isinstance(lib_count, int):
                    emby_account_info['accessible_libraries'] = str(lib_count)
            else:
                emby_account_info['last_verified_time'] = 'Emby未配置'
                emby_account_info['server_name'] = 'Emby未配置'
        
        # 加载前端配置
        site_config = get_site_config()
        # 如果配置中设置了 bot_username，优先使用配置的值
        if site_config.get('telegram_bot_username'):
            bot_username = site_config['telegram_bot_username']
        
        # 根据配置决定是否使用图片代理
        # 大陆用户建议开启代理，海外用户可关闭以加速
        if site_config.get('use_image_proxy', True):
            tmdb_image_base = '/api/tmdb-image/w500'
        else:
            tmdb_image_base = 'https://image.tmdb.org/t/p/w500'
        
        # 获取邀请返利开关状态
        _invite_cfg = get_system_config().get('invite_reward', {})
        invite_reward_enabled = _invite_cfg.get('enabled', True)
        invite_reward_percent = _invite_cfg.get('reward_percent', 10)
        
        # 获取邮箱功能开关状态
        _email_cfg = get_system_config().get('email', {})
        email_enabled = _email_cfg.get('enabled', False)
        
        # 检查是否强制绑定 Telegram
        _tg_cfg = get_system_config().get('telegram', {})
        require_telegram_bind = _tg_cfg.get('require_bindtg', False)
        user_has_telegram = bool(user.telegram_id)
        
        return render_template('dashboard.html', 
                             user=user, 
                             today_count=today_count, 
                             remaining=remaining,
                             max_daily=daily_limit,
                             total_requests=total_requests,
                             level_name=level_name,
                             requests=requests,
                             tmdb_image_base=tmdb_image_base,
                             announcement_enabled=ANNOUNCEMENT_ENABLED,
                             announcement_content=ANNOUNCEMENT_CONTENT,
                             user_has_bot=user_has_bot,
                             bot_username=bot_username,
                             library_counts=library_counts,
                             emby_account_info=emby_account_info,
                             is_banned=is_banned,
                             is_whitelist=is_whitelist,
                             emby_disabled_by_blacklist=emby_disabled_by_blacklist,
                             now=datetime.now(),
                             site_config=site_config,
                             invite_reward_enabled=invite_reward_enabled,
                             invite_reward_percent=invite_reward_percent,
                             email_enabled=email_enabled,
                             require_telegram_bind=require_telegram_bind,
                             user_has_telegram=user_has_telegram,
                             app_version=APP_VERSION)
    except Exception as e:
        app.logger.error(f'Dashboard 渲染异常: {e}', exc_info=True)
        return f'<h2>页面加载失败</h2><p>请尝试刷新页面，或联系管理员。</p><p>错误: {e}</p><p><a href="/login">返回登录</a></p>', 500


