def handle_reject_reason_input(chat_id, admin_id, text):
    """处理管理员输入的拒绝原因
    
    Returns:
        True if handled (consumed the message), False otherwise
    """
    reject_state_key = f'mreq_reject_{admin_id}'
    reject_state = get_db_config(reject_state_key, None)
    
    if not reject_state:
        return False
    
    request_id = reject_state.get('request_id')
    original_chat_id = reject_state.get('chat_id')
    original_message_id = reject_state.get('message_id')
    admin_name = reject_state.get('admin_name', '管理员')
    
    # 清除等待状态
    delete_db_config(reject_state_key)
    
    # 查询求片记录
    movie_request = MovieRequest.query.get(request_id)
    if not movie_request:
        send_telegram_reply(chat_id, "❌ 求片记录不存在，可能已被删除")
        return True
    
    if movie_request.status != 'pending':
        send_telegram_reply(chat_id, f"⚠️ 该求片状态已变更为「{movie_request.status}」，无法拒绝")
        return True
    
    # 执行拒绝
    reject_reason = text.strip()
    movie_request.status = 'rejected'
    movie_request.admin_note = reject_reason
    db.session.commit()
    
    # 通知用户
    user = movie_request.user
    if user and user.tg:
        send_user_telegram_notification(
            user.telegram_id or user.tg,
            movie_request.title,
            'rejected',
            reject_reason,
            movie_request.media_type,
            movie_request.tmdb_id,
            movie_request.poster_path
        )
    
    # 更新管理员的审核消息
    from html import escape as html_escape
    safe_admin = html_escape(str(admin_name))
    safe_reason = html_escape(reject_reason)
    now_str = datetime.now(timezone(timedelta(hours=8))).strftime('%Y-%m-%d %H:%M:%S')
    
    _update_review_message(original_chat_id, original_message_id, movie_request,
                           f"\n\n❌ <b>已拒绝</b> — {safe_admin} · {now_str}\n💬 原因：{safe_reason}")
    
    send_telegram_reply(chat_id, f"✅ 已拒绝「{movie_request.title}」\n💬 原因：{reject_reason}")
    app.logger.info(f'[Bot审核] 管理员 {admin_id}({admin_name}) 拒绝求片: ID={request_id}, {movie_request.title}, 原因: {reject_reason}')
    
    return True


def handle_kk_kick(callback_id, chat_id, message_id, target_user_id, target_username, operator_name):
    """处理踢出并硬删除回调：删除账号 + 踢出群组
    
    注意：必须先硬删除再踢出，因为踢出(banChatMember)会触发 chat_member 事件，
    如果先踢再删，chat_member 事件处理器可能抢先执行导致重复操作。
    先删除后，chat_member 事件触发时用户已不存在，会自然跳过。
    """
    
    if not target_user_id:
        answer_callback_query(callback_id, "❌ 无法识别目标用户（需要用户 ID）", show_alert=True)
        return jsonify({'ok': True})
    
    from html import escape as html_escape
    display_name = f"@{html_escape(target_username)}" if target_username else str(target_user_id)
    safe_operator_name = html_escape(str(operator_name)) if operator_name else '未知'
    
    # 1. 先硬删除：删除 Emby 账号 + 删除网站账号及所有关联数据
    delete_result = hard_delete_user_data(target_user_id, reason=f'被管理员 {operator_name} 通过 /kk 踢出删除')
    
    # 2. 再从群组踢出用户（踢出会触发 chat_member 事件，但此时用户已被删除，事件处理器会自然跳过）
    kick_result = kick_chat_member(TELEGRAM_CHAT_ID, target_user_id)
    
    # 3. 更新消息显示结果
    if delete_result['found']:
        safe_user_name = html_escape(delete_result['user_name'])
        emby_status = '✅ 已删除' if delete_result['emby_deleted'] else '⚠️ 无 Emby 账号或删除失败'
        account_line = f"✅ 已删除（用户: {safe_user_name}）"
        emby_line = f"\n• Emby 账号: {emby_status}"
    else:
        account_line = '⚠️ 该用户无网站账号'
        emby_line = ''
    
    result_message = f"""🚫 <b>用户已被踢出并删除</b>

用户: {display_name}
TG ID: <code>{target_user_id}</code>
操作者: {safe_operator_name}

状态:
• 群组踢出: {'✅ 成功' if kick_result else '❌ 失败（可能已不在群中或权限不足）'}
• 网站账号: {account_line}{emby_line}"""
    
    edit_telegram_message(chat_id, message_id, result_message, None)
    
    answer_callback_query(callback_id, "✅ 用户已被踢出并删除")
    app.logger.info(f'[/kk kick] 管理员 {operator_name} 踢出并删除 {display_name}, 结果: {delete_result}')
    
    return jsonify({'ok': True})


def hard_delete_user_data(user_tg_id, reason='未知'):
    """硬删除用户：删除 Emby 账号 + 删除网站账号及所有关联数据
    
    Args:
        user_tg_id: 用户的 Telegram ID（也是数据库主键 tg）
        reason: 删除原因（用于日志）
        
    Returns:
        dict: {'found': bool, 'user_name': str, 'emby_deleted': bool, 'db_deleted': bool}
    """
    result = {'found': False, 'user_name': '', 'emby_deleted': False, 'db_deleted': False}
    
    try:
        # 查找用户
        user = User.query.filter_by(telegram_id=user_tg_id).first()
        if not user:
            user = db.session.get(User, user_tg_id)
        if not user:
            app.logger.info(f'[硬删除] 未找到用户 tg_id={user_tg_id}，跳过')
            return result
        
        result['found'] = True
        result['user_name'] = user.emby_name or user.name or str(user_tg_id)
        user_tg = user.tg  # 数据库主键
        emby_id = user.embyid
        
        # 防止删除管理员
        if user.is_admin:
            app.logger.warning(f'[硬删除] 拒绝删除管理员 {result["user_name"]} (tg={user_tg})')
            result['found'] = False  # 标记为不处理
            return result
        
        # 1. 删除 Emby 服务器上的账号
        if emby_id and emby_client.is_enabled():
            try:
                result['emby_deleted'] = emby_client.delete_user(emby_id)
                if result['emby_deleted']:
                    app.logger.info(f'[硬删除] Emby 账号已删除: {emby_id}')
                else:
                    app.logger.warning(f'[硬删除] Emby 账号删除失败: {emby_id}')
            except Exception as e:
                app.logger.error(f'[硬删除] 删除 Emby 账号异常: {e}')
        
        # 2. 删除所有关联数据
        try:
            PlaybackRecord.query.filter_by(user_tg=user_tg).delete(synchronize_session=False)
            UserDevice.query.filter_by(user_tg=user_tg).delete(synchronize_session=False)
            Subscription.query.filter_by(user_tg=user_tg).delete(synchronize_session=False)
            Order.query.filter_by(user_tg=user_tg).delete(synchronize_session=False)
            # 下载任务（有外键引用 movie_requests）
            request_ids = [r.id for r in MovieRequest.query.filter_by(user_tg=user_tg).all()]
            if request_ids:
                DownloadTask.query.filter(DownloadTask.request_id.in_(request_ids)).delete(synchronize_session=False)
            MovieRequest.query.filter_by(user_tg=user_tg).delete(synchronize_session=False)
            # 工单（先删消息）
            ticket_ids = [t.id for t in SupportTicket.query.filter_by(user_tg=user_tg).all()]
            if ticket_ids:
                TicketMessage.query.filter(TicketMessage.ticket_id.in_(ticket_ids)).delete(synchronize_session=False)
            SupportTicket.query.filter_by(user_tg=user_tg).delete(synchronize_session=False)
            InviteRecord.query.filter((InviteRecord.inviter_tg == user_tg) | (InviteRecord.invitee_tg == user_tg)).delete(synchronize_session=False)
            UserActivityLog.query.filter_by(user_tg=user_tg).delete(synchronize_session=False)
            CheckInRecord.query.filter_by(user_tg=user_tg).delete(synchronize_session=False)
            CoinTransaction.query.filter_by(user_tg=user_tg).delete(synchronize_session=False)
            ExchangeRecord.query.filter_by(user_tg=user_tg).delete(synchronize_session=False)
            RedeemCode.query.filter_by(used_by=user_tg).update({'used_by': None}, synchronize_session=False)
            
            # 删除用户本身
            db.session.delete(user)
            db.session.commit()
            result['db_deleted'] = True
            app.logger.info(f'[硬删除] 用户数据已删除: {result["user_name"]} (tg={user_tg}), 原因: {reason}')
        except Exception as e:
            db.session.rollback()
            app.logger.error(f'[硬删除] 删除用户数据失败: {e}')
    except Exception as e:
        app.logger.error(f'[硬删除] 处理异常: user_tg_id={user_tg_id}, error={e}')
    
    return result


def handle_chat_member_update(chat_member_update):
    """处理 chat_member 事件：用户退群或被踢时自动硬删除账号
    
    Telegram 推送格式:
    {
        "chat": {"id": ..., "type": "supergroup"},
        "from": {"id": ...},  // 操作者（退群时是用户自己，被踢时是管理员）
        "date": ...,
        "old_chat_member": {"user": {"id": ...}, "status": "member"},
        "new_chat_member": {"user": {"id": ...}, "status": "left"/"kicked"}
    }
    """
    try:
        chat = chat_member_update.get('chat', {})
        chat_id = chat.get('id')
        
        # 只处理授权群组的事件
        if TELEGRAM_CHAT_ID and str(chat_id) != str(TELEGRAM_CHAT_ID):
            return jsonify({'ok': True})
        
        old_member = chat_member_update.get('old_chat_member', {})
        new_member = chat_member_update.get('new_chat_member', {})
        
        old_status = old_member.get('status', '')
        new_status = new_member.get('status', '')
        
        target_user = new_member.get('user', {})
        target_user_id = target_user.get('id')
        target_first_name = target_user.get('first_name', '')
        target_username = target_user.get('username', '')
        
        from_user = chat_member_update.get('from', {})
        from_user_id = from_user.get('id')
        from_first_name = from_user.get('first_name', '')
        
        if not target_user_id:
            return jsonify({'ok': True})
        
        # 判断是否是离开/被踢事件
        # old_status 为 member/administrator/restricted 且 new_status 为 left/kicked
        is_leaving = (old_status in ('member', 'administrator', 'restricted', 'creator') 
                      and new_status in ('left', 'kicked'))
        
        if not is_leaving:
            return jsonify({'ok': True})
        
        # 判断是主动退群还是被踢
        is_self_leave = (from_user_id == target_user_id)
        
        if is_self_leave:
            reason = '用户主动退群'
            app.logger.info(f'[退群删号] 用户 {target_first_name}({target_user_id}) 主动退出群组，开始硬删除...')
        else:
            reason = f'被管理员 {from_first_name}({from_user_id}) 踢出群组'
            app.logger.info(f'[退群删号] 用户 {target_first_name}({target_user_id}) 被踢出群组，开始硬删除...')
        
        # 执行硬删除
        delete_result = hard_delete_user_data(target_user_id, reason=reason)
        
        from html import escape as html_escape
        safe_first_name = html_escape(target_first_name) if target_first_name else ''
        safe_username = html_escape(target_username) if target_username else ''
        display_name = f"@{safe_username}" if safe_username else safe_first_name or str(target_user_id)
        
        # 在群组中发送通知
        if delete_result['found'] and delete_result['db_deleted']:
            emby_info = '，Emby 账号已删除' if delete_result['emby_deleted'] else ''
            notice = f"✅ <b>{display_name}</b> 已离开群组，其网站账号已删除{emby_info}"
            send_telegram_reply(chat_id, notice)
            app.logger.info(f'[退群删号] 已处理: {display_name}, 结果: {delete_result}')
        elif delete_result['found'] and not delete_result['db_deleted']:
            notice = f"⚠️ <b>{display_name}</b> 已离开群组，但账号删除失败，请管理员手动检查"
            send_telegram_reply(chat_id, notice)
            app.logger.warning(f'[退群删号] 删除失败: {display_name}, 结果: {delete_result}')
        else:
            app.logger.info(f'[退群删号] 用户 {display_name} 离开群组，但无网站账号，无需处理')
        
    except Exception as e:
        app.logger.error(f'[退群删号] 处理 chat_member 事件异常: {e}')
    
    return jsonify({'ok': True})


def kick_chat_member(chat_id, user_id):
    """踢出群组成员并封禁"""
    if not TELEGRAM_BOT_TOKEN:
        return False
    
    try:
        # 使用 banChatMember 踢出并封禁用户
        url = f"https://api.telegram.org/bot{TELEGRAM_BOT_TOKEN}/banChatMember"
        payload = {
            'chat_id': chat_id,
            'user_id': user_id,
        }
        response = PROXY_SESSION.post(url, json=payload, timeout=10)
        data = response.json()
        
        if data.get('ok'):
            app.logger.info(f'[踢出用户] 成功踢出 user_id={user_id} 从 chat_id={chat_id}')
            return True
        else:
            app.logger.warning(f'[踢出用户] 踢出失败: {data.get("description", "未知错误")}')
            return False
    except Exception as e:
        app.logger.error(f'[踢出用户] 踢出异常: {e}')
        return False


def edit_telegram_message(chat_id, message_id, text, reply_markup=None, auto_delete=None):
    """编辑 Telegram 消息
    
    Args:
        auto_delete: 编辑后自动撤回延迟秒数。None=群组自动撤回, 0=不撤回, >0=指定延迟
    """
    if not TELEGRAM_BOT_TOKEN:
        return False
    
    try:
        url = f"https://api.telegram.org/bot{TELEGRAM_BOT_TOKEN}/editMessageText"
        payload = {
            'chat_id': chat_id,
            'message_id': message_id,
            'text': text,
            'parse_mode': 'HTML'
        }
        if reply_markup:
            payload['reply_markup'] = reply_markup
        
        response = PROXY_SESSION.post(url, json=payload, timeout=10)
        data = response.json()
        
        if data.get('ok'):
            # 编辑后也支持自动撤回
            if auto_delete is None and _is_group_chat(chat_id) and BOT_AUTO_DELETE_SECONDS > 0:
                schedule_delete_message(chat_id, message_id)
            elif auto_delete and auto_delete > 0:
                schedule_delete_message(chat_id, message_id, delay=auto_delete)
            return True
        else:
            app.logger.warning(f'[编辑消息] 编辑失败: {data.get("description", "未知错误")}')
            return False
    except Exception as e:
        app.logger.error(f'[编辑消息] 编辑异常: {e}')
        return False


def _update_gift_message_claimed(gift_data, claimed_user_id, claimed_username, is_renew=False):
    """领取赠送后删除群组中的赠送消息（自动撤回）"""
    group_chat_id = gift_data.get('group_chat_id')
    group_message_id = gift_data.get('group_message_id')
    if not group_chat_id or not group_message_id:
        return
    
    claim_type = '续期' if is_renew else '新注册'
    delete_telegram_message(group_chat_id, group_message_id)
    app.logger.info(f'[Gift] 已删除群组赠送消息({claim_type}): chat={group_chat_id}, msg={group_message_id}, claimed_by={claimed_user_id}')


def handle_gift_claim(chat_id, telegram_user_id, telegram_username, gift_code):
    """处理赠送领取 - 验证用户身份并显示注册选项"""
    
    app.logger.info(f'[Gift] 用户 {telegram_user_id} ({telegram_username}) 尝试领取赠送码: {gift_code}')
    
    # 获取赠送信息
    gift_key = f'gift_{gift_code}'
    gift_data = get_db_config(gift_key, None)
    
    if not gift_data:
        send_telegram_reply(chat_id, "❌ 赠送码无效或已过期")
        return jsonify({'ok': True})
    
    # 检查是否已被使用
    if gift_data.get('used'):
        used_by = gift_data.get('used_by_id', '未知')
        used_by_name = gift_data.get('used_by_name', '')
        used_at = gift_data.get('used_at', '')
        if used_by_name:
            send_telegram_reply(chat_id, f"❌ 该注册码已被 <code>{used_by}</code>（{used_by_name}）使用")
        else:
            send_telegram_reply(chat_id, f"❌ 该注册码已被 <code>{used_by}</code> 使用")
        return jsonify({'ok': True})
    
    days = gift_data.get('days', 0)
    from_user_id = gift_data.get('from_user_id')
    from_username = gift_data.get('from_username', '管理员')
    target_user_id = gift_data.get('target_user_id')
    
    # 构建邀请人链接
    if from_user_id:
        inviter_text = f'<a href="tg://user?id={from_user_id}">{from_username}</a>'
    else:
        inviter_text = f'<b>{from_username}</b>'
    
    if days <= 0:
        send_telegram_reply(chat_id, "❌ 赠送信息异常")
        return jsonify({'ok': True})
    
    # 验证是否是被赠送的用户
    if target_user_id and int(target_user_id) != int(telegram_user_id):
        # 不是被赠送的用户
        send_telegram_reply(chat_id, "你也想和BOT击剑吗？")
        return jsonify({'ok': True})
    
    # 检查用户是否已有账号
    existing_user = User.query.filter_by(telegram_id=telegram_user_id).first()
    if not existing_user:
        # 兼容：telegram_id 未绑定的用户，尝试用 tg 主键查找
        existing_user = db.session.get(User, telegram_user_id)
    
    if existing_user and existing_user.lv in ['a', 'b', 'c', 'd']:
        # 用户已有账号
        was_banned = (existing_user.lv == 'c')  # 记录是否是被禁用用户
        
        _gift_wl = Subscription.query.filter_by(user_tg=existing_user.tg, plan_type='whitelist', status='active').first()
        if _gift_wl or existing_user.lv == 'a':
            # 白名单用户
            send_telegram_reply(chat_id, f"""✅ <b>领取成功！</b>

您是白名单用户，已拥有永久订阅！
感谢 {inviter_text} 的赠送 🎉

👤 账号: <b>{existing_user.emby_name or existing_user.name}</b>""")
        else:
            # 普通用户 / 被禁用用户 / 无账号用户，先赠送天数
            if existing_user.lv == 'd':
                existing_user.lv = 'b'  # 激活无账号用户
            
            start_date = datetime.now()
            
            if was_banned:
                # 被禁用用户：基于封禁前的到期时间判断
                prev_ex = existing_user.ban_prev_ex
                if prev_ex and prev_ex > start_date:
                    # 封禁前订阅还没过期，在原到期时间上叠加
                    existing_user.ex = prev_ex + timedelta(days=days)
                else:
                    # 封禁前订阅已过期，从领取时间开始推算
                    existing_user.ex = start_date + timedelta(days=days)
            else:
                # 普通用户：如果还有剩余订阅就在此基础上叠加
                if existing_user.ex and existing_user.ex > start_date:
                    existing_user.ex = existing_user.ex + timedelta(days=days)
                else:
                    existing_user.ex = start_date + timedelta(days=days)
            
            # 创建订阅记录
            subscription = Subscription(
                user_tg=existing_user.tg,
                plan_type='gift',
                plan_name=f'管理员赠送 {days}天',
                duration_months=0,  # 按天赠送，不按月计
                price=0,
                start_date=start_date,
                end_date=existing_user.ex,
                status='active',
                source='gift'
            )
            db.session.add(subscription)
            
            # 赠送完成后再解禁
            if was_banned:
                existing_user.lv = 'b'
                existing_user.ban_prev_lv = None
                existing_user.ban_prev_ex = None
                existing_user.ban_time = None
                existing_user.ban_reason = None
                # 恢复Emby账号
                if existing_user.embyid and emby_client.is_enabled():
                    emby_client.enable_user(existing_user.embyid)
                app.logger.info(f'[Gift] 被禁用用户 {existing_user.emby_name or existing_user.name} (tg={existing_user.tg}) 领取赠送后自动解禁')
            else:
                # 非禁用用户领取赠送后，也需要恢复Emby账号
                # （用户可能之前因过期被自动禁用了Emby，但账号等级仍是'b'）
                # 黑名单禁用的用户不自动恢复
                if not existing_user.ban_reason and existing_user.embyid and emby_client.is_enabled():
                    if emby_client.enable_user(existing_user.embyid):
                        app.logger.info(f'[Gift] 用户 {existing_user.emby_name or existing_user.name} 领取赠送后恢复Emby账号')
            
            db.session.commit()
            
            ban_note = '\n🔓 您的账号已自动解除禁用！' if was_banned else ''
            app.logger.info(f'[Gift] 为已有用户 {existing_user.emby_name or existing_user.name} (tg={existing_user.tg}) 创建赠送订阅记录: {days}天{" (原被禁用)" if was_banned else ""}')
            
            send_telegram_reply(chat_id, f"""✅ <b>领取成功！</b>

已为您的账号增加 <b>{days}</b> 天订阅！
感谢 {inviter_text} 的赠送 🎉

👤 账号: <b>{existing_user.emby_name or existing_user.name}</b>
📅 新到期时间: <b>{existing_user.ex.strftime('%Y-%m-%d %H:%M')}</b>{ban_note}""")
        
        # 标记赠送码为已使用
        gift_data['used'] = True
        gift_data['used_by_id'] = telegram_user_id
        gift_data['used_by_name'] = telegram_username or ''
        gift_data['used_at'] = datetime.now().isoformat()
        set_db_config(gift_key, gift_data)
        
        # 更新群组中的赠送消息为已领取状态（已有账号=续期）
        _update_gift_message_claimed(gift_data, telegram_user_id, telegram_username, is_renew=True)
        
        return jsonify({'ok': True})
    
    # 用户没有账号，显示注册选项
    display_name = telegram_username or str(telegram_user_id)
    
    # 发送注册提示消息，带注册和取消按钮
    register_message = f"""🎊 少年郎，恭喜你，已经收到了 {inviter_text} 发送的邀请注册资格

请选择你的选项~"""
    
    reply_markup = {
        'inline_keyboard': [[
            {'text': '📝 注册', 'callback_data': f'reg_start_{gift_code}'},
            {'text': '⭕ 取消', 'callback_data': f'reg_cancel_{gift_code}'}
        ]]
    }
    
    send_telegram_reply(chat_id, register_message, reply_markup)
    return jsonify({'ok': True})


def create_gift_account(chat_id, telegram_user_id, username, gift_code, gift_data):
    """创建赠送账号"""
    import secrets
    
    days = gift_data.get('days', 0)
    from_user_id = gift_data.get('from_user_id')
    from_username = gift_data.get('from_username', '管理员')
    
    # 构建邀请人链接
    if from_user_id:
        inviter_text = f'<a href="tg://user?id={from_user_id}">{from_username}</a>'
    else:
        inviter_text = f'<b>{from_username}</b>'
    
    # 生成随机密码
    password = secrets.token_urlsafe(8)
    
    try:
        # 创建新用户
        new_tg = generate_next_user_id()
        new_user = User(
            tg=new_tg,  # 系统自增正整数 ID
            telegram_id=telegram_user_id,
            name=username,
            pwd=password,
            lv='b',  # 普通用户
            cr=datetime.now(),
            ex=datetime.now() + timedelta(days=days),
            us=1,
            coins=0,
        )
        
        db.session.add(new_user)
        db.session.flush()  # 先flush以获取用户ID
        
        # 创建订阅记录
        subscription = Subscription(
            user_tg=new_user.tg,
            plan_type='gift',
            plan_name=f'管理员赠送 {days}天',
            duration_months=0,  # 按天赠送，不按月计
            price=0,
            start_date=new_user.cr,
            end_date=new_user.ex,
            status='active',
            source='gift'
        )
        db.session.add(subscription)
        db.session.commit()
        
        app.logger.info(f'[Gift] 成功创建账号: {username}, 赠送 {days} 天，已创建订阅记录')
        
        # 标记赠送码为已使用
        gift_key = f'gift_{gift_code}'
        gift_data['used'] = True
        gift_data['used_by_id'] = telegram_user_id
        gift_data['used_by_name'] = username
        gift_data['used_at'] = datetime.now().isoformat()
        set_db_config(gift_key, gift_data)
        
        # 更新群组中的赠送消息为已领取状态（新注册）
        _update_gift_message_claimed(gift_data, telegram_user_id, username, is_renew=False)
        
        # 获取面板登录链接
        site_config = load_site_config()
        panel_url = site_config.get('panel_url', '')
        
        # 构建登录链接文本
        if panel_url:
            login_link = f'\n\n🔗 <b>面板登录:</b> {panel_url}'
        else:
            login_link = ''
        
        send_telegram_reply(chat_id, f"""🎉 <b>账号创建成功！</b>

感谢 {inviter_text} 的赠送！

━━━━━━━━━━━━━━━━
👤 <b>账号信息</b>
━━━━━━━━━━━━━━━━
用户名: <code>{username}</code>
密码: <code>{password}</code>
订阅天数: <b>{days}</b> 天
到期时间: <b>{new_user.ex.strftime('%Y-%m-%d %H:%M')}</b>

⚠️ <b>请妥善保存账号信息！</b>
使用此账号密码登录网站即可使用。{login_link}

💡 如需修改密码，请登录网站后在个人中心修改。""")
        
        return jsonify({'ok': True})
        
    except Exception as e:
        db.session.rollback()
        app.logger.error(f'[Gift] 创建账号失败: {e}')
        send_telegram_reply(chat_id, f"❌ 创建账号失败: {str(e)}")
        return jsonify({'ok': True})


def send_telegram_reply(chat_id, text, reply_markup=None, auto_delete=None):
    """发送 Telegram 消息（支持 inline button）
    
    Args:
        chat_id: 聊天 ID
        text: 消息文本
        reply_markup: 内联键盘
        auto_delete: 自动撤回延迟秒数。None=群组自动撤回/私聊不撤回, 0=不撤回, >0=指定延迟
    
    Returns:
        成功返回 message_id (int)，失败返回 False
    """
    if not TELEGRAM_BOT_TOKEN:
        app.logger.warning(f'[发送消息] Bot Token 未配置，无法发送到 chat_id={chat_id}')
        return False
    
    try:
        url = f"https://api.telegram.org/bot{TELEGRAM_BOT_TOKEN}/sendMessage"
        payload = {
            'chat_id': chat_id,
            'text': text,
            'parse_mode': 'HTML'
        }
        if reply_markup:
            payload['reply_markup'] = reply_markup
        app.logger.info(f'[发送消息] 发送到 chat_id={chat_id}, 文本长度={len(text)}, 使用代理: {PROXY_SESSION.proxies if hasattr(PROXY_SESSION, "proxies") else "无"}')
        
        response = PROXY_SESSION.post(url, json=payload, timeout=10)
        data = response.json()
        
        if data.get('ok'):
            sent_msg_id = data.get('result', {}).get('message_id')
            app.logger.info(f'[发送消息] 发送成功到 chat_id={chat_id}, message_id={sent_msg_id}')
            
            # 自动撤回逻辑：群组消息默认自动撤回
            if auto_delete is None and _is_group_chat(chat_id) and BOT_AUTO_DELETE_SECONDS > 0:
                schedule_delete_message(chat_id, sent_msg_id)
            elif auto_delete and auto_delete > 0:
                schedule_delete_message(chat_id, sent_msg_id, delay=auto_delete)
            
            return sent_msg_id or True
        else:
            error_desc = data.get('description', '未知错误')
            app.logger.error(f'[发送消息] 发送失败到 chat_id={chat_id}: {error_desc}')
            return False
    except requests.exceptions.Timeout:
        app.logger.error(f'[发送消息] 请求超时，无法发送到 chat_id={chat_id}，请检查网络和代理设置')
        return False
    except requests.exceptions.ConnectionError as e:
        app.logger.error(f'[发送消息] 连接错误，无法发送到 chat_id={chat_id}: {e}，请检查网络和代理设置')
        return False
    except Exception as e:
        app.logger.error(f'[发送消息] 发送 Telegram 消息失败到 chat_id={chat_id}: {e}', exc_info=True)
        return False


def generate_captcha_image(code):
    """生成验证码图片"""
    try:
        # 创建图片 (宽300, 高100)
        width, height = 300, 100
        image = Image.new('RGB', (width, height), color=(255, 255, 255))
        draw = ImageDraw.Draw(image)
        
        # 绘制背景干扰线
        for _ in range(5):
            x1 = random.randint(0, width)
            y1 = random.randint(0, height)
            x2 = random.randint(0, width)
            y2 = random.randint(0, height)
            draw.line([(x1, y1), (x2, y2)], fill=(200, 200, 200), width=2)
        
        # 绘制干扰点
        for _ in range(100):
            x = random.randint(0, width)
            y = random.randint(0, height)
            draw.point((x, y), fill=(random.randint(150, 200), random.randint(150, 200), random.randint(150, 200)))
        
        # 尝试加载字体，如果失败使用默认字体
        try:
            # 尝试使用系统字体
            font = ImageFont.truetype("arial.ttf", 50)
        except:
            try:
                # Windows系统字体
                font = ImageFont.truetype("C:/Windows/Fonts/arial.ttf", 50)
            except:
                try:
                    # 其他可能的字体路径
                    font = ImageFont.truetype("/usr/share/fonts/truetype/dejavu/DejaVuSans-Bold.ttf", 50)
                except:
                    # 使用默认字体
                    font = ImageFont.load_default()
        
        # 计算文本位置（居中）
        text = str(code)
        try:
            # 新版本PIL
            bbox = draw.textbbox((0, 0), text, font=font)
            text_width = bbox[2] - bbox[0]
            text_height = bbox[3] - bbox[1]
        except:
            # 旧版本PIL
            text_width, text_height = draw.textsize(text, font=font)
        
        x = (width - text_width) // 2
        y = (height - text_height) // 2
        
        # 绘制验证码文字（添加颜色变化）
        for i, char in enumerate(text):
            char_x = x + i * (text_width // len(text))
            char_y = y + random.randint(-5, 5)  # 随机上下偏移
            color = (
                random.randint(0, 100),
                random.randint(0, 100),
                random.randint(0, 100)
            )
            draw.text((char_x, char_y), char, font=font, fill=color)
        
        # 保存到BytesIO
        bio = BytesIO()
        image.save(bio, format='PNG')
        bio.seek(0)
        return bio
    except Exception as e:
        app.logger.error(f'生成验证码图片失败: {e}')
        return None


def send_telegram_photo(chat_id, photo_bytes, caption=None, auto_delete=None):
    """发送 Telegram 图片
    
    Returns:
        成功返回 message_id (int)，失败返回 False
    """
    if not TELEGRAM_BOT_TOKEN:
        app.logger.warning(f'[发送图片] Bot Token 未配置，无法发送到 chat_id={chat_id}')
        return False
    
    try:
        url = f"https://api.telegram.org/bot{TELEGRAM_BOT_TOKEN}/sendPhoto"
        
        files = {
            'photo': ('captcha.png', photo_bytes, 'image/png')
        }
        
        data = {
            'chat_id': chat_id
        }
        
        if caption:
            data['caption'] = caption
            data['parse_mode'] = 'HTML'
        
        app.logger.info(f'[发送图片] 发送到 chat_id={chat_id}')
        
        response = PROXY_SESSION.post(url, data=data, files=files, timeout=15)
        result = response.json()
        
        if result.get('ok'):
            sent_msg_id = result.get('result', {}).get('message_id')
            app.logger.info(f'[发送图片] 发送成功到 chat_id={chat_id}, message_id={sent_msg_id}')
            
            # 自动撤回逻辑
            if auto_delete is None and _is_group_chat(chat_id) and BOT_AUTO_DELETE_SECONDS > 0:
                schedule_delete_message(chat_id, sent_msg_id)
            elif auto_delete and auto_delete > 0:
                schedule_delete_message(chat_id, sent_msg_id, delay=auto_delete)
            
            return sent_msg_id or True
        else:
            error_desc = result.get('description', '未知错误')
            app.logger.error(f'[发送图片] 发送失败到 chat_id={chat_id}: {error_desc}')
            return False
    except requests.exceptions.Timeout:
        app.logger.error(f'[发送图片] 请求超时，无法发送到 chat_id={chat_id}')
        return False
    except Exception as e:
        app.logger.error(f'[发送图片] 发送失败到 chat_id={chat_id}: {e}', exc_info=True)
        return False


