@app.route('/api/downloads/<int:request_id>')
def get_download_status(request_id):
    movie_request = db.session.get(MovieRequest, request_id)
    
    # 如果记录不存在，返回 200 但标记为无任务（避免触发 toast 错误）
    if not movie_request:
        return jsonify({'success': False, 'error': '记录不存在', 'not_found': True}), 200

    if 'user_id' not in session:
        return jsonify({'success': False, 'error': '未登录'}), 401

    user = db.session.get(User, session['user_id'])
    if not user:
        return jsonify({'success': False, 'error': '未登录'}), 401
    
    # 验证session_token
    if user.session_token and session.get('session_token') != user.session_token:
        return jsonify({'success': False, 'error': '会话已失效，请重新登录'}), 401

    if not user.is_admin and movie_request.user_tg != user.tg:
        return jsonify({'success': False, 'error': '无权查看该下载任务'}), 403

    if not movie_request.download_task:
        return jsonify({'success': False, 'error': '暂无下载任务', 'no_task': True}), 200

    task = movie_request.download_task
    
    # 实时同步 qBittorrent 状态（扩展条件：只要任务未完成/失败就查询 qB）
    # 注意：即使后端状态显示 completed，也查一下 qB 确保进度准确
    should_sync = (
        task.torrent_hash and 
        qbit_client.is_enabled() and
        task.status not in ['failed', 'cancelled']
    )
    
    if should_sync:
        try:
            infos = qbit_client.get_torrents_info(hashes=[task.torrent_hash])
            if infos:
                info = infos[0]
                qb_state = info.get('state', '').lower()
                qb_progress = info.get('progress') or 0
                progress = round(qb_progress * 100, 2)
                
                # 记录进度差异以便调试
                old_progress = task.progress or 0
                if abs(progress - old_progress) > 1:
                    app.logger.info(f'任务 {task.id} 进度同步: {old_progress:.1f}% -> {progress:.1f}% (qB状态: {qb_state})')
                
                # 更新进度信息
                task.progress = progress
                task.download_speed = info.get('dlspeed', 0)
                task.eta = info.get('eta', -1)
                
                # 检查是否已完成（做种状态）
                if qb_state in {'uploading', 'stalledup', 'queuedup', 'checkingup', 'pausedup', 'completed', 'forcedup', 'seeding'}:
                    if task.status != 'completed':
                        task.status = 'completed'
                        task.progress = 100.0
                        task.finished_at = task.finished_at or datetime.now()
                        movie_request.status = 'downloaded'
                        app.logger.info(f'API 查询时同步: 任务 {task.id} 已完成')
                elif qb_state in {'downloading', 'stalleddl', 'forceddl', 'metadl', 'checkingdl', 'allocating', 'moving'}:
                    if task.status != 'downloading':
                        task.status = 'downloading'
                        movie_request.status = 'downloading'
                
                db.session.commit()
            else:
                # qB 中任务不存在
                if task.progress >= 100 or task.status == 'completed':
                    if task.status != 'completed':
                        task.status = 'completed'
                        task.finished_at = task.finished_at or datetime.now()
                        movie_request.status = 'downloaded'
                        db.session.commit()
                        app.logger.info(f'API 查询时同步: 任务 {task.id} qB已删除但进度100%，标记完成')
        except Exception as e:
            app.logger.warning(f'实时同步 qB 状态失败 (任务 {task.id}): {e}')
            db.session.rollback()  # 确保回滚以防止事务问题

    # 如果求片状态已完成（已入库），确保下载任务进度也显示为 100%
    if movie_request.status == 'completed' and task.status != 'completed':
        task.status = 'completed'
        task.progress = 100.0
        task.finished_at = task.finished_at or datetime.now()
        try:
            db.session.commit()
        except:
            db.session.rollback()

    return jsonify({
        'success': True, 
        'task': task.to_dict(),
        'request_status': movie_request.status  # 添加求片状态
    })


@app.route('/api/admin/sync-downloads', methods=['POST'])
@admin_required
def sync_all_downloads():
    """手动同步所有下载任务状态（管理员）"""
    if not qbit_client.is_enabled():
        return jsonify({'success': False, 'error': 'qBittorrent 未配置'}), 400
    
    # 获取所有未完成的下载任务
    tasks = DownloadTask.query.filter(
        DownloadTask.status.in_(['queued', 'downloading'])
    ).all()
    
    synced = 0
    completed = 0
    failed = 0
    
    for task in tasks:
        if not task.torrent_hash:
            continue
        
        try:
            infos = qbit_client.get_torrents_info(hashes=[task.torrent_hash])
            if infos:
                info = infos[0]
                qb_state = info.get('state', '').lower()
                progress = round((info.get('progress') or 0) * 100, 2)
                
                task.progress = progress
                task.download_speed = info.get('dlspeed', 0)
                task.eta = info.get('eta', -1)
                
                if qb_state in {'uploading', 'stalledup', 'queuedup', 'checkingup', 'pausedup', 'completed', 'forcedup'}:
                    task.status = 'completed'
                    task.progress = 100.0
                    task.finished_at = task.finished_at or datetime.now()
                    if task.request:
                        task.request.status = 'downloaded'
                    completed += 1
                else:
                    synced += 1
            else:
                # qB 中不存在
                if task.progress >= 100:
                    task.status = 'completed'
                    if task.request:
                        task.request.status = 'downloaded'
                    completed += 1
                else:
                    task.status = 'failed'
                    task.error_message = 'qBittorrent 中任务不存在'
                    if task.request:
                        task.request.status = 'failed'
                    failed += 1
        except Exception as e:
            app.logger.error(f'同步任务 {task.id} 失败: {e}')
    
    db.session.commit()
    
    return jsonify({
        'success': True,
        'message': f'同步完成: {synced} 个任务更新进度, {completed} 个已完成, {failed} 个失败'
    })


@app.route('/api/downloads/<int:request_id>/retry', methods=['POST'])
@login_required
def retry_download(request_id):
    """重试失败的下载任务"""
    movie_request = db.session.get(MovieRequest, request_id)
    
    if not movie_request:
        return jsonify({'success': False, 'error': '求片记录不存在'}), 404
    
    user = db.session.get(User, session['user_id'])
    if not user:
        return jsonify({'success': False, 'error': '未登录'}), 401
    
    # 检查权限: 管理员或求片用户本人
    if not user.is_admin and movie_request.user_tg != user.tg:
        return jsonify({'success': False, 'error': '无权操作该任务'}), 403
    
    task = movie_request.download_task
    if not task:
        return jsonify({'success': False, 'error': '该求片没有下载任务'}), 400
    
    if not qbit_client.is_enabled():
        return jsonify({'success': False, 'error': 'qBittorrent 未配置，无法重试'}), 400

    # 检查是否可以重试
    if not task.can_retry():
        if (task.retry_count or 0) >= (task.max_retries or 3):
            return jsonify({
                'success': False, 
                'error': f'已达到最大重试次数 ({task.max_retries or 3}次)'
            }), 400
        else:
            return jsonify({
                'success': False, 
                'error': '只有失败的任务才能重试'
            }), 400
    
    # 记录重试计数（无论成功失败，均视为一次重试尝试）
    task.retry_count = (task.retry_count or 0) + 1
    task.last_retry_at = datetime.now()
    retry_no = task.retry_count
    qb_tag = task.qb_tag or f"request-{movie_request.id}"
    task.qb_tag = qb_tag

    retried = False
    retry_error = ''

    # 方案1：优先尝试恢复 qBittorrent 里已存在的失败任务
    if task.torrent_hash:
        try:
            qbit_client.recheck_torrents([task.torrent_hash])
            qbit_client.resume_torrents([task.torrent_hash])
            retried = True
            app.logger.info(f'重试下载: 已恢复 qB 现有任务 hash={task.torrent_hash[:16]}..., task_id={task.id}')
        except Exception as exc:
            retry_error = f'恢复已有任务失败: {exc}'
            app.logger.warning(f'重试下载恢复失败 task_id={task.id}: {exc}')

    # 方案2：若无法恢复，则通过 MoviePilot 重新下发下载
    if not retried:
        download_url = (task.download_url or '').strip()
        if not download_url:
            retry_error = '该任务缺少 download_url，无法重新下发'
        else:
            moviepilot_client = pt_manager.get_client('MoviePilot')
            if not moviepilot_client or not moviepilot_client.is_enabled():
                retry_error = 'MoviePilot 未配置，且无法恢复已有任务'
            else:
                try:
                    retry_title = task.torrent_name or movie_request.title
                    mp_result = moviepilot_client.download_torrent(download_url, title=retry_title)
                    if not mp_result or mp_result.get('success') is not True:
                        raise RuntimeError((mp_result or {}).get('error') or 'MoviePilot 下载失败')

                    # 等待 qB 接收种子后刷新 hash
                    time.sleep(2)
                    torrent_info = qbit_client.get_torrent_by_tag(qb_tag)
                    if not torrent_info:
                        all_torrents = qbit_client.get_torrents_info()
                        if all_torrents:
                            all_torrents.sort(key=lambda x: x.get('added_on', 0), reverse=True)
                            recent = all_torrents[0]
                            if time.time() - recent.get('added_on', 0) < 30:
                                torrent_info = recent
                    if torrent_info and torrent_info.get('hash'):
                        task.torrent_hash = torrent_info.get('hash')

                    retried = True
                    app.logger.info(f'重试下载: 已通过 MoviePilot 重新下发 task_id={task.id}, request_id={movie_request.id}')
                except Exception as exc:
                    retry_error = f'重新下发失败: {exc}'
                    app.logger.error(f'重试下载重新下发失败 task_id={task.id}: {exc}')

    if not retried:
        task.status = 'failed'
        task.error_message = f'第 {retry_no} 次重试失败: {retry_error or "未知错误"}'
        movie_request.status = 'failed'
        db.session.commit()
        return jsonify({
            'success': False,
            'error': task.error_message,
            'retry_count': task.retry_count,
            'max_retries': task.max_retries
        }), 500

    # 重置任务状态并启动监控
    task.status = 'queued'
    task.progress = 0.0
    task.download_speed = 0
    task.eta = -1
    task.finished_at = None
    task.error_message = f'第 {retry_no} 次重试已提交'
    movie_request.status = 'downloading'

    try:
        db.session.commit()
        start_task_monitor(task.id, DOWNLOAD_POLL_INTERVAL)
        app.logger.info(f'用户 {user.name} 重试下载任务 {task.id} 成功 (第{retry_no}次)')
        return jsonify({
            'success': True,
            'message': f'已提交重试 (第{retry_no}/{task.max_retries}次)',
            'retry_count': task.retry_count,
            'max_retries': task.max_retries
        })
    except Exception as e:
        db.session.rollback()
        app.logger.error(f'重试下载提交失败: {e}')
        return jsonify({'success': False, 'error': str(e)}), 500


# ==================== 批量操作 API ====================
@app.route('/admin/batch-update', methods=['POST'])
@admin_required
def batch_update_status():
    """批量更新求片状态"""
    data = request.get_json(silent=True) or {}
    
    request_ids = data.get('ids', [])
    status = data.get('status')
    admin_note = data.get('admin_note', '')
    
    if not request_ids:
        return jsonify({'success': False, 'error': '未选择任何请求'}), 400
    
    if status not in ['approved', 'rejected', 'completed']:
        return jsonify({'success': False, 'error': '无效的状态'}), 400
    
    success_count = 0
    fail_count = 0
    
    for req_id in request_ids:
        try:
            movie_request = db.session.get(MovieRequest, req_id)
            if movie_request:
                old_status = movie_request.status
                movie_request.status = status
                if admin_note:
                    movie_request.admin_note = admin_note
                success_count += 1
                
                # 发送通知（只在拒绝和完成时）
                if status in ['rejected', 'completed'] and old_status != status:
                    # 获取用户信息
                    user = movie_request.user
                    if not user:
                        user = User.query.filter_by(tg=movie_request.user_tg).first()
                    
                    user_tg = user.tg if user else movie_request.user_tg
                    username = user.name if user else '用户'
                    
                    if user_tg:
                        # 发送私聊通知
                        send_user_telegram_notification(
                            user_tg,
                            movie_request.title,
                            status,
                            admin_note,
                            movie_request.media_type,
                            movie_request.tmdb_id,
                            movie_request.poster_path
                        )
                        
                        # 入库完成时额外发送群组通知
                        if status == 'completed':
                            # 获取用户真实 Telegram ID
                            _batch_user = User.query.filter_by(tg=user_tg).first()
                            _batch_tg_id = _batch_user.telegram_id if _batch_user and _batch_user.telegram_id else user_tg
                            send_group_completion_notification(
                                user_tg_id=_batch_tg_id,
                                username=username,
                                title=movie_request.title,
                                year=movie_request.year,
                                media_type=movie_request.media_type,
                                tmdb_id=movie_request.tmdb_id,
                                poster_path=movie_request.poster_path
                            )
            else:
                fail_count += 1
        except Exception as e:
            app.logger.error(f'批量更新失败: ID={req_id}, error={e}')
            fail_count += 1
    
    db.session.commit()
    app.logger.info(f'管理员 {session.get("username")} 批量更新状态: 成功={success_count}, 失败={fail_count}, 状态={status}')
    
    return jsonify({
        'success': True,
        'message': f'已更新 {success_count} 条记录',
        'success_count': success_count,
        'fail_count': fail_count
    }), 200


@app.route('/admin/batch-delete', methods=['POST'])
@admin_required
def batch_delete_requests():
    """批量删除求片记录"""
    data = request.get_json(silent=True) or {}
    
    request_ids = data.get('ids', [])
    
    if not request_ids:
        return jsonify({'success': False, 'error': '未选择任何请求'}), 400
    
    success_count = 0
    fail_count = 0
    
    for req_id in request_ids:
        try:
            movie_request = db.session.get(MovieRequest, req_id)
            if movie_request:
                # 同时删除关联的下载任务
                if movie_request.download_task:
                    db.session.delete(movie_request.download_task)
                db.session.delete(movie_request)
                success_count += 1
            else:
                fail_count += 1
        except Exception as e:
            app.logger.error(f'批量删除失败: ID={req_id}, error={e}')
            fail_count += 1
    
    db.session.commit()
    app.logger.info(f'管理员 {session.get("username")} 批量删除记录: 成功={success_count}, 失败={fail_count}')
    
    return jsonify({
        'success': True,
        'message': f'已删除 {success_count} 条记录',
        'success_count': success_count,
        'fail_count': fail_count
    }), 200


# ==================== 批量操作 API ====================

@app.route('/api/admin/users/import-emby', methods=['POST'])
@admin_required
def import_users_to_emby():
    """一键将面板用户导入 Emby 服务器
    
    逻辑：遍历面板中所有绑定了 emby_name 的用户，检查 Emby 服务器中是否存在该账号，
    不存在则创建。创建后根据用户状态（lv='c' 为禁用）设置 Emby 账号状态。
    """
    try:
        if not emby_client.is_enabled():
            return jsonify({'success': False, 'error': 'Emby 服务器未配置或未启用'}), 400
        
        # 先测试 Emby 连接
        try:
            test_url = f"{emby_client.base_url}/System/Info"
            test_resp = emby_client.session.get(test_url, params={'api_key': emby_client.api_key}, timeout=10)
            if test_resp.status_code != 200:
                return jsonify({'success': False, 'error': f'Emby 服务器连接失败 (HTTP {test_resp.status_code})'}), 500
        except Exception as e:
            return jsonify({'success': False, 'error': f'无法连接 Emby 服务器: {str(e)}'}), 500
        
        # 获取 Emby 服务器上已有的所有用户（用于快速比对）
        emby_users = emby_client.get_all_users()
        
        # 构建 Emby 已有用户名映射（小写比对）和 ID 集合
        emby_name_map = {u.get('Name', '').lower(): u for u in emby_users}
        emby_id_set = {u.get('Id', '') for u in emby_users}
        
        # 获取面板中所有绑定了 emby 用户名的用户
        panel_users = User.query.filter(
            User.emby_name.isnot(None),
            User.emby_name != ''
        ).all()
        
        if not panel_users:
            return jsonify({'success': True, 'message': '没有需要导入的用户', 
                           'total': 0, 'created': 0, 'skipped': 0, 'failed': 0, 'disabled': 0, 'updated': 0})
        
        total = len(panel_users)
        created = 0
        skipped = 0
        failed = 0
        disabled = 0
        updated = 0
        details = []
        
        for user in panel_users:
            emby_name = user.emby_name.strip()
            emby_id = user.embyid
            is_banned = user.lv == 'c'
            
            try:
                # 情况1：用户有 embyid 且 Emby 服务器上存在该 ID → 已存在，跳过
                if emby_id and emby_id in emby_id_set:
                    skipped += 1
                    continue
                
                # 检查 Emby 中是否已有同名用户
                existing_emby = emby_name_map.get(emby_name.lower())
                
                if existing_emby:
                    # 情况2：Emby 中已有同名用户 → 更新面板的 embyid 映射
                    new_emby_id = existing_emby.get('Id')
                    if user.embyid != new_emby_id:
                        user.embyid = new_emby_id
                        updated += 1
                        details.append(f'✏️ {emby_name}: 已关联到已有Emby账号 (ID: {new_emby_id[:8]}...)')
                    else:
                        skipped += 1
                    
                    # 如果面板中是禁用状态，同步禁用 Emby 账号
                    if is_banned:
                        emby_client.disable_user(new_emby_id)
                        disabled += 1
                    continue
                
                # 情况3：Emby 中不存在，需要创建新账号
                # pwd2 存储的是明文 Emby 密码；为空则不设置密码（Emby 允许空密码登录）
                password = user.pwd2 if user.pwd2 else ''
                
                # 直接调用 Emby API 创建用户（跳过 create_user 内部的重复检查，因为我们已经做过了）
                try:
                    create_url = f"{emby_client.base_url}/Users/New"
                    create_params = {'api_key': emby_client.api_key}
                    create_data = {'Name': emby_name}
                    
                    resp = emby_client.session.post(create_url, params=create_params, json=create_data, timeout=15)
                    
                    if resp.status_code not in [200, 201]:
                        failed += 1
                        details.append(f'❌ {emby_name}: Emby创建失败 (HTTP {resp.status_code})')
                        app.logger.warning(f'导入Emby创建用户失败: {emby_name}, status={resp.status_code}, body={resp.text[:200]}')
                        continue
                    
                    new_user_data = resp.json()
                    new_emby_id = new_user_data.get('Id')
                    
                    if not new_emby_id:
                        failed += 1
                        details.append(f'❌ {emby_name}: 创建成功但未返回ID')
                        continue
                    
                    # 设置密码（仅当面板中有保存密码时）
                    pwd_status = '无密码'
                    if password:
                        try:
                            pwd_url = f"{emby_client.base_url}/Users/{new_emby_id}/Password"
                            pwd_data = {'CurrentPw': '', 'NewPw': password}
                            pwd_resp = emby_client.session.post(pwd_url, params=create_params, json=pwd_data, timeout=10)
                            if pwd_resp.status_code in [200, 204]:
                                pwd_status = '已设置'
                            else:
                                pwd_status = '设置失败'
                                app.logger.warning(f'导入Emby设置密码失败: {emby_name}, status={pwd_resp.status_code}')
                        except Exception as pwd_e:
                            pwd_status = '设置异常'
                            app.logger.warning(f'导入Emby设置密码异常: {emby_name}, error={pwd_e}')
                    
                    # 设置用户策略（权限控制）
                    emby_client._set_user_policy(new_emby_id)
                    
                    # 更新面板用户的 embyid
                    user.embyid = new_emby_id
                    
                    # 将新创建的用户加入比对集合（防止同名重复创建）
                    emby_name_map[emby_name.lower()] = {'Id': new_emby_id, 'Name': emby_name}
                    emby_id_set.add(new_emby_id)
                    
                    # 如果是禁用用户，创建后立即禁用
                    if is_banned:
                        emby_client.disable_user(new_emby_id)
                        disabled += 1
                        details.append(f'🔒 {emby_name}: 已创建并禁用 (密码: {pwd_status})')
                    else:
                        details.append(f'✅ {emby_name}: 创建成功 (密码: {pwd_status})')
                    
                    created += 1
                    
                except Exception as create_e:
                    failed += 1
                    details.append(f'❌ {emby_name}: {str(create_e)}')
                    app.logger.error(f'导入Emby创建用户异常: {emby_name}, error={create_e}')
                
            except Exception as e:
                failed += 1
                details.append(f'❌ {emby_name}: {str(e)}')
                app.logger.error(f'导入用户到 Emby 失败: {emby_name}, error={e}')
        
        db.session.commit()
        
        app.logger.info(f'一键导入 Emby 完成: 总计={total}, 新建={created}, 已存在={skipped}, 更新映射={updated}, 禁用={disabled}, 失败={failed}')
        
        return jsonify({
            'success': True,
            'message': f'导入完成！新建 {created} 个，已存在 {skipped} 个，更新 {updated} 个，失败 {failed} 个',
            'total': total,
            'created': created,
            'skipped': skipped,
            'failed': failed,
            'disabled': disabled,
            'updated': updated,
            'details': details[-50:]  # 最多返回50条详情
        })
        
    except Exception as e:
        db.session.rollback()
        app.logger.error(f'一键导入 Emby 失败: {e}', exc_info=True)
        return jsonify({'success': False, 'error': f'导入失败: {str(e)}'}), 500


@app.route('/api/admin/users/batch', methods=['POST'])
@admin_required
def batch_users():
    """批量用户操作：禁用/解禁/删除/赠送订阅/设白名单"""
    data = request.get_json(silent=True) or {}
    ids = data.get('ids', [])
    action = data.get('action', '')
    days = data.get('days', 30)  # 赠送天数
    
    if not ids:
        return jsonify({'success': False, 'error': '未选择任何用户'}), 400
    
    success_count = 0
    fail_count = 0
    now = datetime.now()
    
    for uid in ids:
        try:
            user = db.session.get(User, uid)
            if not user:
                fail_count += 1
                continue
            
            if action == 'ban':
                user.ban_prev_lv = user.lv
                user.ban_prev_ex = user.ex
                user.ban_time = now
                user.lv = 'c'
                # 禁用Emby账号
                if user.embyid and emby_client.is_enabled():
                    emby_client.disable_user(user.embyid)
                success_count += 1
            elif action == 'unban':
                # 恢复封禁前状态
                if user.ban_prev_lv:
                    user.lv = user.ban_prev_lv
                    user.ex = user.ban_prev_ex
                else:
                    user.lv = 'b'
                user.ban_prev_lv = None
                user.ban_prev_ex = None
                user.ban_time = None
                user.ban_reason = None
                # 恢复Emby账号
                if user.embyid and emby_client.is_enabled():
                    emby_client.enable_user(user.embyid)
                success_count += 1
            elif action == 'delete':
                # 复用通用硬删除函数
                del_result = hard_delete_user_data(uid, reason='管理员批量删除')
                if del_result['db_deleted']:
                    success_count += 1
                else:
                    fail_count += 1
            elif action == 'gift':
                # 批量赠送订阅
                gift_days = int(days) if days else 30
                if user.ex and user.ex > now:
                    user.ex = user.ex + timedelta(days=gift_days)
                else:
                    user.ex = now + timedelta(days=gift_days)
                if user.lv not in ['a', 'c']:  # 白名单不变，封禁用户保持封禁状态
                    user.lv = 'b'
                # 创建订阅记录
                sub = Subscription(
                    user_tg=user.tg,
                    plan_type='gift',
                    plan_name=f'管理员赠送 {gift_days}天',
                    duration_months=max(1, -(-gift_days // 30)),
                    price=0,
                    start_date=now,
                    end_date=user.ex,
                    status='active',
                    source='gift'
                )
                db.session.add(sub)
                # 恢复Emby账号（封禁用户和黑名单禁用用户不自动恢复）
                if user.lv != 'c' and not user.ban_reason and user.embyid and emby_client.is_enabled():
                    emby_client.enable_user(user.embyid)
                success_count += 1
            elif action == 'whitelist':
                # 批量设为白名单（lv='a' + 永久到期 + plan_type='whitelist'订阅记录）
                user.lv = 'a'
                user.ex = datetime(9999, 12, 31)
                # 清除黑名单封禁信息
                user.ban_reason = None
                user.ban_time = None
                user.ban_prev_lv = None
                user.ban_prev_ex = None
                # 创建或更新白名单 Subscription
                existing_sub = Subscription.query.filter_by(
                    user_tg=user.tg, status='active'
                ).order_by(Subscription.end_date.desc()).first()
                if existing_sub:
                    existing_sub.plan_type = 'whitelist'
                    existing_sub.plan_name = '白名单用户'
                    existing_sub.end_date = datetime(9999, 12, 31)
                    existing_sub.updated_at = datetime.now()
                else:
                    new_sub = Subscription(
                        user_tg=user.tg,
                        plan_type='whitelist',
                        plan_name='白名单用户',
                        duration_months=-1,
                        price=0,
                        start_date=datetime.now(),
                        end_date=datetime(9999, 12, 31),
                        status='active',
                        source='manual'
                    )
                    db.session.add(new_sub)
                # 恢复Emby账号
                if user.embyid and emby_client.is_enabled():
                    emby_client.enable_user(user.embyid)
                success_count += 1
            elif action == 'clear_coins':
                # 批量清除积分
                old_coins = user.coins or 0
                if old_coins > 0:
                    user.coins = 0
                    # 记录积分交易
                    try:
                        coin_tx = CoinTransaction(
                            user_tg=user.tg,
                            amount=-old_coins,
                            balance_after=0,
                            trans_type='admin_deduct',
                            description='管理员批量清除积分',
                            created_at=now
                        )
                        db.session.add(coin_tx)
                    except Exception:
                        pass
                success_count += 1
            elif action == 'set_plan_type':
                # 批量设置套餐类型（按套餐ID匹配）
                plan_type_value = data.get('plan_type', '')
                if not plan_type_value:
                    fail_count += 1
                    continue
                type_labels = {}
                _plans = []
                try:
                    _plans = load_plans_config()
                    for _p in _plans:
                        pid = _p.get('id')
                        if pid and pid not in type_labels:
                            type_labels[pid] = _p.get('name', pid)
                        # 兼容旧type
                        pt = _p.get('type')
                        if pt and pt not in type_labels:
                            type_labels[pt] = _p.get('name', pt)
                except:
                    pass
                plan_name = type_labels.get(plan_type_value, plan_type_value) + '套餐'
                # 检查该套餐是否为白名单套餐（仅按套餐白名单标记）
                _is_wl_plan = is_whitelist_plan_key(plan_type_value, _plans)
                if _is_wl_plan:
                    # 白名单套餐：设为白名单用户
                    user.lv = 'a'
                    user.ex = datetime(9999, 12, 31)
                    plan_type_value = 'whitelist'
                    plan_name = '白名单用户'
                else:
                    # 普通套餐：确保用户是订阅用户
                    if user.lv == 'a':
                        user.lv = 'b'
                    elif user.lv not in ['a', 'b', 'c']:
                        user.lv = 'b'
                # 更新或创建 Subscription 记录
                existing_sub = Subscription.query.filter_by(
                    user_tg=user.tg, status='active'
                ).order_by(Subscription.end_date.desc()).first()
                if existing_sub:
                    existing_sub.plan_type = plan_type_value
                    existing_sub.plan_name = plan_name
                    existing_sub.updated_at = now
                else:
                    new_sub = Subscription(
                        user_tg=user.tg,
                        plan_type=plan_type_value,
                        plan_name=plan_name,
                        duration_months=1,
                        price=0,
                        start_date=now,
                        end_date=user.ex if user.ex and user.ex > now else now,
                        status='active',
                        source='manual'
                    )
                    db.session.add(new_sub)
                # 清除黑名单封禁信息
                user.ban_reason = None
                user.ban_time = None
                user.ban_prev_lv = None
                user.ban_prev_ex = None
                # 启用 Emby 账号（如果之前被禁用）
                if user.embyid and emby_client.is_enabled():
                    emby_client.enable_user(user.embyid)
                success_count += 1
            else:
                fail_count += 1
        except Exception as e:
            db.session.rollback()
            app.logger.error(f'批量用户操作失败: ID={uid}, action={action}, error={e}', exc_info=True)
            fail_count += 1
    
    try:
        db.session.commit()
    except Exception as e:
        db.session.rollback()
        app.logger.error(f'批量操作提交失败: action={action}, error={e}', exc_info=True)
        return jsonify({'success': False, 'error': f'操作提交失败: {str(e)}'}), 500
    
    app.logger.info(f'管理员批量{action}用户: 成功={success_count}, 失败={fail_count}')
    return jsonify({'success': True, 'message': f'已处理 {success_count} 个用户', 'success_count': success_count, 'fail_count': fail_count})


@app.route('/api/admin/orders/batch', methods=['POST'])
@admin_required
def batch_orders():
    """批量订单操作：取消/删除"""
    data = request.get_json(silent=True) or {}
    order_nos = data.get('order_nos', [])
    action = data.get('action', '')
    
    if not order_nos:
        return jsonify({'success': False, 'error': '未选择任何订单'}), 400
    
    success_count = 0
    fail_count = 0
    
    for order_no in order_nos:
        try:
            order = Order.query.filter_by(order_no=order_no).first()
            if not order:
                fail_count += 1
                continue
            
            if action == 'cancel':
                if order.payment_status == 'pending':
                    order.payment_status = 'cancelled'
                    success_count += 1
                else:
                    fail_count += 1
            elif action == 'delete':
                db.session.delete(order)
                success_count += 1
            else:
                fail_count += 1
        except Exception as e:
            app.logger.error(f'批量订单操作失败: {order_no}, error={e}')
            fail_count += 1
    
    db.session.commit()
    app.logger.info(f'管理员批量{action}订单: 成功={success_count}, 失败={fail_count}')
    return jsonify({'success': True, 'message': f'已处理 {success_count} 个订单', 'success_count': success_count})


