@app.route('/api/admin/subscriptions/batch', methods=['POST'])
@admin_required
def batch_subscriptions():
    """批量订阅操作：删除/延期（基于用户tg ID）"""
    data = request.get_json(silent=True) or {}
    ids = data.get('ids', [])
    action = data.get('action', '')
    days = data.get('days', 30)
    
    if not ids:
        return jsonify({'success': False, 'error': '未选择任何订阅'}), 400
    
    success_count = 0
    fail_count = 0
    now = datetime.now()
    
    for uid in ids:
        try:
            uid_int = int(uid)
            if action == 'delete':
                # 删除该用户的所有订阅记录
                deleted = Subscription.query.filter_by(user_tg=uid_int).delete()
                if deleted > 0:
                    success_count += 1
                else:
                    # 没有订阅记录也算成功（因为订阅页面显示的是用户信息）
                    success_count += 1
            elif action == 'extend':
                # 批量延期订阅
                user = db.session.get(User, uid_int)
                if user:
                    extend_days = int(days) if days else 30
                    if user.ex and user.ex > now:
                        user.ex = user.ex + timedelta(days=extend_days)
                    else:
                        user.ex = now + timedelta(days=extend_days)
                    if user.lv not in ['a', 'c']:  # 白名单不变，封禁用户保持封禁状态
                        user.lv = 'b'
                    # 创建订阅记录
                    sub = Subscription(
                        user_tg=user.tg,
                        plan_type='extend',
                        plan_name=f'管理员延期 {extend_days}天',
                        duration_months=max(1, -(-extend_days // 30)),
                        price=0,
                        start_date=now,
                        end_date=user.ex,
                        status='active',
                        source='gift'
                    )
                    db.session.add(sub)
                    # 恢复Emby账号（封禁用户和黑名单禁用用户不自动恢复）
                    if user.lv != 'c' and not user.ban_reason and user.embyid and emby_client.is_enabled():
                        emby_client.enable_user(user.embyid)
                    success_count += 1
                else:
                    fail_count += 1
            else:
                fail_count += 1
        except Exception as e:
            app.logger.error(f'批量订阅操作失败: ID={uid}, error={e}')
            fail_count += 1
    
    db.session.commit()
    app.logger.info(f'管理员批量{action}订阅: 成功={success_count}, 失败={fail_count}')
    return jsonify({'success': True, 'message': f'已处理 {success_count} 条订阅', 'success_count': success_count})


