@app.route('/api/subscription/benefits', methods=['GET'])
@login_required
def get_subscription_benefits():
    try:
        user = db.session.get(User, session.get('user_id'))
        config = load_system_config()
        default_benefits = config.get('default_benefits', {})
        
        if is_whitelist_user(user):
            benefits = default_benefits.get('whitelist', [
                {'icon': '🎬', 'text': '无限求片'},
                {'icon': '⚡', 'text': '最高优先级'},
                {'icon': '📺', 'text': '4K超清资源'},
                {'icon': '💬', 'text': 'VIP专属客服'}
            ])
            return jsonify({
                'success': True,
                'benefits': benefits,
                'plan_type': 'whitelist'
            }), 200
        
        # 检查用户是否有有效订阅
        if user and user.ex and user.ex > datetime.now():
            subscription = get_latest_active_subscription(user)
            if subscription:
                plans = load_plans_config()
                for plan in plans:
                    if resolve_plan_config(subscription.plan_type, [plan]):
                        benefits = plan.get('benefits', plan.get('features', []))
                        if benefits and isinstance(benefits[0], str):
                            benefits = [{'icon': '✨', 'text': b} for b in benefits]
                        return jsonify({
                            'success': True,
                            'benefits': benefits,
                            'plan_type': subscription.plan_type,
                            'plan_name': plan.get('name', '')
                        }), 200
            
            benefits = default_benefits.get('subscribed', [
                {'icon': '🎬', 'text': '每日求片'},
                {'icon': '⚡', 'text': '优先处理'},
                {'icon': '📺', 'text': '高清资源'},
                {'icon': '💬', 'text': '专属客服'}
            ])
            return jsonify({
                'success': True,
                'benefits': benefits,
                'plan_type': 'subscribed'
            }), 200
        
        # 未订阅用户
        benefits = default_benefits.get('unsubscribed', [
            {'icon': '🚫', 'text': '无求片权限'},
            {'icon': '⏳', 'text': '普通处理'},
            {'icon': '📺', 'text': '标清资源'},
            {'icon': '💬', 'text': '社区支持'}
        ])
        return jsonify({
            'success': True,
            'benefits': benefits,
            'plan_type': 'unsubscribed'
        }), 200
        
    except Exception as e:
        app.logger.error(f'获取订阅权益配置失败: {e}')
        return jsonify({'error': str(e)}), 500


@app.route('/api/admin/default-benefits', methods=['GET', 'POST'])
@admin_required
def admin_default_benefits():
    """管理默认权益配置（未订阅用户和白名单用户）"""
    config = load_system_config()
    
    if request.method == 'GET':
        default_benefits = config.get('default_benefits', {
            'unsubscribed': [
                {'icon': '🚫', 'text': '无求片权限'},
                {'icon': '⏳', 'text': '普通处理'},
                {'icon': '📺', 'text': '标清资源'},
                {'icon': '💬', 'text': '社区支持'}
            ],
            'whitelist': [
                {'icon': '🎬', 'text': '无限求片'},
                {'icon': '⚡', 'text': '最高优先级'},
                {'icon': '📺', 'text': '4K超清资源'},
                {'icon': '💬', 'text': 'VIP专属客服'}
            ]
        })
        return jsonify({
            'success': True,
            'default_benefits': default_benefits
        }), 200
    
    elif request.method == 'POST':
        try:
            data = request.json
            default_benefits = data.get('default_benefits', {})
            
            # 验证数据格式
            for key in ['unsubscribed', 'whitelist']:
                benefits = default_benefits.get(key, [])
                if len(benefits) > 8:
                    return jsonify({'success': False, 'error': f'{key}最多只能配置8个权益'}), 400
            
            config['default_benefits'] = default_benefits
            
            if save_system_config(config):
                return jsonify({
                    'success': True,
                    'message': '默认权益配置已保存'
                }), 200
            else:
                return jsonify({'success': False, 'error': '保存配置失败'}), 500
                
        except Exception as e:
            app.logger.error(f'保存默认权益配置失败: {e}')
            return jsonify({'error': str(e)}), 500


@app.route('/api/subscription/current', methods=['GET'])
@login_required
def get_current_subscription():
    """获取当前用户的订阅信息"""
    try:
        user = db.session.get(User, session.get('user_id'))
        if not user:
            return jsonify({'error': '用户不存在'}), 404
        
        # ===== 构建保号配置信息 =====
        config = load_system_config()
        expire_config = config.get('subscription_expire', {})
        checkin_config = config.get('checkin', {})
        retention_mode = expire_config.get('retention_mode', 'off')
        retention_info = None
        if retention_mode != 'off':
            retention_info = {
                'mode': retention_mode,
                'renew_days': expire_config.get('retention_renew_days', 30),
                'coin_name': checkin_config.get('coin_name', '积分'),
                'user_coins': user.coins or 0,
            }
            if retention_mode in ('checkin', 'both'):
                retention_info['checkin_cost'] = expire_config.get('retention_checkin_cost', 10)
            if retention_mode in ('watch', 'both'):
                retention_info['watch_days'] = expire_config.get('retention_watch_days', 30)
                retention_info['watch_minutes'] = expire_config.get('retention_watch_minutes', 30)
        
        # 白名单用户特殊处理：通过 Subscription plan_type='whitelist' 判断（兼容旧 lv='a'）
        # 检查 Subscription 表是否有白名单记录
        whitelist_sub = Subscription.query.filter_by(
            user_tg=user.tg, status='active', plan_type='whitelist'
        ).first()
        
        if whitelist_sub or user.lv == 'a':
            return jsonify({
                'success': True,
                'subscription': {
                    'id': whitelist_sub.id if whitelist_sub else 0,
                    'user_tg_id': user.tg,
                    'user_name': user.name,
                    'plan_type': 'whitelist',
                    'plan_name': '白名单用户',
                    'duration_months': -1,  # -1 表示永久
                    'price': 0,
                    'start_date': (whitelist_sub.start_date.isoformat() if whitelist_sub else user.cr.isoformat()) if (whitelist_sub or user.cr) else None,
                    'end_date': None,  # 永不过期
                    'status': 'active',
                    'days_remaining': '永久',
                    'is_whitelist': True
                },
                'retention': retention_info
            }), 200
        
        # 优先检查用户的 ex（到期时间）字段 - 这是订阅状态的主要来源
        if user.ex and user.ex > datetime.now():
            # 用户有有效的到期时间
            days_remaining = (user.ex - datetime.now()).days
            
            # 尝试从 Subscription 表获取更多信息
            subscription = Subscription.query.filter_by(
                user_tg=user.tg,
                status='active'
            ).order_by(Subscription.end_date.desc()).first()
            
            if subscription:
                return jsonify({
                    'success': True,
                    'subscription': subscription.to_dict(),
                    'retention': retention_info
                }), 200
            else:
                # 没有 Subscription 记录但有 user.ex，说明是通过其他方式设置的（如管理员手动设置）
                return jsonify({
                    'success': True,
                    'subscription': {
                        'id': 0,
                        'user_tg_id': user.tg,
                        'user_name': user.name,
                        'plan_type': 'manual',
                        'plan_name': '订阅用户',
                        'duration_months': 0,
                        'price': 0,
                        'start_date': user.cr.isoformat() if user.cr else None,
                        'end_date': user.ex.isoformat() if user.ex else None,
                        'status': 'active',
                        'days_remaining': days_remaining,
                        'is_whitelist': False
                    },
                    'retention': retention_info
                }), 200
        
        # 用户没有有效的到期时间
        return jsonify({
            'success': True,
            'subscription': None,
            'retention': retention_info,
            'message': '暂无有效订阅'
        }), 200
    except Exception as e:
        app.logger.error(f'获取订阅信息失败: {e}')
        return jsonify({'error': str(e)}), 500


@app.route('/api/subscription/history', methods=['GET'])
@login_required
def get_subscription_history():
    """获取订阅历史"""
    try:
        user = db.session.get(User, session.get('user_id'))
        now = datetime.now()
        
        # 自动更新订阅状态：
        # 1. 将已过期的 active 订阅标记为 expired
        # 2. 将已到开始时间的 pending 订阅激活为 active
        expired_subs = Subscription.query.filter_by(
            user_tg=user.tg,
            status='active'
        ).filter(Subscription.end_date <= now).all()
        
        for sub in expired_subs:
            sub.status = 'expired'
        
        pending_subs = Subscription.query.filter_by(
            user_tg=user.tg,
            status='pending'
        ).filter(Subscription.start_date <= now).all()
        
        for sub in pending_subs:
            sub.status = 'active'
        
        if expired_subs or pending_subs:
            db.session.commit()
        
        subscriptions = Subscription.query.filter_by(user_tg=user.tg).order_by(
            Subscription.start_date.desc()
        ).all()
        
        # 如果没有 Subscription 记录，但用户有有效的到期时间(user.ex)，补充创建一条记录
        if not subscriptions and user.ex and user.ex > datetime.now():
            # 尝试从订单表找到最近的已支付订单来确定套餐信息
            recent_order = Order.query.filter_by(
                user_tg=user.tg,
                payment_status='paid'
            ).order_by(Order.payment_time.desc()).first()
            
            if recent_order:
                # 根据订单创建订阅记录
                subscription = Subscription(
                    user_tg=user.tg,
                    plan_type=recent_order.plan_type,
                    plan_name=recent_order.plan_name,
                    duration_months=recent_order.duration_months,
                    price=recent_order.final_price,
                    start_date=recent_order.payment_time or datetime.now(),
                    end_date=user.ex,
                    status='active',
                    source='purchase'
                )
                db.session.add(subscription)
                db.session.commit()
                app.logger.info(f'自动补充创建订阅记录: 用户={user.name}, 套餐={recent_order.plan_name}')
                subscriptions = [subscription]
            else:
                # 没有订单记录，可能是管理员手动设置的，创建一个通用记录
                subscription = Subscription(
                    user_tg=user.tg,
                    plan_type='manual',
                    plan_name='订阅会员',
                    duration_months=max(1, (user.ex - datetime.now()).days // 30),
                    price=0,
                    start_date=user.cr or datetime.now(),
                    end_date=user.ex,
                    status='active',
                    source='manual'
                )
                db.session.add(subscription)
                db.session.commit()
                app.logger.info(f'自动补充创建订阅记录(手动设置): 用户={user.name}')
                subscriptions = [subscription]
        
        return jsonify({
            'success': True,
            'subscriptions': [sub.to_dict() for sub in subscriptions]
        }), 200
    except Exception as e:
        app.logger.error(f'获取订阅历史失败: {e}')
        return jsonify({'error': str(e)}), 500


