@app.route('/api/orders/cancel', methods=['POST'])
@login_required
def cancel_order():
    """取消订单"""
    try:
        data = request.json
        order_no = data.get('order_no')
        
        if not order_no:
            return jsonify({'error': '订单号不能为空'}), 400
        
        user = db.session.get(User, session.get('user_id'))
        order = Order.query.filter_by(order_no=order_no, user_tg=user.tg).first()
        
        if not order:
            return jsonify({'error': '订单不存在'}), 404
        
        if order.payment_status != 'pending':
            return jsonify({'error': '只能取消待支付订单'}), 400
        
        order.payment_status = 'cancelled'
        db.session.commit()
        
        app.logger.info(f'取消订单: {order_no}, 用户: {user.name}')
        
        return jsonify({
            'success': True,
            'message': '订单已取消'
        }), 200
        
    except Exception as e:
        app.logger.error(f'取消订单失败: {e}')
        db.session.rollback()
        return jsonify({'error': str(e)}), 500


# ==================== 兑换码 API ====================

@app.route('/api/redeem/use', methods=['POST'])
@login_required
def use_redeem_code():
    """使用兑换码"""
    try:
        # —— 后端验证码校验（防脚本刷兑换码） ——
        data = request.get_json(silent=True) or {}
        captcha_answer = data.get('captcha_answer')
        ok, err = _verify_captcha(captcha_answer)
        if not ok:
            return jsonify({'success': False, 'error': err}), 400

        code = data.get('code', '').strip().upper()
        
        if not code:
            app.logger.warning(f'兑换码使用失败 - 原因: 未输入兑换码')
            return jsonify({'success': False, 'error': '请输入兑换码'}), 400
        
        user = db.session.get(User, session.get('user_id'))
        if not user:
            app.logger.warning(f'兑换码使用失败 - 原因: 用户不存在 (session user_id={session.get("user_id")})')
            return jsonify({'success': False, 'error': '用户不存在，请重新登录'}), 401
        
        if not user.tg:
            app.logger.warning(f'兑换码使用失败 - 用户: {user.name}, 原因: 缺少TG标识')
            return jsonify({'success': False, 'error': '用户账户异常，缺少TG标识'}), 400
        
        app.logger.info(f'用户 {user.name}(tg={user.tg}) 尝试使用兑换码: {code}')
        
        # 查找兑换码（MySQL 加行级锁防并发竞态；SQLite 单写者模型天然安全）
        is_mysql = 'mysql' in app.config.get('SQLALCHEMY_DATABASE_URI', '')
        query = RedeemCode.query.filter_by(code=code)
        if is_mysql:
            query = query.with_for_update()
        redeem = query.first()
        
        if not redeem:
            app.logger.warning(f'兑换码使用失败 - 用户: {user.name}(tg={user.tg}), 兑换码: {code}, 原因: 兑换码不存在')
            return jsonify({'success': False, 'error': '兑换码不存在，请检查输入是否正确'}), 404

        # 兜底校验：历史脏数据或异常生成的兑换码直接拦截，避免污染用户订阅状态
        if redeem.code_type not in {'new', 'renew'}:
            app.logger.error(
                f'兑换码数据异常 - code={code}, code_type={redeem.code_type}, '
                f'user={user.name}(tg={user.tg})'
            )
            return jsonify({'success': False, 'error': '兑换码数据异常，请联系管理员处理'}), 400
        if not redeem.duration_days or int(redeem.duration_days) <= 0:
            app.logger.error(
                f'兑换码数据异常 - code={code}, duration_days={redeem.duration_days}, '
                f'user={user.name}(tg={user.tg})'
            )
            return jsonify({'success': False, 'error': '兑换码时长异常，请联系管理员处理'}), 400
        
        if redeem.is_used:
            # 同一用户重复提交同一码：返回幂等成功，避免“已生效但前端误报失败”后再次尝试时造成困惑
            if str(redeem.used_by or '') == str(user.tg):
                app.logger.info(
                    f'兑换码重复提交(幂等成功) - 用户: {user.name}(tg={user.tg}), '
                    f'兑换码: {code}, used_at={redeem.used_at}'
                )
                return jsonify({
                    'success': True,
                    'message': '该兑换码已兑换成功，无需重复操作',
                    'plan_type': redeem.plan_type,
                    'duration_days': redeem.duration_days,
                    'code_type': redeem.code_type,
                    'has_emby_account': bool(user.embyid),
                    'reused': True
                }), 200
            app.logger.warning(f'兑换码使用失败 - 用户: {user.name}(tg={user.tg}), 兑换码: {code}, 原因: 兑换码已被使用 (used_by={redeem.used_by}, used_at={redeem.used_at})')
            return jsonify({'success': False, 'error': '兑换码已被使用，每个兑换码只能使用一次'}), 400
        
        if not redeem.is_active:
            app.logger.warning(f'兑换码使用失败 - 用户: {user.name}(tg={user.tg}), 兑换码: {code}, 原因: 兑换码已被禁用')
            return jsonify({'success': False, 'error': '兑换码已被禁用，请联系管理员'}), 400
        
        # 检查是否过期
        if redeem.expires_at and redeem.expires_at < datetime.now():
            app.logger.warning(f'兑换码使用失败 - 用户: {user.name}(tg={user.tg}), 兑换码: {code}, 原因: 兑换码已过期 (expires_at={redeem.expires_at})')
            return jsonify({'success': False, 'error': '兑换码已过期，请使用有效的兑换码'}), 400
        
        # 校验兑换码类型与用户状态是否匹配
        has_emby = bool(user.embyid)
        if redeem.code_type == 'new' and has_emby:
            app.logger.warning(f'兑换码使用失败 - 用户: {user.name}(tg={user.tg}), 兑换码: {code}, 原因: 类型不匹配(注册码但用户已有Emby账号)')
            return jsonify({'success': False, 'error': '您已有 Emby 账号，此为注册码，仅限未开通账号的用户使用。请使用续期码延长订阅。'}), 400
        
        if redeem.code_type == 'renew' and not has_emby:
            app.logger.warning(f'兑换码使用失败 - 用户: {user.name}(tg={user.tg}), 兑换码: {code}, 原因: 类型不匹配(续期码但用户无Emby账号)')
            return jsonify({'success': False, 'error': '您还没有 Emby 账号，此为续期码，仅限已有账号的用户使用。请先使用注册码开通账号。'}), 400
        
        # 获取套餐配置
        plans_config = []
        try:
            plans_config = load_plans_config()
        except Exception as e:
            app.logger.error(f'加载套餐配置失败: {e}')
        
        # 从配置中获取套餐名称
        plan_name = redeem.plan_type
        if redeem.plan_type == 'custom':
            plan_name = '自定义时长'
        else:
            for plan in plans_config:
                if resolve_plan_config(redeem.plan_type, [plan]):
                    plan_name = plan.get('name', redeem.plan_type)
                    break
        
        # 计算月数（向上取整，保证 Subscription.duration_months 不为 0）
        duration_months = max(1, -(-redeem.duration_days // 30))  # ceil division
        
        # 检查该套餐是否为白名单套餐（仅按套餐白名单标记）
        _redeem_plan_type = redeem.plan_type
        _redeem_plan_name = plan_name
        _redeem_is_wl = is_whitelist_plan_key(redeem.plan_type, plans_config)
        
        # 计算订阅时间 - 所有类型都立即生效，在现有到期时间基础上叠加
        now = datetime.now()
        start_date = now
        
        if _redeem_is_wl:
            # 白名单套餐：永久有效
            end_date = datetime(9999, 12, 31)
            _redeem_plan_type = 'whitelist'
            _redeem_plan_name = '白名单用户'
        else:
            # 普通套餐：如果用户已有未过期的到期时间，在此基础上叠加
            if user.ex and user.ex > now:
                end_date = user.ex + timedelta(days=redeem.duration_days)
            else:
                end_date = now + timedelta(days=redeem.duration_days)
        
        # 创建订阅记录
        subscription = Subscription(
            user_tg=user.tg,
            plan_type=_redeem_plan_type,
            plan_name=_redeem_plan_name,
            duration_months=duration_months,
            price=0,  # 兑换码免费
            start_date=start_date,
            end_date=end_date,
            status='active',
            source='redeem'
        )
        db.session.add(subscription)
        
        # 标记兑换码已使用
        redeem.is_used = True
        redeem.used_by = user.tg
        redeem.used_at = datetime.now()
        
        # 同步更新用户表的订阅状态
        if _redeem_is_wl:
            user.lv = 'a'  # 白名单套餐设为白名单等级
        elif user.lv not in ['a', 'c']:
            # 普通套餐：白名单不变，封禁用户保持封禁状态
            user.lv = 'b'
        
        # 更新过期时间 - 直接使用上面已经正确计算（含叠加）的 end_date
        user.ex = end_date
        
        app.logger.info(f'更新用户订阅状态: lv={user.lv}, ex={user.ex}')
        
        # 邀请返利：检查是否有邀请人，给邀请人返利
        process_invite_reward(user, redeem.duration_days, source='兑换码')
        
        db.session.commit()
        
        app.logger.info(f'兑换码使用成功: {code}, 用户: {user.name}(tg={user.tg}), 类型: {redeem.code_type}, 套餐: {plan_name}, 天数: {redeem.duration_days}')
        
        # 检查用户是否有 Emby 账号（commit 后立即取值，供返回和后台线程使用）
        has_emby_account = bool(user.embyid)
        _emby_id = user.embyid
        _emby_name = user.emby_name
        _user_name = user.name
        _user_tg = user.tg
        _user_lv = user.lv
        _user_ban_reason = user.ban_reason
        _display_name = user.emby_name or user.name or str(user.tg)
        _code_type = redeem.code_type
        _plan_type = redeem.plan_type
        _duration_days = redeem.duration_days
        
        # —— 耗时 IO 操作放入后台线程，主线程立即返回给用户 ——
        def _post_redeem_tasks():
            with app.app_context():
                # 恢复 Emby 账号（封禁用户和黑名单禁用用户不自动恢复）
                if _user_lv != 'c' and not _user_ban_reason and _emby_id and emby_client.is_enabled():
                    if emby_client.enable_user(_emby_id):
                        app.logger.info(f'用户 {_user_name} 兑换成功，已恢复Emby账号 {_emby_name}')
                
                # 记录活动日志
                try:
                    log_user_activity(UserActivityLog.ACTION_REDEEM_CODE, user_tg=_user_tg, user_name=_user_name,
                                     detail={'code': code, 'plan_type': _plan_type, 'plan_name': plan_name,
                                            'duration_days': _duration_days, 'code_type': _code_type})
                except Exception as e:
                    app.logger.warning(f'记录兑换码活动日志失败: {e}')
                
                # 发送 Telegram 通知
                try:
                    code_type_name = '注册码' if _code_type == 'new' else '续期码'
                    masked_code = code[:4] + '░' * max(len(code) - 4, 0) if len(code) > 4 else code
                    notify_msg = (
                        f"· 🎟️ <b>{code_type_name}使用</b> - "
                        f"<a href=\"tg://user?id={_user_tg}\">{_display_name}</a> "
                        f"[<code>{_user_tg}</code>] "
                        f"使用了 <code>{masked_code}</code>\n"
                        f"· 📅 到期: {end_date.strftime('%Y-%m-%d')}"
                    )
                    send_admin_notification(notify_msg)
                except Exception as e:
                    app.logger.warning(f'发送兑换码使用群组通知失败: {e}')
        
        Thread(target=_post_redeem_tasks, daemon=True).start()
        
        return jsonify({
            'success': True,
            'message': f'🎉 兑换成功！已获得 {plan_name} {redeem.duration_days} 天',
            'plan_type': _plan_type,
            'plan_name': plan_name,
            'duration_days': _duration_days,
            'code_type': _code_type,
            'has_emby_account': has_emby_account
        }), 200
        
    except Exception as e:
        app.logger.error(f'使用兑换码失败: {e}')
        db.session.rollback()
        return jsonify({'error': str(e)}), 500


# ==================== 支付 API ====================

def epay_sign(params, key):
    """易支付签名生成"""
    # 1. 过滤空值和sign、sign_type参数
    filtered = {k: v for k, v in params.items() if v and k not in ['sign', 'sign_type']}
    # 2. 按参数名ASCII码排序
    sorted_params = sorted(filtered.items(), key=lambda x: x[0])
    # 3. 拼接为 key=value& 格式
    sign_str = '&'.join([f'{k}={v}' for k, v in sorted_params])
    # 4. 拼接商户密钥
    sign_str += key
    # 5. MD5加密
    return hashlib.md5(sign_str.encode('utf-8')).hexdigest()


def epay_verify_sign(params, key):
    """易支付签名验证"""
    sign = params.get('sign', '')
    if not sign:
        return False
    return epay_sign(params, key) == sign


@app.route('/api/payment/create', methods=['POST'])
@login_required
def create_payment():
    """创建支付（对接易支付）"""
    try:
        data = request.json
        order_no = data.get('order_no')
        payment_method = data.get('payment_method', 'alipay')
        
        order = Order.query.filter_by(order_no=order_no).first()
        if not order:
            return jsonify({'error': '订单不存在'}), 404
        
        # 验证订单归属（防止用户支付别人的订单）
        user = db.session.get(User, session.get('user_id'))
        if not user or order.user_tg != user.tg:
            return jsonify({'error': '无权操作此订单'}), 403
        
        if order.payment_status == 'paid':
            return jsonify({'error': '订单已支付'}), 400
        
        if order.payment_status == 'cancelled':
            return jsonify({'error': '订单已取消，请重新下单'}), 400

        def _safe_float(v, default=0.0):
            return _safe_price_float(v, default)

        # 兼容历史待支付白名单订单：
        # 如果旧订单是在白名单价格修复前创建的，这里按当前套餐配置重新校正金额，避免继续支付 999 元旧金额。
        current_plan_config = resolve_plan_config(order.plan_type)
        if current_plan_config and is_whitelist_plan_config(current_plan_config):
            corrected_price = resolve_whitelist_once_price(current_plan_config, plan_key=order.plan_type)

            if corrected_price <= 0:
                return jsonify({'error': '白名单套餐未配置一次性价格，请联系管理员检查套餐设置'}), 400

            try:
                corrected_days = int(current_plan_config.get('duration_days', WHITELIST_INTERNAL_DAYS) or WHITELIST_INTERNAL_DAYS)
            except (TypeError, ValueError):
                corrected_days = WHITELIST_INTERNAL_DAYS
            corrected_plan_name = to_db_safe_text(
                f"{current_plan_config.get('name', order.plan_name or '套餐')}(永久)",
                max_length=100
            ) or '套餐(永久)'

            if (
                abs(float(order.final_price or 0) - corrected_price) > 1e-9 or
                int(order.duration_months or 0) != 0 or
                int(order.duration_days or 0) != corrected_days or
                (order.plan_name or '') != corrected_plan_name
            ):
                app.logger.warning(
                    f'检测到历史白名单待支付订单金额/信息不一致，已自动校正: '
                    f'order_no={order.order_no}, old_price={order.final_price}, new_price={corrected_price}, '
                    f'old_duration_months={order.duration_months}, new_duration_days={corrected_days}'
                )
                order.duration_months = 0
                order.duration_days = corrected_days
                order.original_price = corrected_price
                order.discount = 0
                order.final_price = corrected_price
                order.plan_name = corrected_plan_name
                db.session.commit()
        
        # 动态获取易支付配置
        epay_config = get_epay_config()
        epay_url = epay_config['epay_url'].rstrip('/') if epay_config['epay_url'] else ''
        epay_pid = epay_config['epay_pid']
        epay_key = epay_config['epay_key']
        epay_notify = epay_config['epay_notify_url']
        epay_return = epay_config['epay_return_url']
        
        # 检查易支付配置
        if not epay_url or not epay_pid or not epay_key:
            # 如果未配置易支付，返回测试模式提示
            return jsonify({
                'success': False,
                'error': '支付功能未配置，请联系管理员在系统设置中配置易支付参数',
                'test_mode': True
            }), 400
        
        # 构建易支付请求参数
        # 获取当前站点地址
        site_url = request.host_url.rstrip('/')
        notify_url = epay_notify or f'{site_url}/api/payment/notify'
        return_url = epay_return or f'{site_url}/dashboard#purchase'
        
        # 支付类型映射
        pay_type_map = {
            'alipay': 'alipay',
            'wxpay': 'wxpay', 
            'qqpay': 'qqpay'
        }
        pay_type = pay_type_map.get(payment_method, 'alipay')
        
        params = {
            'pid': epay_pid,
            'type': pay_type,
            'out_trade_no': order_no,
            'notify_url': notify_url,
            'return_url': return_url,
            'name': order.plan_name or f'{order.plan_type}套餐',
            'money': str(order.final_price),
            'sitename': 'Emby媒体库'
        }
        
        # 生成签名
        params['sign'] = epay_sign(params, epay_key)
        params['sign_type'] = 'MD5'
        
        # 构建支付URL（提交到易支付网关）
        payment_url = f'{epay_url}/submit.php'
        
        # 使用 GET 方式跳转
        query_string = '&'.join([f'{k}={requests.utils.quote(str(v))}' for k, v in params.items()])
        redirect_url = f'{epay_url}/submit.php?{query_string}'
        
        app.logger.info(f'创建易支付订单: 订单={order_no}, 金额={order.final_price}, 方式={payment_method}')
        
        return jsonify({
            'success': True,
            'payment_url': redirect_url,
            'params': params,  # 也返回参数供前端表单提交
            'submit_url': payment_url
        }), 200
        
    except Exception as e:
        app.logger.error(f'创建支付失败: {e}')
        return jsonify({'error': str(e)}), 500


@app.route('/api/payment/notify', methods=['POST', 'GET'])
def payment_notify():
    """易支付异步通知回调"""
    try:
        # 易支付会同时发送 GET 和 POST 请求
        if request.method == 'GET':
            params = request.args.to_dict()
        else:
            params = request.form.to_dict() if request.form else request.json or {}
        
        app.logger.info(f'收到易支付通知: {params}')
        
        # 动态获取配置验证签名
        epay_config = get_epay_config()
        epay_key = epay_config['epay_key']
        
        # 验证签名
        if epay_key and not epay_verify_sign(params, epay_key):
            app.logger.warning(f'易支付签名验证失败: {params}')
            return 'sign error', 400
        
        # 获取参数
        trade_status = params.get('trade_status', '')
        out_trade_no = params.get('out_trade_no', '')  # 商户订单号
        trade_no = params.get('trade_no', '')  # 易支付订单号
        money = params.get('money', '')
        
        # 只处理支付成功的通知
        if trade_status != 'TRADE_SUCCESS':
            app.logger.info(f'订单状态非成功: {trade_status}')
            return 'success'  # 返回success避免重复通知
        
        # 查找订单
        order = Order.query.filter_by(order_no=out_trade_no).first()
        if not order:
            app.logger.error(f'订单不存在: {out_trade_no}')
            return 'order not found', 404
        
        # 检查是否已处理
        if order.payment_status == 'paid':
            app.logger.info(f'订单已处理: {out_trade_no}')
            return 'success'
        
        # 已取消的订单不能再被激活
        if order.payment_status == 'cancelled':
            app.logger.warning(f'已取消的订单收到支付通知，忽略: {out_trade_no}')
            return 'order cancelled'
        
        # 验证金额（可选，但推荐）
        if money and float(money) != float(order.final_price):
            app.logger.warning(f'金额不匹配: 订单金额={order.final_price}, 实付={money}')
        
        # 更新订单状态
        order.payment_status = 'paid'
        order.payment_time = datetime.now()
        order.trade_no = trade_no
        
        # 创建订阅记录
        user = db.session.get(User, order.user_tg)
        if user:
            # 计算订阅开始和结束时间 - 在现有订阅基础上叠加
            now = datetime.now()
            start_date = now
            purchased_days = order.duration_days if order.duration_days else (order.duration_months * 30)
            
            # 检查该套餐是否为白名单套餐（仅按套餐白名单标记）
            _purchase_plan_type = order.plan_type
            _purchase_plan_name = order.plan_name
            _is_wl_purchase = is_whitelist_plan_key(order.plan_type)
            
            if _is_wl_purchase:
                # 白名单套餐：永久有效
                end_date = datetime(9999, 12, 31)
                _purchase_plan_type = 'whitelist'
                _purchase_plan_name = '白名单用户'
            else:
                # 普通套餐：在现有订阅基础上叠加
                if user.ex and user.ex > now:
                    end_date = user.ex + timedelta(days=purchased_days)
                else:
                    end_date = now + timedelta(days=purchased_days)
            
            subscription = Subscription(
                user_tg=user.tg,
                plan_type=_purchase_plan_type,
                plan_name=_purchase_plan_name,
                duration_months=order.duration_months,
                price=order.final_price,
                start_date=start_date,
                end_date=end_date,
                status='active',
                source='purchase'
            )
            
            db.session.add(subscription)
            
            # 更新用户信息
            user.ex = end_date
            if _is_wl_purchase:
                user.lv = 'a'  # 白名单套餐设为白名单等级
            elif user.lv not in ['a', 'b', 'c']:  # 普通用户不变，封禁用户保持封禁状态
                user.lv = 'b'
            
            # 恢复Emby账号（封禁用户和黑名单禁用用户不自动恢复）
            if user.lv != 'c' and not user.ban_reason and user.embyid and emby_client.is_enabled():
                if emby_client.enable_user(user.embyid):
                    app.logger.info(f'用户 {user.name} 续费成功，已恢复Emby账号')
            
            # 邀请返利：检查是否有邀请人，给邀请人返利
            process_invite_reward(user, purchased_days, source='易支付通知')
        
        db.session.commit()
        app.logger.info(f'易支付成功: 订单={out_trade_no}, 交易号={trade_no}, 天数={purchased_days if user else "N/A"}')
        
        # 记录支付成功日志
        if user:
            log_user_activity(UserActivityLog.ACTION_PAYMENT_SUCCESS, user=user,
                             detail={'order_no': out_trade_no, 'trade_no': trade_no, 'amount': money,
                                    'plan_name': order.plan_name, 'duration_days': purchased_days})
        
        # 返回success告知易支付不再重复通知
        return 'success'
        
    except Exception as e:
        app.logger.error(f'易支付通知处理失败: {e}')
        db.session.rollback()
        return 'error', 500


@app.route('/api/payment/callback', methods=['POST'])
def payment_callback():
    """支付回调（兼容旧接口）- 需要验证签名"""
    try:
        data = request.json or request.form.to_dict()
        
        # 验证签名
        epay_config = get_epay_config()
        epay_key = epay_config['epay_key']
        
        if epay_key and not epay_verify_sign(data, epay_key):
            app.logger.warning(f'支付回调签名验证失败: {data}')
            return jsonify({'error': '签名验证失败'}), 403
        
        order_no = data.get('order_no') or data.get('out_trade_no')
        trade_no = data.get('trade_no')
        status = data.get('status') or data.get('trade_status')
        
        order = Order.query.filter_by(order_no=order_no).first()
        if not order:
            return jsonify({'error': '订单不存在'}), 404
        
        # 检查是否已处理
        if order.payment_status == 'paid':
            return jsonify({'success': True, 'message': '订单已处理'}), 200
        
        # 已取消的订单不能再被激活
        if order.payment_status == 'cancelled':
            app.logger.warning(f'已取消的订单收到支付回调，忽略: {order_no}')
            return jsonify({'error': '订单已取消，无法处理支付'}), 400
        
        if status in ('success', 'TRADE_SUCCESS'):
            order.payment_status = 'paid'
            order.payment_time = datetime.now()
            order.trade_no = trade_no
            
            # 创建订阅记录
            user = db.session.get(User, order.user_tg)
            if user:
                # 计算订阅开始和结束时间 - 在现有订阅基础上叠加
                now = datetime.now()
                start_date = now
                purchased_days = order.duration_days if order.duration_days else (order.duration_months * 30)
                
                # 检查该套餐是否为白名单套餐（仅按套餐白名单标记）
                _cb_plan_type = order.plan_type
                _cb_plan_name = order.plan_name
                _cb_is_wl = is_whitelist_plan_key(order.plan_type)
                
                if _cb_is_wl:
                    # 白名单套餐：永久有效
                    end_date = datetime(9999, 12, 31)
                    _cb_plan_type = 'whitelist'
                    _cb_plan_name = '白名单用户'
                else:
                    # 普通套餐：在现有订阅基础上叠加
                    if user.ex and user.ex > now:
                        end_date = user.ex + timedelta(days=purchased_days)
                    else:
                        end_date = now + timedelta(days=purchased_days)
                
                subscription = Subscription(
                    user_tg=user.tg,
                    plan_type=_cb_plan_type,
                    plan_name=_cb_plan_name,
                    duration_months=order.duration_months,
                    price=order.final_price,
                    start_date=start_date,
                    end_date=end_date,
                    status='active',
                    source='purchase'
                )
                
                db.session.add(subscription)
                
                # 更新用户信息
                user.ex = end_date
                if _cb_is_wl:
                    user.lv = 'a'  # 白名单套餐设为白名单等级
                elif user.lv not in ['a', 'b', 'c']:  # 普通用户不变，封禁用户保持封禁状态
                    user.lv = 'b'
                
                # 邀请返利：检查是否有邀请人，给邀请人返利
                process_invite_reward(user, purchased_days, source='支付回调')
                
                # 恢复Emby账号（封禁用户和黑名单禁用用户不自动恢复）
                if user.lv != 'c' and not user.ban_reason and user.embyid and emby_client.is_enabled():
                    if emby_client.enable_user(user.embyid):
                        app.logger.info(f'用户 {user.name} 支付成功，已恢复Emby账号')
            
            db.session.commit()
            app.logger.info(f'支付成功: 订单={order_no}, 交易号={trade_no}')
            
        return jsonify({'success': True}), 200
        
    except Exception as e:
        app.logger.error(f'支付回调处理失败: {e}')
        db.session.rollback()
        return jsonify({'error': str(e)}), 500


@app.route('/api/payment/query', methods=['GET'])
@login_required
def query_payment():
    """查询订单支付状态"""
    try:
        order_no = request.args.get('order_no')
        if not order_no:
            return jsonify({'error': '缺少订单号'}), 400
        
        order = Order.query.filter_by(order_no=order_no).first()
        if not order:
            return jsonify({'error': '订单不存在'}), 404
        
        # 如果本地状态是已支付，直接返回
        if order.payment_status == 'paid':
            # 获取用户信息，判断是否有 Emby 账号
            user = db.session.get(User, order.user_tg)
            has_emby_account = bool(user and user.embyid) if user else False
            return jsonify({
                'success': True,
                'paid': True,
                'order_no': order_no,
                'trade_no': order.trade_no,
                'has_emby_account': has_emby_account
            }), 200
        
        # 已取消的订单不再查询支付状态，直接返回未支付
        if order.payment_status == 'cancelled':
            return jsonify({
                'success': True,
                'paid': False,
                'order_no': order_no,
                'status': 'cancelled'
            }), 200
        
        # 只有 pending 状态的订单才去易支付查询
        # 动态获取易支付配置
        epay_config = get_epay_config()
        epay_url = epay_config['epay_url'].rstrip('/') if epay_config['epay_url'] else ''
        epay_pid = epay_config['epay_pid']
        epay_key = epay_config['epay_key']
        
        # 如果配置了易支付，可以主动查询易支付订单状态
        if epay_url and epay_pid and epay_key:
            try:
                params = {
                    'act': 'order',
                    'pid': epay_pid,
                    'out_trade_no': order_no
                }
                params['sign'] = epay_sign(params, epay_key)
                params['sign_type'] = 'MD5'
                
                response = get_proxied_session(epay_url).get(f'{epay_url}/api.php', params=params, timeout=10)
                result = response.json()
                
                if result.get('code') == 1 and result.get('status') == 1:
                    # 易支付显示已支付，更新本地状态
                    order.payment_status = 'paid'
                    order.payment_time = datetime.now()
                    order.trade_no = result.get('trade_no', '')
                    
                    # 创建订阅（与notify相同逻辑）
                    user = db.session.get(User, order.user_tg)
                    if user:
                        now = datetime.now()
                        start_date = now
                        purchased_days = order.duration_days if order.duration_days else (order.duration_months * 30)
                        
                        # 在现有订阅基础上叠加
                        if user.ex and user.ex > now:
                            end_date = user.ex + timedelta(days=purchased_days)
                        else:
                            end_date = now + timedelta(days=purchased_days)
                        
                        subscription = Subscription(
                            user_tg=user.tg,
                            plan_type=order.plan_type,
                            plan_name=order.plan_name,
                            duration_months=order.duration_months,
                            price=order.final_price,
                            start_date=start_date,
                            end_date=end_date,
                            status='active',
                            source='purchase'
                        )
                        db.session.add(subscription)
                        user.ex = end_date
                        if user.lv not in ['a', 'b', 'c']:  # 白名单/普通用户不变，封禁用户保持封禁状态
                            user.lv = 'b'
                        
                        # 恢复Emby账号（封禁用户和黑名单禁用用户不自动恢复）
                        if user.lv != 'c' and not user.ban_reason and user.embyid and emby_client.is_enabled():
                            if emby_client.enable_user(user.embyid):
                                app.logger.info(f'用户 {user.name} 轮询确认支付成功，已恢复Emby账号')
                        
                        # 邀请返利：检查是否有邀请人，给邀请人返利
                        process_invite_reward(user, purchased_days, source='轮询确认')
                    
                    db.session.commit()
                    
                    # 判断用户是否有 Emby 账号
                    has_emby_account = bool(user and user.embyid) if user else False
                    return jsonify({
                        'success': True,
                        'paid': True,
                        'order_no': order_no,
                        'trade_no': order.trade_no,
                        'has_emby_account': has_emby_account
                    }), 200
                    
            except Exception as e:
                app.logger.warning(f'查询易支付状态失败: {e}')
        
        return jsonify({
            'success': True,
            'paid': False,
            'order_no': order_no,
            'status': order.payment_status
        }), 200
        
    except Exception as e:
        app.logger.error(f'查询支付状态失败: {e}')
        return jsonify({'error': str(e)}), 500


