@app.route('/api/admin/test-telegram', methods=['POST'])
@admin_required
def test_telegram_connection():
    """测试 Telegram Bot 连接"""
    try:
        data = request.json
        bot_token = data.get('bot_token', '').strip()
        chat_id = data.get('chat_id', '').strip()
        
        app.logger.info(f'[测试连接] 开始测试 Telegram 连接 - chat_id={chat_id}')
        
        if not bot_token:
            app.logger.warning('[测试连接] Bot Token 为空')
            return jsonify({'success': False, 'error': 'Bot Token 不能为空'}), 400
        
        # 测试 Bot Token - 获取机器人信息
        test_url = f"https://api.telegram.org/bot{bot_token}/getMe"
        app.logger.info(f'[测试连接] 请求 getMe - URL: {test_url[:80]}..., 使用代理: {PROXY_SESSION.proxies if hasattr(PROXY_SESSION, "proxies") else "无"}')
        
        resp = PROXY_SESSION.get(test_url, timeout=10)
        app.logger.info(f'[测试连接] getMe 响应 - 状态码: {resp.status_code}')
        
        if resp.status_code != 200:
            app.logger.error(f'[测试连接] Bot Token 无效 - 状态码: {resp.status_code}')
            return jsonify({
                'success': False,
                'error': 'Bot Token 无效'
            }), 400
        
        bot_info = resp.json()
        app.logger.info(f'[测试连接] Bot 信息: {json.dumps(bot_info, ensure_ascii=False)[:200]}')
        
        if not bot_info.get('ok'):
            app.logger.error(f'[测试连接] Bot Token 验证失败: {bot_info.get("description")}')
            return jsonify({
                'success': False,
                'error': bot_info.get('description', 'Bot Token 验证失败')
            }), 400
        
        bot_name = bot_info.get('result', {}).get('username', '未知')
        app.logger.info(f'[测试连接] Bot 验证成功: @{bot_name}')
        
        # 检查 Webhook 状态
        webhook_url = f"https://api.telegram.org/bot{bot_token}/getWebhookInfo"
        app.logger.info(f'[测试连接] 获取 Webhook 信息...')
        
        webhook_resp = PROXY_SESSION.get(webhook_url, timeout=10)
        webhook_info = {}
        if webhook_resp.status_code == 200:
            webhook_data = webhook_resp.json()
            if webhook_data.get('ok'):
                webhook_info = webhook_data.get('result', {})
                app.logger.info(f'[测试连接] Webhook 信息: URL={webhook_info.get("url", "未设置")}, pending_update_count={webhook_info.get("pending_update_count", 0)}, last_error={webhook_info.get("last_error_message", "无")}')
        
        # 如果提供了 chat_id，尝试发送测试消息
        if chat_id:
            send_url = f"https://api.telegram.org/bot{bot_token}/sendMessage"
            app.logger.info(f'[测试连接] 发送测试消息到 chat_id={chat_id}')
            
            send_resp = PROXY_SESSION.post(send_url, json={
                'chat_id': chat_id,
                'text': '✅ 测试消息 - Emby管理系统连接成功！',
                'parse_mode': 'HTML'
            }, timeout=10)
            
            app.logger.info(f'[测试连接] 发送消息响应 - 状态码: {send_resp.status_code}')
            
            if send_resp.status_code == 200 and send_resp.json().get('ok'):
                message = f'连接成功！Bot: @{bot_name}，已发送测试消息到群组'
                
                # 注册命令菜单
                register_telegram_commands_with_token(bot_token)
                
                # 添加 Webhook 状态提示
                if not webhook_info.get('url'):
                    message += '\n\n⚠️ 提示：Webhook 未设置，Bot 命令功能将无法使用。请点击"设置 Webhook"按钮进行配置。'
                    app.logger.warning('[测试连接] Webhook 未设置，Bot 命令将无法工作')
                else:
                    app.logger.info(f'[测试连接] Webhook 已设置: {webhook_info.get("url")}')
                
                app.logger.info('[测试连接] 测试完成 - 成功')
                return jsonify({
                    'success': True,
                    'message': message,
                    'webhook_info': webhook_info
                }), 200
            else:
                error_desc = send_resp.json().get('description', '发送失败')
                app.logger.error(f'[测试连接] 发送消息失败: {error_desc}')
                return jsonify({
                    'success': False,
                    'error': f'Bot 有效但发送消息失败: {error_desc}'
                }), 400
        
        message = f'Bot Token 有效！Bot: @{bot_name}'
        if not webhook_info.get('url'):
            message += '\n\n⚠️ 提示：Webhook 未设置，Bot 命令功能将无法使用'
            app.logger.warning('[测试连接] Webhook 未设置')
        
        app.logger.info('[测试连接] 测试完成 - 成功（未测试消息发送）')
        return jsonify({
            'success': True,
            'message': message,
            'webhook_info': webhook_info
        }), 200
            
    except requests.exceptions.Timeout:
        app.logger.error('[测试连接] 连接超时')
        return jsonify({'success': False, 'error': '连接超时，请检查网络和代理设置'}), 400
    except requests.exceptions.ConnectionError as e:
        app.logger.error(f'[测试连接] 无法连接到 Telegram 服务器: {e}')
        return jsonify({'success': False, 'error': f'无法连接到 Telegram 服务器，请检查网络和代理设置: {str(e)}'}), 400
    except Exception as e:
        app.logger.error(f'[测试连接] 测试失败: {e}', exc_info=True)
        return jsonify({'success': False, 'error': str(e)}), 500


@app.route('/api/admin/register-telegram-commands', methods=['POST'])
@admin_required
def api_register_telegram_commands():
    """手动注册 Telegram Bot 命令菜单"""
    try:
        data = request.json or {}
        bot_token = data.get('bot_token', '').strip() or TELEGRAM_BOT_TOKEN
        
        if not bot_token:
            return jsonify({
                'success': False,
                'error': '未配置 Telegram Bot Token'
            }), 400
        
        app.logger.info('[命令注册API] 开始手动注册命令')
        result = register_telegram_commands_with_token(bot_token)
        
        if result:
            # 获取当前注册的命令列表
            try:
                verify_url = f"https://api.telegram.org/bot{bot_token}/getMyCommands"
                verify_resp = PROXY_SESSION.get(verify_url, timeout=10)
                verify_data = verify_resp.json()
                commands = verify_data.get('result', []) if verify_data.get('ok') else []
            except:
                commands = []
            
            return jsonify({
                'success': True,
                'message': '命令菜单注册成功！请在 Telegram 中输入 / 查看命令列表',
                'commands': commands
            })
        else:
            return jsonify({
                'success': False,
                'error': '命令注册失败，请查看服务器日志'
            }), 500
            
    except Exception as e:
        app.logger.error(f'[命令注册API] 失败: {e}', exc_info=True)
        return jsonify({'success': False, 'error': str(e)}), 500


# ==================== 套餐配置 API ====================
@app.route('/api/admin/plans-config', methods=['GET'])
@admin_required
def get_plans_config():
    """获取套餐配置（管理员）"""
    plans = load_plans_config()
    return jsonify({
        'success': True,
        'plans': plans
    }), 200


@app.route('/api/admin/plans-config', methods=['POST'])
@admin_required
def save_plans_config_api():
    """保存套餐配置（管理员）"""
    try:
        data = request.get_json(silent=True) or {}
        plans = data.get('plans', [])
        if not isinstance(plans, list):
            return jsonify({
                'success': False,
                'error': '套餐数据格式错误'
            }), 400

        existing_plans = load_plans_config()
        existing_by_key = {}
        for existing_plan in existing_plans:
            if not isinstance(existing_plan, dict):
                continue
            for alias in collect_plan_aliases(existing_plan):
                if alias and alias not in existing_by_key:
                    existing_by_key[alias] = existing_plan

        def _float_or_none(value):
            if value in [None, '']:
                return None
            try:
                return float(value)
            except (TypeError, ValueError):
                return None
        
        # 验证套餐数据
        validated_plans = []
        for plan in plans:
            if not isinstance(plan, dict):
                continue
            if not plan.get('name'):
                continue
                
            # 计算 duration_days：优先使用前端传来的值，否则从 duration（月）计算
            try:
                duration_months = int(plan.get('duration', 1) or 1)
            except (TypeError, ValueError):
                duration_months = 1
            if duration_months <= 0:
                duration_months = 1
            try:
                duration_days = int(plan.get('duration_days', 0) or 0)
            except (TypeError, ValueError):
                duration_days = 0
            if duration_days <= 0:
                duration_days = duration_months * 30
            is_whitelist_plan = bool(plan.get('is_whitelist', False))
            if is_whitelist_plan:
                duration_days = WHITELIST_INTERNAL_DAYS
                duration_months = 1

            incoming_id = coerce_plan_key(plan.get('id'))
            incoming_type = coerce_plan_key(plan.get('type'))
            existing_plan = existing_by_key.get(incoming_id) or existing_by_key.get(incoming_type)
            current_plan_id = incoming_id or (coerce_plan_key(existing_plan.get('id')) if existing_plan else '')
            legacy_ids = []
            if existing_plan:
                legacy_ids.extend(_unique_plan_keys(existing_plan.get('legacy_ids') or []))
                for alias in [
                    existing_plan.get('id'),
                    existing_plan.get('type'),
                    existing_plan.get('name'),
                ]:
                    alias = coerce_plan_key(alias)
                    if alias and alias != current_plan_id and alias not in legacy_ids:
                        legacy_ids.append(alias)

            for alias in [incoming_id, incoming_type]:
                if alias and alias not in legacy_ids:
                    legacy_ids.append(alias)
            
            validated_plan = {
                'id': current_plan_id,
                'name': str(plan.get('name', '')).strip(),
                'icon': str(plan.get('icon', '')).strip() if plan.get('icon') else None,
                'description': str(plan.get('description', '')).strip() if plan.get('description') else None,
                'duration': duration_months,
                'duration_days': duration_days,
                'price': _float_or_none(plan.get('price')) or 0.0,
                'original_price': _float_or_none(plan.get('original_price')),
                'features': plan.get('features', []) if isinstance(plan.get('features'), list) else [],
                'popular': bool(plan.get('popular', False)),
                # 白名单套餐标记（勾选后该套餐用户视为白名单用户）
                'is_whitelist': is_whitelist_plan,
                # 多周期价格（互斥：一次性和月付/季付/年付只能设一种）
                'price_once': _float_or_none(plan.get('price_once')),
                'price_1m': _float_or_none(plan.get('price_1m')),
                'price_3m': _float_or_none(plan.get('price_3m')),
                'price_6m': _float_or_none(plan.get('price_6m')),
                'price_12m': _float_or_none(plan.get('price_12m')),
                # 订阅权益
                'benefits': plan.get('benefits', []) if isinstance(plan.get('benefits'), list) else [],
            }
            preserved_type = incoming_type or (coerce_plan_key(existing_plan.get('type')) if existing_plan else '')
            if preserved_type:
                validated_plan['type'] = preserved_type
            if legacy_ids:
                validated_plan['legacy_ids'] = legacy_ids
            
            # 互斥校验：一次性价格和周期价格不能同时存在
            once_price = validated_plan.get('price_once') or 0
            monthly_price = validated_plan.get('price_1m') or 0
            quarter_price = validated_plan.get('price_3m') or 0
            halfyear_price = validated_plan.get('price_6m') or 0
            yearly_price = validated_plan.get('price_12m') or 0
            legacy_price = validated_plan.get('price') or 0

            if is_whitelist_plan:
                whitelist_once_price = resolve_whitelist_once_price(validated_plan, plan_key=current_plan_id or validated_plan['name'])
                validated_plan['price_once'] = whitelist_once_price or None
                validated_plan['price_1m'] = None
                validated_plan['price_3m'] = None
                validated_plan['price_6m'] = None
                validated_plan['price_12m'] = None
                validated_plan['price'] = 0
            else:
                if monthly_price <= 0 and legacy_price > 0:
                    monthly_price = legacy_price

                has_periodic_price = any(price > 0 for price in [monthly_price, quarter_price, halfyear_price, yearly_price, legacy_price])
                if once_price > 0 and has_periodic_price:
                    validated_plan['price_1m'] = None
                    validated_plan['price_3m'] = None
                    validated_plan['price_6m'] = None
                    validated_plan['price_12m'] = None
                    validated_plan['price'] = 0
                    app.logger.warning(f'濂楅 {validated_plan["name"]} 鍚屾椂璁剧疆浜嗕竴娆℃€у拰鍛ㄦ湡浠锋牸锛屽凡鑷姩娓呯┖鍛ㄦ湡浠锋牸')
                else:
                    validated_plan['price_once'] = once_price or None
                    validated_plan['price_1m'] = monthly_price or None
                    validated_plan['price_3m'] = quarter_price or None
                    validated_plan['price_6m'] = halfyear_price or None
                    validated_plan['price_12m'] = yearly_price or None
                    validated_plan['price'] = monthly_price or 0

            validated_plans.append(validated_plan)
            continue
        
        if not validated_plans:
            return jsonify({
                'success': False,
                'error': '请至少配置一个有效套餐'
            }), 400
        
        # 保存配置
        normalized_response_plans = normalize_plans_config(validated_plans)

        if save_plans_config(normalized_response_plans):
            clear_db_config_cache(CONFIG_KEY_PLANS)
            app.logger.info(f'套餐配置已更新，共 {len(normalized_response_plans)} 个套餐')
            
            return jsonify({
                'success': True,
                'message': f'配置保存成功，共 {len(normalized_response_plans)} 个套餐',
                'plans': normalized_response_plans
            }), 200
        else:
            return jsonify({
                'success': False,
                'error': '保存配置失败'
            }), 500
            
    except Exception as e:
        app.logger.error(f'保存套餐配置失败: {e}')
        return jsonify({'error': str(e)}), 500


