# ==================== Telegram 绑定 API ====================
# 存储临时绑定码 {bind_code: {'user_tg': xxx, 'created_at': datetime, 'expires_at': datetime}}
TELEGRAM_BIND_CODES = {}

# 存储签到验证码 {telegram_user_id: {'code': '1234', 'created_at': datetime, 'expires_at': datetime}}
TELEGRAM_CHECKIN_CODES = {}

# Telegram Webhook 消息去重缓存（防止重复推送导致重复回复）
# 用 message_id+chat_id 做去重（同一消息可能以不同 update_id 推送多次）
_PROCESSED_MSG_KEYS = set()
_PROCESSED_MSG_KEYS_MAX = 500
_PROCESSED_MSG_KEYS_LOCK = threading.Lock()

# 存储忘记密码验证码 {username: {'code': '1234', 'telegram_id': xxx, 'created_at': datetime, 'expires_at': datetime}}
PASSWORD_RESET_CODES = {}

# 存储邮箱验证码 {email_or_key: {'code': '1234', 'user_tg': xxx, 'created_at': datetime, 'expires_at': datetime}}
EMAIL_VERIFY_CODES = {}


def cleanup_expired_bind_codes():
    """清理过期的绑定码、邮箱验证码和密码重置码"""
    now = datetime.now()
    expired = [code for code, data in TELEGRAM_BIND_CODES.items() 
               if data.get('expires_at') and data['expires_at'] < now]
    for code in expired:
        del TELEGRAM_BIND_CODES[code]
    
    # 同时清理过期的邮箱验证码
    expired_email = [key for key, data in EMAIL_VERIFY_CODES.items()
                     if data.get('expires_at') and data['expires_at'] < now]
    for key in expired_email:
        del EMAIL_VERIFY_CODES[key]
    
    # 清理过期的密码重置验证码
    expired_reset = [key for key, data in PASSWORD_RESET_CODES.items()
                     if data.get('expires_at') and data['expires_at'] < now]
    for key in expired_reset:
        del PASSWORD_RESET_CODES[key]


