@app.route('/api/admin/lines', methods=['POST'])
@admin_required
def admin_add_line():
    """管理员添加线路"""
    try:
        data = request.get_json(silent=True) or {}
        
        name = data.get('name', '').strip()
        server_url = data.get('server_url', '').strip()
        port = data.get('port', 8096)
        is_https = data.get('is_https', False)
        description = data.get('description', '').strip()
        sort_order = data.get('sort_order', 0)
        
        # 处理允许的套餐类型（多选）
        allowed_plan_types_raw = data.get('allowed_plan_types', [])
        allowed_plan_types = ','.join(normalize_plan_match_keys(allowed_plan_types_raw))
        
        # 兼容旧的 access_level 参数
        access_level = data.get('access_level', 'subscriber')
        
        if not name:
            return jsonify({'success': False, 'error': '线路名称不能为空'}), 400
        server_url, port, is_https = ServerLine.resolve_url(server_url, port, is_https)
        if not server_url:
            return jsonify({'success': False, 'error': '服务器地址不能为空'}), 400
        
        line = ServerLine(
            name=name,
            server_url=server_url,
            port=port,
            is_https=is_https,
            description=description,
            access_level=access_level,
            allowed_plan_types=allowed_plan_types,
            sort_order=sort_order,
            is_active=True
        )
        
        db.session.add(line)
        db.session.commit()
        
        app.logger.info(f'管理员添加线路: {name}')
        
        return jsonify({
            'success': True,
            'message': '线路添加成功',
            'line': line.to_dict(include_sensitive=True)
        }), 201
    except Exception as e:
        db.session.rollback()
        app.logger.error(f'添加线路失败: {e}')
        return jsonify({'error': str(e)}), 500


@app.route('/api/admin/lines/<int:line_id>', methods=['PUT'])
@admin_required
def admin_update_line(line_id):
    """管理员更新线路"""
    try:
        line = db.session.get(ServerLine, line_id)
        if not line:
            return jsonify({'success': False, 'error': '线路不存在'}), 404
        
        data = request.get_json(silent=True) or {}
        
        if 'name' in data:
            line.name = data['name'].strip()
        if any(key in data for key in ('server_url', 'port', 'is_https')):
            next_server_url = data.get('server_url', line.server_url)
            next_port = data.get('port', line.port)
            next_is_https = data.get('is_https', line.is_https)
            line.server_url, line.port, line.is_https = ServerLine.resolve_url(
                next_server_url,
                next_port,
                next_is_https
            )
        if 'description' in data:
            line.description = data['description'].strip()
        if 'access_level' in data:
            line.access_level = data.get('access_level', 'subscriber')
        if 'allowed_plan_types' in data:
            apt = data['allowed_plan_types']
            line.allowed_plan_types = ','.join(normalize_plan_match_keys(apt))
        if 'sort_order' in data:
            line.sort_order = data['sort_order']
        if 'is_active' in data:
            line.is_active = data['is_active']
        
        db.session.commit()
        
        app.logger.info(f'管理员更新线路: {line.name}')
        
        return jsonify({
            'success': True,
            'message': '线路更新成功',
            'line': line.to_dict(include_sensitive=True)
        }), 200
    except Exception as e:
        db.session.rollback()
        app.logger.error(f'更新线路失败: {e}')
        return jsonify({'error': str(e)}), 500


