@app.route('/api/admin/invite-stats', methods=['GET'])
@admin_required
def admin_get_invite_stats():
    """管理员获取邀请统计"""
    try:
        from sqlalchemy import func
        
        # 总邀请数
        total_invites = InviteRecord.query.count()
        
        # 成功邀请数（已领取奖励）
        successful_invites = InviteRecord.query.filter_by(reward_claimed=True).count()
        
        # 总奖励天数
        total_rewards = db.session.query(
            func.sum(InviteRecord.reward_value)
        ).filter(InviteRecord.reward_claimed == True).scalar() or 0
        
        # 邀请记录
        records = InviteRecord.query.order_by(
            InviteRecord.created_at.desc()
        ).limit(100).all()
        
        # 邀请排行榜
        rankings = db.session.query(
            InviteRecord.inviter_tg,
            func.count(InviteRecord.id).label('count')
        ).group_by(InviteRecord.inviter_tg).order_by(
            func.count(InviteRecord.id).desc()
        ).limit(10).all()
        
        ranking_list = []
        for inviter_tg, count in rankings:
            user = User.query.filter_by(tg=inviter_tg).first()
            ranking_list.append({
                'tg_id': inviter_tg,
                'name': (user.emby_name or user.name) if user else f'用户{inviter_tg}',
                'count': count
            })
        
        # 近30天趋势
        from datetime import datetime, timedelta
        thirty_days_ago = datetime.now() - timedelta(days=30)
        daily_stats = db.session.query(
            func.date(InviteRecord.created_at).label('date'),
            func.count(InviteRecord.id).label('count')
        ).filter(
            InviteRecord.created_at >= thirty_days_ago
        ).group_by(
            func.date(InviteRecord.created_at)
        ).order_by('date').all()
        
        trend = [{'date': str(date), 'count': count} for date, count in daily_stats]
        
        return jsonify({
            'success': True,
            'stats': {
                'total': total_invites,
                'successful': successful_invites,
                'total_rewards': float(total_rewards)
            },
            'records': [record.to_dict() for record in records],
            'rankings': ranking_list,
            'trend': trend
        }), 200
    except Exception as e:
        app.logger.error(f'获取邀请统计失败: {e}')
        return jsonify({'success': False, 'error': str(e)}), 500


@app.route('/api/admin/users', methods=['GET'])
@admin_required
def admin_get_users():
    """管理员获取用户列表（支持分页）"""
    try:
        from sqlalchemy import func, or_, cast, String
        role = request.args.get('role', '')
        search = request.args.get('search', '').strip()
        page = request.args.get('page', 1, type=int)
        per_page = request.args.get('per_page', 20, type=int)
        
        # 构建查询
        query = User.query
        
        # 搜索过滤
        if search:
            query = query.filter(
                or_(
                    User.name.ilike(f'%{search}%'),
                    User.emby_name.ilike(f'%{search}%'),
                    cast(User.tg, String).ilike(f'%{search}%'),
                    cast(User.telegram_id, String).ilike(f'%{search}%'),
                    User.email.ilike(f'%{search}%')
                )
            )
        
        # 统计数据（在筛选前）
        total_users = User.query.count()
        all_users_for_stats = User.query.all()
        admin_users = len([u for u in all_users_for_stats if u.is_admin])
        
        # 获取订阅用户数
        subscribed_users = db.session.query(
            func.count(func.distinct(Subscription.user_tg))
        ).filter(Subscription.status == 'active').scalar() or 0
        
        # 排序（MySQL 兼容：使用 CASE WHEN 处理 NULL 值排在最后）
        query = query.order_by(
            db.case((User.cr.is_(None), 1), else_=0),
            User.cr.desc()
        )
        
        # 获取所有数据用于角色筛选（因为 is_admin 是计算属性）
        all_filtered_users = query.all()
        
        # 根据角色筛选
        if role == 'admin':
            all_filtered_users = [u for u in all_filtered_users if u.is_admin]
        elif role == 'user':
            all_filtered_users = [u for u in all_filtered_users if not u.is_admin]
        
        # 根据用户状态筛选（白名单通过订阅记录判断）
        now = datetime.now()  # 使用不带时区的时间，与数据库一致
        status_filter = request.args.get('status', '').strip()
        if status_filter == 'whitelist':
            # 查询所有白名单订阅的user_tg
            _wl_tgs = set(s.user_tg for s in Subscription.query.filter_by(plan_type='whitelist', status='active').all())
            all_filtered_users = [u for u in all_filtered_users if u.tg in _wl_tgs or u.lv == 'a']
        elif status_filter == 'subscribed':
            _wl_tgs2 = set(s.user_tg for s in Subscription.query.filter_by(plan_type='whitelist', status='active').all())
            all_filtered_users = [u for u in all_filtered_users if u.tg not in _wl_tgs2 and u.lv != 'a' and u.ex and u.ex > now]
        elif status_filter == 'normal':
            _wl_tgs3 = set(s.user_tg for s in Subscription.query.filter_by(plan_type='whitelist', status='active').all())
            all_filtered_users = [u for u in all_filtered_users if u.tg not in _wl_tgs3 and u.lv != 'a' and u.lv != 'c' and (not u.ex or u.ex <= now)]
        elif status_filter == 'banned':
            all_filtered_users = [u for u in all_filtered_users if u.lv == 'c' or u.ban_reason]
        elif status_filter == 'emby_banned':
            all_filtered_users = [u for u in all_filtered_users if u.ban_reason and u.lv != 'c']
        
        # 手动分页
        total_filtered = len(all_filtered_users)
        total_pages = (total_filtered + per_page - 1) // per_page
        start_idx = (page - 1) * per_page
        end_idx = start_idx + per_page
        paginated_users = all_filtered_users[start_idx:end_idx]
        
        # 获取货币名称配置
        checkin_config = get_db_config('checkin', {})
        coin_name = checkin_config.get('coin_name', '积分')
        
        # 用户数据
        user_list = []
        # 预加载分页用户的订阅记录
        _page_tgs = [u.tg for u in paginated_users]
        _page_subs = Subscription.query.filter(
            Subscription.user_tg.in_(_page_tgs),
            Subscription.status == 'active'
        ).order_by(Subscription.end_date.desc(), Subscription.created_at.desc()).all() if _page_tgs else []
        _page_sub_map = {}
        for _ps in _page_subs:
            if _ps.user_tg not in _page_sub_map:
                _page_sub_map[_ps.user_tg] = _ps
        
        for user in paginated_users:
            # 订阅状态逻辑：
            # 1. 白名单套餐用户永远视为已订阅
            # 2. 有有效到期时间的用户视为已订阅
            # 3. 其他用户为未订阅
            subscription_status = 'inactive'
            subscription_end = None
            subscription_plan_type = None
            
            _u_sub = _page_sub_map.get(user.tg)
            _u_sub_plan = resolve_plan_config(_u_sub.plan_type) if _u_sub else None
            _u_is_wl = bool((_u_sub_plan and _u_sub_plan.get('is_whitelist')) or (_u_sub and _u_sub.plan_type == 'whitelist') or user.lv == 'a')
            
            if _u_is_wl:
                subscription_status = 'active'
                subscription_end = None  # 白名单永久有效
                subscription_plan_type = 'whitelist'
            elif user.ex and user.ex > now:
                subscription_status = 'active'
                subscription_end = user.ex.isoformat()
                if _u_sub:
                    subscription_plan_type = _u_sub_plan.get('id') if _u_sub_plan else _u_sub.plan_type
            elif user.ex:
                subscription_end = user.ex.isoformat()  # 已过期也返回到期时间

            user_list.append({
                'id': user.tg,  # 使用 tg 作为用户 ID
                'name': user.name,
                'emby_name': user.emby_name,  # Emby用户名（独立于网站用户名）
                'telegram_id': user.telegram_id,  # 只有绑定了才有值
                'email': user.email,  # 绑定邮箱
                'is_admin': user.is_admin,
                'level': user.lv,
                'subscription_status': subscription_status,
                'subscription_end': subscription_end,
                'subscription_plan_type': subscription_plan_type,
                'coins': user.coins or 0,
                'created_at': user.cr.isoformat() if user.cr else None,
                'ban_reason': user.ban_reason,  # 黑名单封禁原因（lv未改但Emby被禁用）
                'ban_time': user.ban_time.isoformat() if user.ban_time else None
            })
        
        return jsonify({
            'success': True,
            'users': user_list,
            'pagination': {
                'page': page,
                'per_page': per_page,
                'total': total_filtered,
                'total_pages': total_pages,
                'has_prev': page > 1,
                'has_next': page < total_pages
            },
            'stats': {
                'total': total_users,
                'admins': admin_users,
                'subscribed': subscribed_users,
                'coin_name': coin_name
            }
        }), 200
    except Exception as e:
        app.logger.error(f'获取用户列表失败: {e}')
        return jsonify({'success': False, 'error': str(e)}), 500


@app.route('/api/admin/export/<string:export_type>', methods=['GET'])
@admin_required
def admin_export_data(export_type):
    """管理员数据导出API - 支持用户列表、订单、订阅历史导出为CSV"""
    import csv
    import io
    from urllib.parse import quote
    
    try:
        output = io.StringIO()
        output.write('\ufeff')  # UTF-8 BOM
        now = datetime.now()
        
        if export_type == 'users':
            writer = csv.writer(output)
            writer.writerow(['用户ID', '网站用户名', 'Emby用户名', '邮箱', 'Telegram ID', 
                           '等级', '订阅状态', '到期时间', '积分', '注册时间'])
            
            users = User.query.order_by(User.cr.desc()).all()
            # 预加载白名单订阅
            _exp_wl_tgs = set(s.user_tg for s in Subscription.query.filter_by(plan_type='whitelist', status='active').all())
            level_names = {'a': '白名单(旧)', 'b': '普通用户', 'c': '已禁用', 'd': '无账号'}
            for u in users:
                is_wl = u.tg in _exp_wl_tgs or u.lv == 'a'
                if is_wl:
                    status = '白名单'
                    lv_name = '白名单'
                elif u.lv == 'c':
                    status = '已禁用'
                    lv_name = level_names.get(u.lv, u.lv or 'd')
                elif u.ex and u.ex > now:
                    status = '已订阅'
                    lv_name = level_names.get(u.lv, u.lv or 'd')
                else:
                    status = '未订阅'
                    lv_name = level_names.get(u.lv, u.lv or 'd')
                writer.writerow([
                    u.tg, u.name or '', u.emby_name or '', u.email or '', u.telegram_id or '',
                    lv_name, status,
                    u.ex.strftime('%Y-%m-%d %H:%M') if u.ex else '',
                    u.coins or 0,
                    u.cr.strftime('%Y-%m-%d %H:%M') if u.cr else ''
                ])
            cn_filename = f'用户列表_{now.strftime("%Y%m%d_%H%M")}.csv'
            ascii_filename = f'users_{now.strftime("%Y%m%d_%H%M")}.csv'
        
        elif export_type == 'orders':
            writer = csv.writer(output)
            writer.writerow(['订单号', '用户名', '套餐名称', '金额', '时长(天)', '状态', 
                           '支付方式', '创建时间', '支付时间'])
            
            orders = Order.query.order_by(Order.created_at.desc()).all()
            status_names = {'pending': '待支付', 'paid': '已支付', 'cancelled': '已取消', 'expired': '已过期', 'failed': '失败', 'refunded': '已退款'}
            for o in orders:
                # 获取用户名
                user = db.session.get(User, o.user_tg)
                user_name = (user.name if user else f'用户{o.user_tg}')
                days = o.duration_days if o.duration_days else (o.duration_months * 30 if o.duration_months else '')
                writer.writerow([
                    o.order_no or '', user_name,
                    o.plan_name or '', f'{o.final_price:.2f}' if o.final_price else '0.00',
                    days,
                    status_names.get(o.payment_status, o.payment_status or ''),
                    o.payment_method or '',
                    o.created_at.strftime('%Y-%m-%d %H:%M') if o.created_at else '',
                    o.payment_time.strftime('%Y-%m-%d %H:%M') if o.payment_time else ''
                ])
            cn_filename = f'订单列表_{now.strftime("%Y%m%d_%H%M")}.csv'
            ascii_filename = f'orders_{now.strftime("%Y%m%d_%H%M")}.csv'
        
        elif export_type == 'subscriptions':
            writer = csv.writer(output)
            writer.writerow(['用户名', '套餐名称', '开始时间', '结束时间', '时长(月)', '价格', '状态', '来源'])
            
            subs = Subscription.query.order_by(Subscription.created_at.desc()).all()
            status_names = {'active': '生效中', 'expired': '已过期', 'cancelled': '已取消'}
            source_names = {'purchase': '购买', 'gift': '管理员赠送', 'manual': '手动设置', 'redeem': '兑换码'}
            for s in subs:
                user = db.session.get(User, s.user_tg)
                user_name = (user.name if user else f'用户{s.user_tg}')
                writer.writerow([
                    user_name, s.plan_name or '',
                    s.start_date.strftime('%Y-%m-%d') if s.start_date else '',
                    s.end_date.strftime('%Y-%m-%d') if s.end_date else '',
                    s.duration_months or '',
                    f'{s.price:.2f}' if s.price else '0.00',
                    status_names.get(s.status, s.status or ''),
                    source_names.get(s.source, s.source or 'purchase')
                ])
            cn_filename = f'订阅记录_{now.strftime("%Y%m%d_%H%M")}.csv'
            ascii_filename = f'subscriptions_{now.strftime("%Y%m%d_%H%M")}.csv'
        
        else:
            return jsonify({'success': False, 'error': '不支持的导出类型'}), 400
        
        # 记录审计日志
        log_admin_audit('export_data', detail=f'导出{export_type}数据')
        
        csv_data = output.getvalue()
        output.close()
        
        # 文件名处理：使用 RFC 5987 编码中文文件名，避免 Gunicorn WSGI Latin-1 编码错误
        # filename= 提供 ASCII 后备名，filename*= 提供 UTF-8 编码的中文名（现代浏览器优先使用）
        encoded_cn_filename = quote(cn_filename)
        content_disposition = f"attachment; filename=\"{ascii_filename}\"; filename*=UTF-8''{encoded_cn_filename}"
        
        response = Response(
            csv_data,
            mimetype='text/csv; charset=utf-8',
            headers={
                'Content-Disposition': content_disposition,
                'X-Skip-Gzip': '1',  # 标记跳过 after_request 的 gzip 压缩
            }
        )
        return response
        
    except Exception as e:
        app.logger.error(f'数据导出失败: {e}', exc_info=True)
        return jsonify({'success': False, 'error': str(e)}), 500


@app.route('/api/admin/audit-logs', methods=['GET'])
@admin_required
def admin_get_audit_logs():
    """获取管理员审计日志"""
    try:
        page = request.args.get('page', 1, type=int)
        per_page = request.args.get('per_page', 20, type=int)
        action_type = request.args.get('action_type', '')
        admin_username = request.args.get('admin_username', '')
        keyword = request.args.get('keyword', '')
        
        per_page = min(per_page, 100)
        
        query = AdminAuditLog.query
        
        if action_type:
            query = query.filter(AdminAuditLog.action_type == action_type)
        if admin_username:
            query = query.filter(AdminAuditLog.admin_username == admin_username)
        if keyword:
            query = query.filter(AdminAuditLog.action_detail.like(f'%{keyword}%'))
        
        query = query.order_by(AdminAuditLog.created_at.desc())
        pagination = query.paginate(page=page, per_page=per_page, error_out=False)
        
        # 获取所有管理员用户名（用于筛选）
        admin_names = db.session.query(AdminAuditLog.admin_username).distinct().all()
        admin_names = sorted(set(n[0] for n in admin_names if n[0]))
        
        # 获取所有操作类型（用于筛选）
        action_types = db.session.query(AdminAuditLog.action_type).distinct().all()
        action_types = sorted(set(t[0] for t in action_types if t[0]))
        
        return jsonify({
            'success': True,
            'logs': [log.to_dict() for log in pagination.items],
            'total': pagination.total,
            'page': page,
            'per_page': per_page,
            'total_pages': pagination.pages,
            'admin_names': admin_names,
            'action_types': action_types
        })
        
    except Exception as e:
        app.logger.error(f'获取审计日志失败: {e}', exc_info=True)
        return jsonify({'success': False, 'error': str(e)}), 500


@app.route('/api/admin/audit-logs/cleanup', methods=['POST'])
@admin_required
def admin_cleanup_audit_logs():
    """清理旧审计日志（保留最近N天）"""
    try:
        # 仅超级管理员可执行
        admin = getattr(g, 'current_admin', None)
        if admin and not admin.is_super:
            return jsonify({'success': False, 'error': '仅超级管理员可执行此操作'}), 403
        
        data = request.get_json(silent=True) or {}
        keep_days = data.get('keep_days', 90)
        keep_days = max(7, min(keep_days, 365))  # 最少保留7天，最多365天
        
        cutoff = datetime.now() - timedelta(days=keep_days)
        deleted = AdminAuditLog.query.filter(AdminAuditLog.created_at < cutoff).delete()
        db.session.commit()
        
        log_admin_audit('config_change', detail=f'清理审计日志，保留{keep_days}天，删除{deleted}条')
        
        return jsonify({
            'success': True,
            'deleted': deleted,
            'message': f'已清理{deleted}条审计日志（保留最近{keep_days}天）'
        })
        
    except Exception as e:
        db.session.rollback()
        app.logger.error(f'清理审计日志失败: {e}', exc_info=True)
        return jsonify({'success': False, 'error': str(e)}), 500


@app.route('/api/admin/users/<int:user_id>/toggle-role', methods=['POST'])
@admin_required
def admin_toggle_user_role(user_id):
    """设置用户等级（a=白名单, b=普通, c=禁用）
    注意：管理员身份是通过环境变量 ADMIN_USERNAMES 配置的，无法通过 API 修改
    此 API 只能设置用户等级
    
    当设置为 c（禁用）时，会自动：
    1. 备份当前等级和过期时间
    2. 禁用 Emby 账号
    3. 暂停用户订阅
    """
    try:
        user = db.session.get(User, user_id)
        if not user:
            return jsonify({'success': False, 'error': '用户不存在'}), 404
        
        data = request.get_json(silent=True) or {}
        new_level = data.get('level')
        
        level_names = {'a': '白名单', 'b': '普通用户', 'c': '已禁用', 'd': '无账号'}
        
        # 如果指定了新等级，直接设置
        if new_level and new_level in ['a', 'b', 'c', 'd']:
            old_level = user.lv or 'd'
            
            emby_disabled = False
            subscription_suspended = False
            
            # 如果是封禁操作（设置为 c），备份原状态并禁用 Emby
            if new_level == 'c' and old_level != 'c':
                # 备份封禁前的等级和过期时间
                user.ban_prev_lv = old_level
                user.ban_prev_ex = user.ex
                user.ban_time = datetime.now()
                user.ban_reason = data.get('reason', '管理员手动禁用')
                
                # 禁用 Emby 账号
                if user.embyid and emby_client.is_enabled():
                    emby_disabled = emby_client.disable_user(user.embyid)
                
                # 暂停用户的活跃订阅（设为 suspended 状态）
                active_subscriptions = Subscription.query.filter_by(
                    user_tg=user.tg, 
                    status='active'
                ).all()
                for sub in active_subscriptions:
                    sub.status = 'suspended'
                    subscription_suspended = True
            
            user.lv = new_level
            db.session.commit()
            
            message = f'用户等级已更新为 {level_names.get(user.lv, user.lv)}'
            if emby_disabled:
                message += '，Emby 账号已禁用'
            if subscription_suspended:
                message += '，订阅已暂停'
            
            app.logger.info(f'设置用户等级: {user.name}, {old_level} -> {new_level}, Emby禁用={emby_disabled}, 订阅暂停={subscription_suspended}')
            
            # 记录等级变更日志
            if new_level == 'c':
                log_user_activity(UserActivityLog.ACTION_ACCOUNT_BANNED, user=user,
                                 detail={'reason': data.get('reason', '管理员手动禁用'), 'old_level': old_level,
                                        'emby_disabled': emby_disabled, 'subscription_suspended': subscription_suspended})
                log_admin_audit('user_ban', detail=f'封禁用户 {user.name}', target_type='user', target_id=user.tg)
            else:
                log_user_activity(UserActivityLog.ACTION_LEVEL_CHANGE, user=user,
                                 detail={'old_level': old_level, 'new_level': new_level, 
                                        'old_level_name': level_names.get(old_level), 'new_level_name': level_names.get(new_level)})
                log_admin_audit('user_level_change', detail=f'修改用户 {user.name} 等级: {level_names.get(old_level)} → {level_names.get(new_level)}', target_type='user', target_id=user.tg)
            
            return jsonify({
                'success': True,
                'message': message,
                'old_level': old_level,
                'new_level': new_level,
                'emby_disabled': emby_disabled,
                'subscription_suspended': subscription_suspended
            }), 200
        else:
            return jsonify({
                'success': False,
                'error': '请指定有效的等级（a=白名单, b=普通, c=禁用）'
            }), 400
    except Exception as e:
        db.session.rollback()
        app.logger.error(f'设置用户等级失败: {e}')
        return jsonify({'success': False, 'error': str(e)}), 500


@app.route('/api/admin/users/<int:user_id>/ban-emby', methods=['POST'])
@admin_required
def admin_ban_emby(user_id):
    """手动封禁用户的 Emby 账号（不影响网站登录）
    
    仅禁用 Emby，不改 lv，用户仍可登录面板
    """
    try:
        user = db.session.get(User, user_id)
        if not user:
            return jsonify({'success': False, 'error': '用户不存在'}), 404
        
        if user.ban_reason:
            return jsonify({'success': False, 'error': 'Emby 已处于封禁状态'}), 400
        
        data = request.get_json(silent=True) or {}
        reason = data.get('reason', '管理员手动封禁Emby')
        
        # 保存封禁前状态
        user.ban_prev_lv = user.lv
        user.ban_prev_ex = user.ex
        user.ban_time = datetime.now()
        user.ban_reason = reason
        
        # 暂停活跃订阅
        active_subs = Subscription.query.filter_by(user_tg=user.tg, status='active').all()
        for sub in active_subs:
            sub.status = 'suspended'
        
        # 禁用 Emby 账号并踢出会话
        emby_disabled = False
        if user.embyid and emby_client.is_enabled():
            emby_disabled = emby_client.disable_user(user.embyid)
            emby_client.kill_user_sessions(user.embyid)
        
        db.session.commit()
        
        app.logger.info(f'管理员手动封禁Emby: 用户={user.name}, 原因={reason}')
        log_admin_audit('user_ban_emby', detail=f'封禁用户 {user.name} 的Emby账号，原因: {reason}', target_type='user', target_id=user.tg)
        
        return jsonify({
            'success': True,
            'message': f'已封禁用户 {user.name} 的 Emby 账号',
            'emby_disabled': emby_disabled
        }), 200
    except Exception as e:
        db.session.rollback()
        app.logger.error(f'封禁Emby失败: {e}')
        return jsonify({'success': False, 'error': str(e)}), 500


@app.route('/api/admin/users/<int:user_id>/unban-emby', methods=['POST'])
@admin_required
def admin_unban_emby(user_id):
    """解除用户的 Emby 封禁（仅清除 ban_reason 并恢复 Emby，不改 lv）"""
    try:
        user = db.session.get(User, user_id)
        if not user:
            return jsonify({'success': False, 'error': '用户不存在'}), 404
        
        if not user.ban_reason:
            return jsonify({'success': False, 'error': 'Emby 未处于封禁状态'}), 400
        
        # 清除封禁信息
        user.ban_reason = None
        user.ban_time = None
        user.ban_prev_lv = None
        user.ban_prev_ex = None
        
        # 恢复 Emby 账号
        emby_restored = False
        if user.embyid and emby_client.is_enabled():
            emby_restored = emby_client.enable_user(user.embyid)
        
        # 恢复暂停的订阅
        suspended_subs = Subscription.query.filter_by(user_tg=user.tg, status='suspended').all()
        for sub in suspended_subs:
            sub.status = 'active'
        
        # 解除设备黑名单
        blocked_devices = UserDevice.query.filter_by(user_tg=user.tg, is_blocked=True).all()
        unblocked_count = 0
        for device in blocked_devices:
            device.is_blocked = False
            unblocked_count += 1
        
        db.session.commit()
        
        app.logger.info(f'管理员解除Emby封禁: 用户={user.name}')
        log_admin_audit('user_unban_emby', detail=f'解除用户 {user.name} 的Emby封禁', target_type='user', target_id=user.tg)
        
        return jsonify({
            'success': True,
            'message': f'已解除用户 {user.name} 的 Emby 封禁',
            'emby_restored': emby_restored,
            'devices_unblocked': unblocked_count
        }), 200
    except Exception as e:
        db.session.rollback()
        app.logger.error(f'解除Emby封禁失败: {e}')
        return jsonify({'success': False, 'error': str(e)}), 500


@app.route('/api/admin/users/<int:user_id>/set-type', methods=['POST'])
@admin_required
def admin_set_user_type(user_id):
    """设置用户类型：白名单用户 / 订阅用户 / 非订阅用户
    
    - whitelist: 设为白名单用户 (lv='a')
    - subscribed: 设为订阅用户 (lv='b' + 写入有效期与订阅记录)
    - normal: 设为非订阅用户 (lv='b' + 清除订阅时间)
    """
    try:
        user = db.session.get(User, user_id)
        if not user:
            return jsonify({'success': False, 'error': '用户不存在'}), 404
        
        data = request.get_json(silent=True) or {}
        user_type = data.get('user_type')
        subscription_days = data.get('subscription_days', 30)  # 默认30天
        now = datetime.now()
        
        def _safe_int(value, default=30):
            try:
                value = int(value)
                return value if value > 0 else default
            except (ValueError, TypeError):
                return default
        
        # 支持 sub_basic, sub_standard 等格式
        plan_type_value = None
        matched_plan = None
        if user_type and user_type.startswith('sub_'):
            plan_type_value = user_type[4:]  # 提取 basic, standard 等
            matched_plan = resolve_plan_config(plan_type_value)
            if matched_plan and is_whitelist_plan_config(matched_plan):
                user_type = 'whitelist'  # 白名单套餐按白名单逻辑处理
                plan_type_value = 'whitelist'
            else:
                user_type = 'subscribed'  # 普通套餐按订阅用户处理
        
        if user_type not in ['whitelist', 'subscribed', 'normal']:
            return jsonify({'success': False, 'error': '无效的用户类型'}), 400
        
        # 验证订阅天数
        subscription_days = _safe_int(subscription_days, 30)
        
        old_level = user.lv
        old_ex = user.ex
        message = ''
        active_subscriptions = Subscription.query.filter_by(
            user_tg=user.tg,
            status='active'
        ).order_by(Subscription.end_date.desc(), Subscription.created_at.desc()).all()
        primary_active_sub = active_subscriptions[0] if active_subscriptions else None
        was_whitelist = user.lv == 'a' or (primary_active_sub and primary_active_sub.plan_type == 'whitelist')
        
        def _clear_ban_info():
            user.ban_reason = None
            user.ban_time = None
            user.ban_prev_lv = None
            user.ban_prev_ex = None
        
        def _cancel_extra_active_subs(keep_sub=None):
            for sub in active_subscriptions:
                if keep_sub and sub.id == keep_sub.id:
                    continue
                sub.status = 'cancelled'
                sub.updated_at = now
        
        def _upsert_active_subscription(plan_type, plan_name, end_date, source='manual', keep_existing=True):
            target_sub = primary_active_sub if keep_existing else None
            duration_months = -1 if plan_type == 'whitelist' else max(1, -(-max(1, (end_date - now).days) // 30))
            if target_sub:
                target_sub.plan_type = plan_type
                target_sub.plan_name = plan_name
                target_sub.duration_months = duration_months
                target_sub.price = 0
                target_sub.start_date = target_sub.start_date or now
                target_sub.end_date = end_date
                target_sub.status = 'active'
                target_sub.source = source
                target_sub.updated_at = now
            else:
                target_sub = Subscription(
                    user_tg=user.tg,
                    plan_type=plan_type,
                    plan_name=plan_name,
                    duration_months=duration_months,
                    price=0,
                    start_date=now,
                    end_date=end_date,
                    status='active',
                    source=source
                )
                db.session.add(target_sub)
            _cancel_extra_active_subs(target_sub)
            return target_sub
        
        if user_type == 'whitelist':
            # 设为白名单用户（lv='a' + 永久到期 + plan_type='whitelist'订阅记录）
            user.lv = 'a'
            user.ex = datetime(9999, 12, 31)  # 永久有效
            _clear_ban_info()
            _upsert_active_subscription('whitelist', '白名单用户', datetime(9999, 12, 31), source='manual')
            
            # 启用 Emby 账号（如果之前被禁用）
            if user.embyid and emby_client.is_enabled():
                emby_client.enable_user(user.embyid)
            
            message = '已设为白名单用户'
            
        elif user_type == 'subscribed':
            # 设为订阅用户：切换等级，同时写入有效期，保证列表页/详情页状态一致
            _clear_ban_info()
            
            # 如果指定了套餐ID，更新或创建 Subscription 记录
            plan_name = '订阅用户'
            effective_days = subscription_days
            if plan_type_value:
                if matched_plan:
                    plan_name = matched_plan.get('name') or plan_type_value
                    effective_days = _safe_int(matched_plan.get('duration_days'), effective_days)
                    plan_name = f'{plan_name}套餐'
                else:
                    plan_name = f'{plan_type_value}套餐'
            
            target_end = now + timedelta(days=effective_days)
            if not was_whitelist:
                if user.ex and user.ex > now:
                    target_end = max(target_end, user.ex)
                if primary_active_sub and primary_active_sub.end_date and primary_active_sub.end_date > now:
                    target_end = max(target_end, primary_active_sub.end_date)
            else:
                # 白名单降级为普通订阅时，不沿用 9999-12-31 的永久期限
                target_end = now + timedelta(days=effective_days)
            
            user.lv = 'b'
            user.ex = target_end
            _upsert_active_subscription(plan_type_value or 'manual', plan_name, target_end, source='manual')
            message = f'已设为{plan_name}用户'
            
            # 启用 Emby 账号（如果之前被禁用）
            if user.embyid and emby_client.is_enabled():
                emby_client.enable_user(user.embyid)
                
        elif user_type == 'normal':
            # 设为非订阅用户：普通等级 + 清除订阅
            user.lv = 'b'
            user.ex = None
            _clear_ban_info()
            _cancel_extra_active_subs(None)
            message = '已设为非订阅用户，订阅已清除'
        
        db.session.commit()
        
        # 记录日志
        log_user_activity(UserActivityLog.ACTION_LEVEL_CHANGE, user=user,
                         detail={'action': 'set_user_type', 'user_type': user_type,
                                'old_level': old_level, 'new_level': user.lv,
                                'old_ex': str(old_ex) if old_ex else None,
                                'new_ex': str(user.ex) if user.ex else None,
                                'subscription_days': subscription_days if user_type == 'subscribed' else None})
        
        app.logger.info(f'设置用户类型: {user.name}, type={user_type}, lv={old_level}->{user.lv}, ex={old_ex}->{user.ex}')
        
        return jsonify({
            'success': True,
            'message': message
        }), 200
        
    except Exception as e:
        db.session.rollback()
        app.logger.error(f'设置用户类型失败: {e}')
        return jsonify({'success': False, 'error': str(e)}), 500


@app.route('/api/admin/users/<int:user_id>/unban', methods=['POST'])
@admin_required
def admin_unban_user(user_id):
    """解除用户禁用（恢复本地账号和 Emby 账号，恢复原先的等级和到期时间）
    
    实时生效：解封后用户立即可以登录和观看
    """
    try:
        user = db.session.get(User, user_id)
        if not user:
            return jsonify({'success': False, 'error': '用户不存在'}), 404
        
        data = request.get_json(silent=True) or {}
        restore_original = data.get('restore_original', True)  # 默认恢复原先状态
        
        old_level = user.lv
        restored_info = {}
        
        if restore_original and user.ban_prev_lv:
            # 恢复封禁前的等级
            user.lv = user.ban_prev_lv
            restored_info['level'] = user.ban_prev_lv
            
            # 恢复封禁前的到期时间（保持原样，不自动延长）
            if user.ban_prev_ex:
                user.ex = user.ban_prev_ex
                restored_info['expires_at'] = user.ban_prev_ex.isoformat()
            
            # 清空封禁备份信息
            user.ban_prev_lv = None
            user.ban_prev_ex = None
            user.ban_time = None
            user.ban_reason = None
        else:
            # 没有备份信息，恢复为普通用户
            new_level = data.get('level', 'b')
            if new_level not in ['a', 'b']:
                new_level = 'b'
            user.lv = new_level
            restored_info['level'] = new_level
            # 清空封禁信息
            user.ban_prev_lv = None
            user.ban_prev_ex = None
            user.ban_time = None
            user.ban_reason = None
        
        # 恢复 Emby 账号
        emby_restored = False
        emby_error = None
        if user.embyid:
            if emby_client.is_enabled():
                emby_restored = emby_client.enable_user(user.embyid)
                if not emby_restored:
                    emby_error = 'Emby 账号启用失败，请在 Emby 后台手动启用'
                    app.logger.warning(f'解封用户 {user.name}: Emby 账号启用失败, embyid={user.embyid}')
            else:
                emby_error = 'Emby 未配置，请手动启用 Emby 账号'
                app.logger.warning(f'解封用户 {user.name}: Emby 未配置')
        else:
            app.logger.info(f'解封用户 {user.name}: 用户未绑定 Emby 账号')
        
        # 恢复用户的暂停订阅（suspended -> active）
        subscription_restored = False
        suspended_subscriptions = Subscription.query.filter_by(
            user_tg=user.tg,
            status='suspended'
        ).all()
        for sub in suspended_subscriptions:
            sub.status = 'active'
            subscription_restored = True
        
        # 解除该用户所有设备的黑名单状态
        blocked_devices = UserDevice.query.filter_by(user_tg=user.tg, is_blocked=True).all()
        unblocked_count = 0
        for device in blocked_devices:
            device.is_blocked = False
            unblocked_count += 1
        
        db.session.commit()
        
        level_names = {'a': '白名单', 'b': '普通用户', 'c': '禁用', 'd': '无账号'}
        new_level_name = level_names.get(user.lv, user.lv)
        
        app.logger.info(f'解除用户禁用: {user.name}, 等级 {old_level} -> {user.lv}, Emby恢复={emby_restored}, 订阅恢复={subscription_restored}, 解除设备={unblocked_count}')
        
        # 记录解封日志
        log_user_activity(UserActivityLog.ACTION_ACCOUNT_UNBANNED, user=user,
                         detail={'old_level': old_level, 'new_level': user.lv, 'emby_restored': emby_restored,
                                'subscription_restored': subscription_restored, 'devices_unblocked': unblocked_count})
        log_admin_audit('user_unban', detail=f'解封用户 {user.name}', target_type='user', target_id=user.tg)
        
        message = f'用户已解除禁用，等级恢复为{new_level_name}'
        if 'expires_at' in restored_info:
            message += f'，到期时间已恢复'
        if subscription_restored:
            message += '，订阅已恢复'
        if emby_error:
            message += f'\n⚠️ {emby_error}'
        
        return jsonify({
            'success': True,
            'message': message,
            'emby_restored': emby_restored,
            'emby_error': emby_error,
            'subscription_restored': subscription_restored,
            'devices_unblocked': unblocked_count,
            'restored': restored_info
        }), 200
    except Exception as e:
        db.session.rollback()
        app.logger.error(f'解除用户禁用失败: {e}')
        return jsonify({'success': False, 'error': str(e)}), 500


@app.route('/api/admin/users/<int:user_id>/reset-password', methods=['POST'])
@admin_required
def admin_reset_user_password(user_id):
    """管理员重置用户密码"""
    try:
        user = db.session.get(User, user_id)
        if not user:
            return jsonify({'success': False, 'error': '用户不存在'}), 404
        
        data = request.get_json(silent=True) or {}
        raw_password = data.get('password', '')
        if raw_password is None:
            raw_password = ''
        if not isinstance(raw_password, str):
            raw_password = str(raw_password)
        new_password = raw_password.strip()
        
        # 如果没有提供密码，生成随机密码
        if not new_password:
            import random
            import string
            new_password = ''.join(random.choices(string.ascii_letters + string.digits, k=8))
        
        # 验证密码长度
        if len(new_password) < 6 or len(new_password) > 32:
            return jsonify({'success': False, 'error': '密码长度必须在6-32个字符之间'}), 400
        
        user.pwd = new_password
        
        # 更新session_token，使用户的所有会话失效
        import secrets
        user.session_token = secrets.token_hex(32)
        
        db.session.commit()
        
        app.logger.info(f'管理员重置用户密码: {user.name}，用户已被强制退出登录')
        
        # 记录操作日志
        log_user_activity(UserActivityLog.ACTION_PASSWORD_CHANGE, user=user,
                         detail={'admin_reset': True, 'admin': session.get('admin_username', 'unknown')})
        log_admin_audit('user_reset_password', detail=f'重置用户 {user.name} 密码', target_type='user', target_id=user.tg)
        
        return jsonify({
            'success': True,
            'message': '密码重置成功',
            'new_password': new_password  # 返回新密码供管理员告知用户
        }), 200
    except Exception as e:
        db.session.rollback()
        app.logger.error(f'重置用户密码失败: {e}')
        return jsonify({'success': False, 'error': str(e)}), 500


@app.route('/api/admin/users/<int:user_id>/delete', methods=['DELETE'])
@admin_required
def admin_delete_user(user_id):
    """管理员删除用户账号（复用 hard_delete_user_data）"""
    try:
        user = db.session.get(User, user_id)
        if not user:
            return jsonify({'success': False, 'error': '用户不存在'}), 404
        
        # 防止删除管理员账户
        if user.is_admin:
            return jsonify({'success': False, 'error': '不能删除管理员账户'}), 400
        
        user_name = user.name
        
        # 调用通用硬删除函数
        result = hard_delete_user_data(user_id, reason='管理员手动删除')
        
        if result['db_deleted']:
            app.logger.info(f'管理员删除用户账号: {user_name} (tg={user_id}, emby_deleted={result["emby_deleted"]})')
            return jsonify({
                'success': True,
                'message': f'用户 {user_name} 已删除',
                'emby_deleted': result['emby_deleted']
            }), 200
        else:
            return jsonify({'success': False, 'error': '删除用户数据失败，请查看日志'}), 500
    except Exception as e:
        db.session.rollback()
        app.logger.error(f'删除用户账号失败: {e}')
        return jsonify({'success': False, 'error': str(e)}), 500


@app.route('/api/admin/users/<int:user_id>/details', methods=['GET'])
@admin_required
def admin_get_user_details(user_id):
    """管理员获取用户详细信息"""
    try:
        user = db.session.get(User, user_id)
        if not user:
            return jsonify({'success': False, 'error': '用户不存在'}), 404
        
        # 获取用户订阅信息
        subscriptions = Subscription.query.filter_by(user_tg=user.tg).order_by(
            Subscription.created_at.desc()
        ).limit(10).all()
        
        # 如果没有 Subscription 记录，但用户有有效的到期时间(user.ex)，补充创建一条记录
        if not subscriptions and user.ex and user.ex > datetime.now():
            # 尝试从订单表找到最近的已支付订单来确定套餐信息
            recent_order = Order.query.filter_by(
                user_tg=user.tg,
                payment_status='paid'
            ).order_by(Order.payment_time.desc()).first()
            
            if recent_order:
                # 根据订单创建订阅记录
                subscription = Subscription(
                    user_tg=user.tg,
                    plan_type=recent_order.plan_type,
                    plan_name=recent_order.plan_name,
                    duration_months=recent_order.duration_months,
                    price=recent_order.final_price,
                    start_date=recent_order.payment_time or datetime.now(),
                    end_date=user.ex,
                    status='active',
                    source='purchase'
                )
                db.session.add(subscription)
                db.session.commit()
                app.logger.info(f'[管理后台] 自动补充创建订阅记录: 用户={user.name}, 套餐={recent_order.plan_name}')
                subscriptions = [subscription]
            elif user.lv != 'a':  # 旧白名单用户兼容：不补充创建（已有whitelist订阅）
                # 没有订单记录，可能是管理员手动设置的，创建一个通用记录
                subscription = Subscription(
                    user_tg=user.tg,
                    plan_type='manual',
                    plan_name='订阅会员',
                    duration_months=max(1, (user.ex - datetime.now()).days // 30),
                    price=0,
                    start_date=user.cr or datetime.now(),
                    end_date=user.ex,
                    status='active',
                    source='manual'
                )
                db.session.add(subscription)
                db.session.commit()
                app.logger.info(f'[管理后台] 自动补充创建订阅记录(手动设置): 用户={user.name}')
                subscriptions = [subscription]
        
        # 获取用户订单信息
        orders = Order.query.filter_by(user_tg=user.tg).order_by(
            Order.created_at.desc()
        ).limit(10).all()
        
        # 获取用户求片记录
        requests = MovieRequest.query.filter_by(user_tg=user.tg).order_by(
            MovieRequest.created_at.desc()
        ).limit(10).all()
        
        # 获取用户设备信息
        devices = UserDevice.query.filter_by(user_tg=user.tg).order_by(
            UserDevice.last_active.desc()
        ).limit(10).all()
        
        # 获取邀请记录
        invite_records = InviteRecord.query.filter_by(inviter_tg=user.tg).order_by(
            InviteRecord.created_at.desc()
        ).limit(10).all()
        
        # 判断用户等级名称（考虑订阅状态）
        _detail_wl = Subscription.query.filter_by(user_tg=user.tg, plan_type='whitelist', status='active').first()
        _detail_wl_plan = resolve_plan_config(_detail_wl.plan_type) if _detail_wl else None
        if user.lv == 'c':
            level_name = '已禁用'
        elif (_detail_wl_plan and _detail_wl_plan.get('is_whitelist')) or user.lv == 'a' or (_detail_wl and _detail_wl.plan_type == 'whitelist'):
            level_name = '白名单'
        elif user.ex and user.ex > datetime.now():
            level_name = '订阅用户'
        else:
            level_name = '普通用户'
        
        # 判断是否是 BOT 管理员
        config = load_system_config()
        bot_admins_str = config.get('telegram', {}).get('bot_admins', '')
        bot_admin_ids = [x.strip() for x in bot_admins_str.split(',') if x.strip()]
        is_bot_admin = str(user.telegram_id) in bot_admin_ids if user.telegram_id else False
        
        # 获取签到配置和积分信息
        checkin_config = get_db_config('checkin', {})
        coin_name = checkin_config.get('coin_name', '积分')
        user_coins = user.coins if hasattr(user, 'coins') else 0
        
        return jsonify({
            'success': True,
            'coin_name': coin_name,  # 货币名称
            'user': {
                'id': user.tg,
                'name': user.name,
                'pwd': user.pwd or '',  # 网站密码（管理员查看用）
                'pwd2': user.pwd2 or '',  # Emby 密码（管理员查看用）
                'telegram_id': user.telegram_id,  # 只有绑定了才有值
                'emby_id': user.embyid,
                'emby_name': user.emby_name,  # Emby 用户名（独立字段）
                'level': user.lv,
                'level_name': level_name,
                'subscription_plan_type': (
                    'whitelist'
                    if ((_detail_wl_plan and _detail_wl_plan.get('is_whitelist')) or user.lv == 'a' or (_detail_wl and _detail_wl.plan_type == 'whitelist'))
                    else (
                        resolve_plan_config(subscriptions[0].plan_type).get('id')
                        if subscriptions and subscriptions[0].status == 'active' and resolve_plan_config(subscriptions[0].plan_type)
                        else (subscriptions[0].plan_type if subscriptions and subscriptions[0].status == 'active' else None)
                    )
                ),
                'is_admin': user.is_admin,
                'is_bot_admin': is_bot_admin,
                'email': user.email,  # 绑定邮箱
                'coins': user_coins,  # 用户积分
                'expires_at': user.ex.isoformat() if user.ex else None,
                'created_at': user.cr.isoformat() if user.cr else None,
                'invite_count': user.iv or 0,
                'invite_reward_mode': user.invite_reward_mode,
                'invite_reward_percent': user.invite_reward_percent,
                'ban_time': user.ban_time.isoformat() if user.ban_time else None,
                'ban_reason': user.ban_reason,
                'ban_prev_lv': user.ban_prev_lv,
                'ban_prev_ex': user.ban_prev_ex.isoformat() if user.ban_prev_ex else None
            },
            'subscriptions': [s.to_dict() for s in subscriptions],
            'orders': [o.to_dict() for o in orders],
            'requests': [{
                'id': r.id,
                'title': r.title,
                'year': r.year,
                'status': r.status,
                'media_type': r.media_type,
                'created_at': r.created_at.isoformat() if r.created_at else None
            } for r in requests],
            'devices': [{
                'id': d.id,
                'device_name': d.device_name,
                'client': d.client,
                'last_ip': d.last_ip,
                'is_blocked': d.is_blocked,
                'last_active': d.last_active.isoformat() if d.last_active else None
            } for d in devices],
            'invites': [{
                'id': i.id,
                'invitee_tg': i.invitee_tg,
                'invitee_name': (db.session.get(User, i.invitee_tg) or type('', (), {'name': '未知'})()).name,
                'reward_type': i.reward_type,
                'reward_value': i.reward_value,
                'reward_claimed': i.reward_claimed,
                'reward_mode': i.reward_mode,
                'custom_reward_percent': i.custom_reward_percent,
                'pending_reward': i.pending_reward or 0,
                'status': 'pending' if (i.pending_reward and i.pending_reward > 0) else ('approved' if i.reward_claimed else 'waiting'),
                'status_display': '待审核' if (i.pending_reward and i.pending_reward > 0) else ('已发放' if i.reward_claimed else '等待购买'),
                'created_at': i.created_at.isoformat() if i.created_at else None
            } for i in invite_records],
            # 该用户作为被邀请人的邀请记录（谁邀请了他）
            'invited_by': (lambda r: {
                'inviter_tg': r.inviter_tg,
                'inviter_name': (db.session.get(User, r.inviter_tg) or type('', (), {'name': '未知'})()).name,
                'reward_mode': r.reward_mode,
                'custom_reward_percent': r.custom_reward_percent,
                'reward_value': r.reward_value,
                'reward_claimed': r.reward_claimed,
                'pending_reward': r.pending_reward or 0,
                'status_display': '待审核' if (r.pending_reward and r.pending_reward > 0) else ('已发放' if r.reward_claimed else '等待购买')
            } if r else None)(InviteRecord.query.filter_by(invitee_tg=user.tg).first())
        }), 200
    except Exception as e:
        app.logger.error(f'获取用户详情失败: {e}')
        return jsonify({'success': False, 'error': str(e)}), 500


