@app.route('/api/admin/orders/<order_no>/mark-paid', methods=['POST'])
@admin_required
def admin_mark_order_paid(order_no):
    """管理员标记订单为已支付"""
    try:
        order = Order.query.filter_by(order_no=order_no).first()
        if not order:
            return jsonify({'success': False, 'error': '订单不存在'}), 404
        
        if order.payment_status == 'paid':
            return jsonify({'success': False, 'error': '订单已经是已支付状态'}), 400
        
        # 更新订单状态
        order.payment_status = 'paid'
        order.payment_time = datetime.now()
        order.payment_method = 'manual'  # 标记为人工处理
        
        # 创建订阅记录，逻辑与支付回调保持一致
        from datetime import timedelta
        user_tg = order.user_tg
        duration_months = order.duration_months or 1
        purchased_days = order.duration_days if order.duration_days else (duration_months * 30)
        
        user = db.session.get(User, user_tg)
        if not user:
            return jsonify({'success': False, 'error': '用户不存在'}), 404
        
        start_date = datetime.now()
        _mark_plan_type = order.plan_type
        _mark_plan_name = order.plan_name
        _mark_is_wl = is_whitelist_plan_key(order.plan_type)

        if _mark_is_wl:
            end_date = datetime(9999, 12, 31)
            _mark_plan_type = 'whitelist'
            _mark_plan_name = '白名单用户'
        elif user.ex and user.ex > start_date:
            end_date = user.ex + timedelta(days=purchased_days)
        else:
            end_date = start_date + timedelta(days=purchased_days)

        new_sub = Subscription(
            user_tg=user_tg,
            plan_type=_mark_plan_type,
            plan_name=_mark_plan_name,
            duration_months=duration_months,
            price=order.final_price,
            start_date=start_date,
            end_date=end_date,
            status='active',
            source='purchase'
        )
        db.session.add(new_sub)
        
        # 更新用户到期时间和等级
        user.ex = end_date
        if _mark_is_wl:
            user.lv = 'a'
        elif user.lv not in ['a', 'b', 'c']:
            user.lv = 'b'
        
        # 邀请返利：检查是否有邀请人，给邀请人返利
        process_invite_reward(user, purchased_days, source='手工标记付款')
        
        db.session.commit()
        
        # 恢复Emby账号（封禁用户和黑名单禁用用户不自动恢复）
        if user.lv != 'c' and not user.ban_reason and user.embyid and emby_client.is_enabled():
            if emby_client.enable_user(user.embyid):
                app.logger.info(f'管理员手动标记付款，已恢复用户 {user.name} 的Emby账号')
        
        app.logger.info(f'管理员手动标记订单 {order_no} 为已支付，用户 {user.name} 订阅已生效，到期时间: {user.ex}')
        log_admin_audit('order_mark_paid', detail=f'手动标记订单 {order_no} 为已支付，用户 {user.name}', target_type='order', target_id=order_no)
        
        return jsonify({
            'success': True,
            'message': '订单已标记为已支付，订阅已生效'
        }), 200
    except Exception as e:
        db.session.rollback()
        app.logger.error(f'标记订单已支付失败: {e}')
        return jsonify({'success': False, 'error': str(e)}), 500


@app.route('/api/admin/orders/<order_no>/cancel', methods=['POST'])
@admin_required
def admin_cancel_order(order_no):
    """管理员取消订单"""
    try:
        from sqlalchemy import text
        
        # 使用SQL查询订单
        result = db.session.execute(
            text("SELECT * FROM orders WHERE order_no = :order_no"),
            {'order_no': order_no}
        ).fetchone()
        
        if not result:
            return jsonify({'success': False, 'error': '订单不存在'}), 404
        
        row = result._asdict() if hasattr(result, '_asdict') else dict(result._mapping)
        
        if row.get('payment_status') == 'paid':
            return jsonify({'success': False, 'error': '已支付订单无法取消'}), 400
        
        if row.get('payment_status') == 'cancelled':
            return jsonify({'success': False, 'error': '订单已经是取消状态'}), 400
        
        # 更新订单状态为取消
        db.session.execute(
            text("UPDATE orders SET payment_status = 'cancelled', updated_at = :now WHERE order_no = :order_no"),
            {'order_no': order_no, 'now': datetime.now()}
        )
        db.session.commit()
        
        app.logger.info(f'管理员取消订单 {order_no}')
        log_admin_audit('order_cancel', detail=f'取消订单 {order_no}', target_type='order', target_id=order_no)
        
        return jsonify({
            'success': True,
            'message': '订单已取消'
        }), 200
    except Exception as e:
        db.session.rollback()
        app.logger.error(f'取消订单失败: {e}')
        return jsonify({'success': False, 'error': str(e)}), 500


@app.route('/api/admin/users/<int:user_id>/gift-subscription', methods=['POST'])
@admin_required
def admin_gift_subscription(user_id):
    """管理员赠送订阅"""
    try:
        data = request.get_json(silent=True) or {}
        plan_type = data.get('plan_type', 'basic')
        duration_days = data.get('duration_days')  # 优先使用天数
        duration_months = data.get('duration_months', 1)
        
        user = db.session.get(User, user_id)
        if not user:
            return jsonify({'success': False, 'error': '用户不存在'}), 404
        
        from datetime import timedelta
        
        # 计算赠送天数（优先使用传入的天数，否则按月计算）
        if duration_days and int(duration_days) > 0:
            gift_days = int(duration_days)
        else:
            gift_days = 30 * duration_months
        now = datetime.now()  # 使用 timezone-naive datetime 以保持一致
        
        plan_names = {
            'basic': '基础版',
            'standard': '标准版',
            'premium': '高级版'
        }
        
        # 立即生效，在现有到期时间基础上叠加
        start_date = now
        if user.ex and user.ex > now:
            # 用户有未过期的到期时间，在此基础上叠加
            end_date = user.ex + timedelta(days=gift_days)
        else:
            # 用户没有有效期或已过期，从今天开始
            end_date = now + timedelta(days=gift_days)
        
        # 创建订阅记录
        gift_record = Subscription(
            user_tg=user.tg,
            plan_type=plan_type,
            plan_name=plan_names.get(plan_type, '基础版'),
            duration_months=duration_months,
            price=0,  # 赠送的免费
            start_date=start_date,
            end_date=end_date,
            status='active',
            source='gift'  # 标记为管理员赠送
        )
        db.session.add(gift_record)
        
        # 更新用户的到期时间
        user.ex = end_date
        
        # 确保用户等级为B（普通用户），但不降级白名单用户，封禁用户保持封禁状态
        if user.lv not in ['a', 'c']:
            user.lv = 'b'
        
        db.session.commit()
        
        # 恢复Emby账号（封禁用户和黑名单禁用用户不自动恢复）
        if user.lv != 'c' and not user.ban_reason and user.embyid and emby_client.is_enabled():
            if emby_client.enable_user(user.embyid):
                app.logger.info(f'用户 {user.name} 获赠订阅，已恢复Emby账号')
        
        app.logger.info(f'管理员赠送订阅: 用户={user.name}, 套餐={plan_type}, 天数={gift_days}, 新到期时间={user.ex}')
        
        # 记录操作日志
        log_user_activity(UserActivityLog.ACTION_SUBSCRIPTION_GIFT, user=user,
                         detail={'action': 'gift_subscription', 'plan_type': plan_type,
                                'gift_days': gift_days, 'new_ex': str(user.ex)})
        log_admin_audit('user_gift_subscription', detail=f'赠送用户 {user.name} {gift_days}天订阅', target_type='user', target_id=user.tg)
        
        return jsonify({
            'success': True,
            'message': f'已为用户赠送 {gift_days} 天订阅，到期时间：{user.ex.strftime("%Y-%m-%d %H:%M")}'
        }), 200
    except Exception as e:
        db.session.rollback()
        app.logger.error(f'赠送订阅失败: {e}')
        return jsonify({'success': False, 'error': str(e)}), 500


@app.route('/api/admin/users/<int:user_id>/reduce-subscription', methods=['POST'])
@admin_required
def admin_reduce_subscription(user_id):
    """管理员减少订阅时间"""
    try:
        data = request.get_json(silent=True) or {}
        duration_days = data.get('duration_days', 0)
        
        if not duration_days or int(duration_days) <= 0:
            return jsonify({'success': False, 'error': '请输入有效的天数'}), 400
        
        reduce_days = int(duration_days)
        
        user = db.session.get(User, user_id)
        if not user:
            return jsonify({'success': False, 'error': '用户不存在'}), 404
        
        from datetime import timedelta
        now = datetime.now()
        
        # 检查用户是否有有效订阅
        if not user.ex or user.ex <= now:
            return jsonify({'success': False, 'error': '用户当前没有有效订阅'}), 400
        
        # 计算减少后的到期时间
        new_ex = user.ex - timedelta(days=reduce_days)
        
        # 如果减少后的时间早于当前时间，则设为当前时间（立即过期）
        if new_ex <= now:
            new_ex = now
            message = f'已减少 {reduce_days} 天订阅，用户订阅已过期'
        else:
            remaining_days = (new_ex - now).days
            message = f'已减少 {reduce_days} 天订阅，剩余 {remaining_days} 天，到期时间：{new_ex.strftime("%Y-%m-%d %H:%M")}'
        
        user.ex = new_ex
        db.session.commit()
        
        # 如果订阅已过期，禁用Emby账号
        if new_ex <= now and user.embyid and emby_client.is_enabled():
            emby_client.disable_user(user.embyid)
            emby_client.kill_user_sessions(user.embyid)
            app.logger.info(f'用户 {user.name} 订阅过期，已禁用Emby账号')
        
        app.logger.info(f'管理员减少订阅: 用户={user.name}, 减少天数={reduce_days}, 新到期时间={user.ex}')
        
        # 记录操作日志
        log_user_activity(UserActivityLog.ACTION_SUBSCRIPTION_REDUCE, user=user,
                         detail={'action': 'reduce_subscription', 'reduce_days': reduce_days,
                                'new_ex': str(user.ex), 'expired': new_ex <= now})
        log_admin_audit('user_reduce_subscription', detail=f'减少用户 {user.name} {reduce_days}天订阅', target_type='user', target_id=user.tg)
        
        return jsonify({
            'success': True,
            'message': message
        }), 200
    except Exception as e:
        db.session.rollback()
        app.logger.error(f'减少订阅失败: {e}')
        return jsonify({'success': False, 'error': str(e)}), 500


@app.route('/api/admin/users/<int:user_id>/adjust-coins', methods=['POST'])
@admin_required
def admin_adjust_coins(user_id):
    """管理员调整用户积分"""
    try:
        data = request.get_json(silent=True) or {}
        adjust_type = data.get('action')  # 'add' or 'reduce'
        amount = data.get('amount', 0)
        reason = data.get('reason', '')
        
        if adjust_type not in ['add', 'reduce']:
            return jsonify({'success': False, 'error': '无效的操作类型'}), 400
        
        if not amount or int(amount) <= 0:
            return jsonify({'success': False, 'error': '请输入有效的数量'}), 400
        
        amount = int(amount)
        
        user = db.session.get(User, user_id)
        if not user:
            return jsonify({'success': False, 'error': '用户不存在'}), 404
        
        # 获取积分名称
        config = load_system_config()
        checkin_config = config.get('checkin', {})
        coin_name = checkin_config.get('coin_name', '积分')
        
        old_coins = user.coins or 0
        
        if adjust_type == 'add':
            user.coins = old_coins + amount
            action_name = '增加'
        else:
            if old_coins < amount:
                return jsonify({'success': False, 'error': f'用户{coin_name}不足，当前仅有 {old_coins}'}), 400
            user.coins = old_coins - amount
            action_name = '减少'
        
        # 构建描述信息
        description = f'管理员{action_name}{amount}{coin_name}'
        if reason:
            description += f' - {reason}'
        
        # 记录积分交易
        transaction = CoinTransaction(
            user_tg=user.tg,
            amount=amount if adjust_type == 'add' else -amount,
            trans_type='admin_adjust',
            description=description,
            balance_after=user.coins
        )
        db.session.add(transaction)
        db.session.commit()
        
        app.logger.info(f'管理员调整{coin_name}: 用户={user.name}, 操作={action_name}, 数量={amount}, 原余额={old_coins}, 新余额={user.coins}')
        
        # 记录操作日志
        log_user_activity(UserActivityLog.ACTION_COIN_CHANGE, user=user,
                         detail={'action': 'admin_adjust', 'type': adjust_type,
                                'amount': amount, 'old_coins': old_coins,
                                'new_coins': user.coins, 'reason': reason,
                                'coin_name': coin_name})
        
        return jsonify({
            'success': True,
            'message': f'已{action_name} {amount} {coin_name}，当前余额：{user.coins}',
            'new_balance': user.coins
        }), 200
    except Exception as e:
        db.session.rollback()
        app.logger.error(f'调整积分失败: {e}')
        return jsonify({'success': False, 'error': str(e)}), 500


# 配置检查
def check_config():
    """检查关键配置项"""
    issues = []
    
    # 从数据库加载配置检查
    config = load_system_config()
    admin_config = config.get('admin', {})
    telegram_config = config.get('telegram', {})
    tmdb_config = config.get('tmdb', {})
    
    if not tmdb_config.get('api_key') and not TMDB_API_KEY:
        issues.append('TMDB_API_KEY 未配置，影片搜索功能将不可用')
    
    if not admin_config.get('username') or not admin_config.get('password'):
        issues.append('管理员账号密码未配置，请在后台设置或 .env 文件中配置')
    
    if not admin_config.get('secret_path') or admin_config.get('secret_path') == 'admin-secret-path':
        issues.append('管理后台安全入口未配置，请在后台设置或 .env 文件中配置')
    
    if not telegram_config.get('bot_token') and not TELEGRAM_BOT_TOKEN:
        issues.append('Telegram 通知未配置，求片通知将不会发送')
    
    if issues:
        app.logger.warning('配置检查发现以下问题:')
        for issue in issues:
            app.logger.warning(f'  - {issue}')
    else:
        app.logger.info('所有关键配置项检查通过 ✓')


# 数据库迁移：添加缺失的列
def migrate_database():
    """检查并添加数据库中缺失的列"""
    
    # 检测数据库类型
    is_mysql = 'mysql' in str(db.engine.url).lower()
    
    # 辅助函数：检查表是否存在
    def table_exists(table_name):
        try:
            if is_mysql:
                result = db.session.execute(db.text(f"""
                    SELECT COUNT(*) FROM information_schema.tables 
                    WHERE table_schema = DATABASE() AND table_name = '{table_name}'
                """)).fetchone()
                return result[0] > 0
            else:
                result = db.session.execute(db.text(f"""
                    SELECT COUNT(*) FROM sqlite_master 
                    WHERE type='table' AND name='{table_name}'
                """)).fetchone()
                return result[0] > 0
        except:
            return False
    
    # 辅助函数：检查列是否存在（使用直接查询方式）
    def column_exists(table_name, column_name):
        try:
            if is_mysql:
                # 方法1：使用 information_schema
                result = db.session.execute(db.text(f"""
                    SELECT COUNT(*) FROM information_schema.columns 
                    WHERE table_schema = DATABASE() 
                    AND table_name = '{table_name}' 
                    AND column_name = '{column_name}'
                """)).fetchone()
                if result[0] > 0:
                    return True
                # 方法2：尝试直接 SELECT 该列（作为备用检测）
                try:
                    db.session.execute(db.text(f"SELECT `{column_name}` FROM `{table_name}` LIMIT 0"))
                    return True
                except:
                    return False
            else:
                result = db.session.execute(db.text(f"PRAGMA table_info({table_name})")).fetchall()
                return any(row[1] == column_name for row in result)
        except Exception as e:
            app.logger.warning(f'检查列存在性失败 ({table_name}.{column_name}): {e}')
            return False
    
    migrations = [
        # (表名, 列名, 列定义 for MySQL, 列定义 for SQLite)
        ('emby', 'telegram_id', 'BIGINT NULL UNIQUE'),
        ('emby', 'is_banned', 'INTEGER DEFAULT 0'),
        ('emby', 'ban_reason', 'VARCHAR(500) NULL'),
        ('emby', 'invited_by', 'INTEGER NULL'),
        ('emby', 'invite_count', 'INTEGER DEFAULT 0'),
        ('emby', 'invite_reward_days', 'INTEGER DEFAULT 0'),
        ('emby', 'session_token', 'VARCHAR(64) NULL'),  # 用于强制用户退出登录
        # 工单表新字段
        ('support_tickets', 'last_reply_by', "VARCHAR(20) DEFAULT 'user'"),
        ('support_tickets', 'last_reply_at', 'DATETIME NULL'),
        # 订阅表来源字段
        ('subscriptions', 'source', "VARCHAR(20) DEFAULT 'purchase'"),
        # Emby用户名独立字段（与网站用户名分离）
        ('emby', 'emby_name', 'VARCHAR(255) NULL'),
        # 邀请记录表：返利模式和个性化返利比例
        ('invite_records', 'reward_mode', 'VARCHAR(20) NULL'),
        ('invite_records', 'custom_reward_percent', 'FLOAT NULL'),
        ('invite_records', 'pending_reward', 'FLOAT DEFAULT 0'),
        # User表个性化返利配置
        ('emby', 'invite_reward_mode', 'VARCHAR(20) NULL'),
        ('emby', 'invite_reward_percent', 'FLOAT NULL'),
        # User表邮箱字段
        ('emby', 'email', 'VARCHAR(255) NULL'),
        # 线路表套餐可见性字段
        ('server_lines', 'allowed_plan_types', "VARCHAR(500) DEFAULT ''"),
        # 订单表天数字段（支持自定义天数套餐）
        ('orders', 'duration_days', 'INTEGER NULL'),
        # 管理员表明文密码字段（子管理员密码供超级管理员查看）
        ('admin_users', 'password_plain', 'VARCHAR(255) NULL'),
    ]
    
    app.logger.info('开始检查数据库迁移...')
    app.logger.info(f'数据库类型: {"MySQL" if is_mysql else "SQLite"}')
    
    for table, column, definition in migrations:
        try:
            # 先检查表是否存在
            if not table_exists(table):
                app.logger.info(f'数据库迁移: 表 {table} 不存在，跳过列 {column}')
                continue
            
            # 检查列是否已存在
            exists = column_exists(table, column)
            app.logger.info(f'数据库迁移: 检查列 {table}.{column} 是否存在: {exists}')
            if exists:
                continue
            
            # 添加列
            try:
                sql = f"ALTER TABLE {table} ADD COLUMN {column} {definition}"
                app.logger.info(f'数据库迁移: 执行SQL: {sql}')
                db.session.execute(db.text(sql))
                db.session.commit()
                app.logger.info(f'数据库迁移: 成功添加列 {table}.{column}')
            except Exception as add_err:
                db.session.rollback()
                err_str = str(add_err).lower()
                # 如果是因为列已存在，忽略错误
                if 'duplicate' in err_str or 'already exists' in err_str or 'duplicate column' in err_str:
                    app.logger.info(f'数据库迁移: 列 {table}.{column} 已存在（通过异常检测）')
                else:
                    app.logger.error(f'数据库迁移失败 ({table}.{column}): {add_err}')
        except Exception as e:
            db.session.rollback()
            app.logger.error(f'数据库迁移异常 ({table}.{column}): {e}')
    
    # 数据迁移：将已有 embyid 用户的 name 复制到 emby_name（仅首次迁移时执行）
    try:
        if column_exists('emby', 'emby_name'):
            # 检查是否有 embyid 非空但 emby_name 为空的记录（需要迁移）
            result = db.session.execute(db.text(
                "SELECT COUNT(*) FROM emby WHERE embyid IS NOT NULL AND emby_name IS NULL AND name IS NOT NULL"
            )).fetchone()
            if result[0] > 0:
                db.session.execute(db.text(
                    "UPDATE emby SET emby_name = name WHERE embyid IS NOT NULL AND emby_name IS NULL AND name IS NOT NULL"
                ))
                db.session.commit()
                app.logger.info(f'数据迁移: 已将 {result[0]} 个用户的 name 复制到 emby_name')
    except Exception as e:
        db.session.rollback()
        app.logger.warning(f'数据迁移(emby_name)失败: {e}')
    
    # 签到系统表迁移
    _migrate_checkin_system()
    
    app.logger.info('数据库迁移检查完成')


def _migrate_checkin_system():
    """签到系统数据库迁移"""
    try:
        app.logger.info('开始签到系统迁移...')
        
        # 检测数据库类型
        is_mysql = 'mysql' in str(db.engine.url).lower()
        auto_increment = 'AUTO_INCREMENT' if is_mysql else 'AUTOINCREMENT'
        
        # 辅助函数：检查表是否存在
        def table_exists(table_name):
            try:
                if is_mysql:
                    result = db.session.execute(db.text(f"""
                        SELECT COUNT(*) FROM information_schema.tables 
                        WHERE table_schema = DATABASE() AND table_name = '{table_name}'
                    """)).fetchone()
                    return result[0] > 0
                else:
                    result = db.session.execute(db.text(f"""
                        SELECT COUNT(*) FROM sqlite_master 
                        WHERE type='table' AND name='{table_name}'
                    """)).fetchone()
                    return result[0] > 0
            except:
                return False
        
        # 辅助函数：检查列是否存在
        def column_exists(table_name, column_name):
            try:
                if is_mysql:
                    result = db.session.execute(db.text(f"""
                        SELECT COUNT(*) FROM information_schema.columns 
                        WHERE table_schema = DATABASE() 
                        AND table_name = '{table_name}' 
                        AND column_name = '{column_name}'
                    """)).fetchone()
                    return result[0] > 0
                else:
                    result = db.session.execute(db.text(f"PRAGMA table_info({table_name})")).fetchall()
                    return any(row[1] == column_name for row in result)
            except:
                return False
        
        # 1. 给 emby 表添加 coins 字段
        if not column_exists('emby', 'coins'):
            try:
                db.session.execute(
                    db.text("ALTER TABLE emby ADD COLUMN coins INTEGER DEFAULT 0")
                )
                db.session.commit()
                app.logger.info('签到系统迁移: 成功添加 emby.coins 字段')
            except Exception as e:
                db.session.rollback()
                if 'duplicate' not in str(e).lower() and 'already exists' not in str(e).lower():
                    app.logger.warning(f'添加 coins 字段警告: {e}')
        
        # 2. 创建签到记录表
        if not table_exists('checkin_records'):
            try:
                db.session.execute(db.text(f"""
                    CREATE TABLE IF NOT EXISTS checkin_records (
                        id INTEGER PRIMARY KEY {auto_increment},
                        user_tg BIGINT NOT NULL,
                        checkin_date DATE NOT NULL,
                        coins_earned INTEGER NOT NULL,
                        continuous_days INTEGER DEFAULT 1,
                        created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
                        UNIQUE(user_tg, checkin_date),
                        FOREIGN KEY (user_tg) REFERENCES emby (tg) ON DELETE CASCADE
                    )
                """))
                db.session.commit()
                app.logger.info('签到系统迁移: 成功创建 checkin_records 表')
            except Exception as e:
                db.session.rollback()
                if 'already exists' not in str(e).lower():
                    app.logger.warning(f'创建 checkin_records 表警告: {e}')
        
        # 3. 创建积分交易记录表
        if not table_exists('coin_transactions'):
            try:
                db.session.execute(db.text(f"""
                    CREATE TABLE IF NOT EXISTS coin_transactions (
                        id INTEGER PRIMARY KEY {auto_increment},
                        user_tg BIGINT NOT NULL,
                        amount INTEGER NOT NULL,
                        balance_after INTEGER NOT NULL,
                        trans_type VARCHAR(50) NOT NULL,
                        description TEXT,
                        related_id INTEGER,
                        created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
                        FOREIGN KEY (user_tg) REFERENCES emby (tg) ON DELETE CASCADE
                    )
                """))
                db.session.commit()
                app.logger.info('签到系统迁移: 成功创建 coin_transactions 表')
            except Exception as e:
                db.session.rollback()
                if 'already exists' not in str(e).lower():
                    app.logger.warning(f'创建 coin_transactions 表警告: {e}')
        
        # 4. 创建兑换记录表
        if not table_exists('exchange_records'):
            try:
                db.session.execute(db.text(f"""
                    CREATE TABLE IF NOT EXISTS exchange_records (
                        id INTEGER PRIMARY KEY {auto_increment},
                        user_tg BIGINT NOT NULL,
                        plan_id VARCHAR(50) NOT NULL,
                        plan_name VARCHAR(100) NOT NULL,
                        coins_cost INTEGER NOT NULL,
                        duration_days INTEGER NOT NULL,
                        status VARCHAR(20) DEFAULT 'completed',
                        created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
                        FOREIGN KEY (user_tg) REFERENCES emby (tg) ON DELETE CASCADE
                    )
                """))
                db.session.commit()
                app.logger.info('签到系统迁移: 成功创建 exchange_records 表')
            except Exception as e:
                db.session.rollback()
                if 'already exists' not in str(e).lower():
                    app.logger.warning(f'创建 exchange_records 表警告: {e}')
        
        # 5. 创建索引
        # MySQL 不支持 IF NOT EXISTS，需要分别处理
        if is_mysql:
            indexes = [
                ("idx_checkin_user_date", "checkin_records", "(user_tg, checkin_date)"),
                ("idx_checkin_date", "checkin_records", "(checkin_date)"),
                ("idx_transaction_user", "coin_transactions", "(user_tg, created_at)"),
                ("idx_transaction_type", "coin_transactions", "(trans_type)"),
                ("idx_exchange_user", "exchange_records", "(user_tg, created_at)")
            ]
            
            for index_name, table_name, columns in indexes:
                try:
                    # MySQL: 先检查索引是否存在
                    result = db.session.execute(db.text(f"""
                        SELECT COUNT(*) as cnt 
                        FROM information_schema.statistics 
                        WHERE table_schema = DATABASE() 
                        AND table_name = '{table_name}' 
                        AND index_name = '{index_name}'
                    """)).fetchone()
                    
                    if result[0] == 0:  # 索引不存在
                        db.session.execute(db.text(f"CREATE INDEX {index_name} ON {table_name}{columns}"))
                        db.session.commit()
                except Exception as e:
                    db.session.rollback()
                    if 'duplicate' not in str(e).lower() and 'already exists' not in str(e).lower():
                        app.logger.warning(f'创建索引 {index_name} 警告: {e}')
        else:
            # SQLite 支持 IF NOT EXISTS
            indexes = [
                "CREATE INDEX IF NOT EXISTS idx_checkin_user_date ON checkin_records(user_tg, checkin_date)",
                "CREATE INDEX IF NOT EXISTS idx_checkin_date ON checkin_records(checkin_date)",
                "CREATE INDEX IF NOT EXISTS idx_transaction_user ON coin_transactions(user_tg, created_at)",
                "CREATE INDEX IF NOT EXISTS idx_transaction_type ON coin_transactions(trans_type)",
                "CREATE INDEX IF NOT EXISTS idx_exchange_user ON exchange_records(user_tg, created_at)"
            ]
            
            for index_sql in indexes:
                try:
                    db.session.execute(db.text(index_sql))
                    db.session.commit()
                except Exception as e:
                    db.session.rollback()
                    if 'already exists' not in str(e).lower():
                        app.logger.warning(f'创建索引警告: {e}')
        
        app.logger.info('签到系统迁移完成 ✓')
        
    except Exception as e:
        db.session.rollback()
        app.logger.error(f'签到系统迁移失败: {e}', exc_info=True)


# 初始化数据库
def init_db():
    global db_initialized
    if db_initialized:
        return
    with app.app_context():
        try:
            # 只创建movie_requests表，emby表已经存在
            db.create_all()
            app.logger.info('数据库初始化成功')
            
            # 执行数据库迁移（添加缺失的列）
            migrate_database()
            
            # 修复播放记录中异常的进度数据（>100%的记录修正为100%）
            try:
                fixed = PlaybackRecord.query.filter(PlaybackRecord.play_percentage > 100).update(
                    {PlaybackRecord.play_percentage: 100.0}
                )
                if fixed > 0:
                    db.session.commit()
                    app.logger.info(f'已修复 {fixed} 条异常播放进度记录（>100%）')
            except Exception as e:
                db.session.rollback()
                app.logger.warning(f'修复异常播放进度失败: {e}')
            
            # 修复播放记录中异常的播放时长（play_duration > total_duration 的修正）
            try:
                fixed_dur = PlaybackRecord.query.filter(
                    PlaybackRecord.total_duration > 0,
                    PlaybackRecord.play_duration > PlaybackRecord.total_duration
                ).update(
                    {PlaybackRecord.play_duration: PlaybackRecord.total_duration},
                    synchronize_session=False
                )
                if fixed_dur > 0:
                    db.session.commit()
                    app.logger.info(f'已修复 {fixed_dur} 条异常播放时长记录（duration > total）')
            except Exception as e:
                db.session.rollback()
                app.logger.warning(f'修复异常播放时长失败: {e}')
            
            # 初始化管理员配置
            admin_config = init_admin_config()
            secret_path = admin_config.get('admin', {}).get('secret_path')
            if secret_path:
                app.logger.info(f"管理后台入口: /{secret_path}")
            
            # 重新从数据库加载配置到全局变量（确保数据库中的配置生效）
            update_global_system_config()
            app.logger.info('系统配置已从数据库加载')
            
            # 检查配置
            check_config()
            db_initialized = True
        except Exception as e:
            app.logger.error(f'数据库初始化失败: {e}', exc_info=True)
            raise


download_monitor = DownloadMonitor(app, DOWNLOAD_POLL_INTERVAL)


def auto_close_inactive_tickets():
    """自动关闭3天内管理员回复后用户未回复的工单"""
    with app.app_context():
        try:
            three_days_ago = datetime.now() - timedelta(days=3)
            
            # 查找处理中状态且管理员回复后3天用户未回复的工单
            tickets_to_close = SupportTicket.query.filter(
                SupportTicket.status == 'in_progress',
                SupportTicket.last_reply_by == 'admin',
                SupportTicket.last_reply_at < three_days_ago
            ).all()
            
            closed_count = 0
            for ticket in tickets_to_close:
                ticket.status = 'closed'
                ticket.resolved_at = datetime.now()
                closed_count += 1
                app.logger.info(f'自动关闭工单: {ticket.ticket_no} (3天未回复)')
            
            if closed_count > 0:
                db.session.commit()
                app.logger.info(f'自动关闭了 {closed_count} 个超时工单')
        except Exception as e:
            db.session.rollback()
            app.logger.error(f'自动关闭工单失败: {e}', exc_info=True)
        finally:
            db.session.remove()


# 工单自动关闭检查的时间戳
last_ticket_check_time = None


def bootstrap_background_tasks():
    """初始化数据库并启动下载监控"""
    global last_ticket_check_time
    if download_monitor.thread and download_monitor.thread.is_alive():
        return

    try:
        init_db()
    except Exception:
        pass

    should_start = True
    if app.debug:
        should_start = os.environ.get('WERKZEUG_RUN_MAIN') == 'true'
    if should_start:
        download_monitor.start()
        # 启动排行定时推送
        try:
            ranking_cfg = load_system_config().get('ranking', {})
            if ranking_cfg.get('push_enabled'):
                _restart_ranking_scheduler(ranking_cfg)
        except Exception as e:
            print(f'[WARNING] 启动排行定时推送失败: {e}')

last_subscription_check_time = None
last_expire_remind_time = None

# 数据库 key: 存储已发送提醒的记录，格式 {'date': '2026-02-10', 'keys': ['tg:days', ...]}
CONFIG_KEY_EXPIRE_REMIND_SENT = '_expire_remind_sent'


def check_subscription_expiry_reminders():
    """检查即将到期的订阅，发送到期提醒（邮件 + Telegram）"""
    with app.app_context():
        try:
            config = load_system_config()
            remind_cfg = config.get('expire_remind', {})
            
            if not remind_cfg.get('enabled', False):
                return
            
            remind_days_list = remind_cfg.get('days', [3, 7])  # 提前多少天提醒
            site_name = get_site_config().get('site_name', 'Emby')
            now = datetime.now()
            today_str = now.strftime('%Y-%m-%d')
            reminded_count = 0
            
            # ★ 从数据库读取已发送记录（持久化，容器重建不丢失）
            sent_data = get_db_config(CONFIG_KEY_EXPIRE_REMIND_SENT, {}) or {}
            # 如果日期不是今天，说明是新的一天，清空旧记录
            if sent_data.get('date') != today_str:
                sent_data = {'date': today_str, 'keys': []}
            sent_keys = set(sent_data.get('keys', []))
            new_keys_added = False
            
            for remind_days in remind_days_list:
                # 查找在 remind_days 天后过期的用户（按日期匹配整天，确保不会遗漏）
                target_date = (now + timedelta(days=remind_days)).date()
                expire_start = datetime(target_date.year, target_date.month, target_date.day, 0, 0, 0)
                expire_end = datetime(target_date.year, target_date.month, target_date.day, 23, 59, 59)
                
                users = User.query.filter(
                    User.lv.in_(['a', 'b']),
                    User.ex >= expire_start,
                    User.ex <= expire_end,
                    User.embyid.isnot(None),
                    User.embyid != ''
                ).all()
                
                for user in users:
                    # ★ 去重：从数据库读取，同一天同一用户只提醒一次
                    remind_key = f'{user.tg}:{remind_days}'
                    if remind_key in sent_keys:
                        continue
                    sent_keys.add(remind_key)
                    new_keys_added = True
                    
                    username = user.name or '用户'
                    expire_date = user.ex.strftime('%Y-%m-%d') if user.ex else '未知'
                    
                    # 邮件提醒
                    if remind_cfg.get('email', True) and user.email:
                        try:
                            body = f"""<p>您好，<b>{username}</b>！</p>
<p>您的 Emby 订阅将在 <b>{remind_days} 天后</b>（{expire_date}）到期。</p>
<div style="background:#fff3cd;border-left:4px solid #ffc107;padding:12px 16px;border-radius:4px;margin:16px 0;">
    <p style="margin:0;"><b>⏰ 到期时间：</b>{expire_date}</p>
    <p style="margin:4px 0 0;"><b>💡 建议：</b>请及时续费以免影响观影体验</p>
</div>
<p>您可以登录网站进行续费，或使用兑换码延长订阅。</p>"""
                            html = build_email_html(f'{site_name} - 订阅即将到期', body, site_name)
                            send_email(user.email, f'【{site_name}】您的订阅将在{remind_days}天后到期', html)
                            reminded_count += 1
                        except Exception as e:
                            app.logger.debug(f'到期提醒邮件发送失败({username}): {e}')
                    
                    # Telegram 提醒
                    if remind_cfg.get('telegram', True) and user.telegram_id and TELEGRAM_BOT_TOKEN:
                        try:
                            msg = f"""⏰ <b>订阅到期提醒</b>

您好 <code>{username}</code>，您的 Emby 订阅将在 <b>{remind_days} 天后</b>到期。

📅 到期时间：{expire_date}
💡 请及时续费以免影响观影体验！"""
                            send_telegram_private_message(user.telegram_id, msg)
                            reminded_count += 1
                        except Exception as e:
                            app.logger.debug(f'到期提醒TG发送失败({username}): {e}')
            
            # ★ 把已发送记录写回数据库（持久化，容器重建也不会重发）
            if new_keys_added:
                sent_data = {'date': today_str, 'keys': list(sent_keys)}
                set_db_config(CONFIG_KEY_EXPIRE_REMIND_SENT, sent_data, '到期提醒已发送记录')
            
            if reminded_count > 0:
                app.logger.info(f'订阅到期提醒: 已发送 {reminded_count} 条提醒')
                
        except Exception as e:
            app.logger.error(f'订阅到期提醒检查失败: {e}', exc_info=True)
        finally:
            db.session.remove()


def check_expired_subscriptions():
    """检查订阅到期用户并禁用/删除其Emby账号（含保号自动续期逻辑）"""
    with app.app_context():
        try:
            now = datetime.now()
            
            # 获取订阅过期配置
            config = load_system_config()
            expire_config = config.get('subscription_expire', {})
            auto_disable = expire_config.get('auto_disable', True)
            delete_days = expire_config.get('delete_days', 0)
            delete_web_account = expire_config.get('delete_web_account', False)
            
            # 保号配置
            retention_mode = expire_config.get('retention_mode', 'off')
            retention_checkin_days = expire_config.get('retention_checkin_days', 20)
            retention_checkin_cost = expire_config.get('retention_checkin_cost', 10)
            retention_watch_days = expire_config.get('retention_watch_days', 30)
            retention_watch_minutes = expire_config.get('retention_watch_minutes', 30)
            retention_renew_days = expire_config.get('retention_renew_days', 30)
            
            # 获取签到货币名称（用于日志和交易记录）
            checkin_config = config.get('checkin', {})
            coin_name = checkin_config.get('coin_name', '积分')
            
            # 查找需要处理的用户：
            # 1. 普通用户(lv='b') + 有Emby账号
            # 2. 订阅已过期(ex < now) 或 从未订阅(ex=None)
            from sqlalchemy import or_
            expired_users = User.query.filter(
                User.lv == 'b',  # 普通用户
                User.embyid.isnot(None),  # 有Emby账号
                or_(
                    User.ex.is_(None),  # 从未订阅
                    User.ex < now  # 已过期
                )
            ).all()
            
            if not expired_users:
                return
            
            # 立即提交/结束查询事务，释放行锁，避免后续慢操作持锁
            db.session.commit()
            
            app.logger.info(f'[订阅检查] 发现 {len(expired_users)} 个无有效订阅用户')
            
            disabled_count = 0
            emby_deleted_count = 0
            web_deleted_count = 0
            retention_count = 0
            
            for user in expired_users:
                try:
                    # 二次确认：重新从数据库读取最新状态，防止竞态条件
                    # （用户可能在查询后刚续费，此时不应被禁用）
                    db.session.refresh(user)
                    # 白名单用户跳过（通过订阅记录判断）
                    _expire_wl = Subscription.query.filter_by(user_tg=user.tg, plan_type='whitelist', status='active').first()
                    if _expire_wl or user.lv == 'a':
                        continue
                    if user.ex and user.ex > datetime.now():  # 已续费，跳过
                        continue
                    if not user.embyid:  # 已无Emby账号，跳过
                        continue
                    
                    # ==================== 保号检查 ====================
                    # 仅对刚过期（严格72小时内）的用户执行保号检查，避免对长期过期用户重复续期
                    expired_seconds = (now - user.ex).total_seconds() if user.ex else None
                    days_expired = int(expired_seconds // 86400) if expired_seconds is not None and expired_seconds >= 0 else 999
                    recently_expired = (
                        expired_seconds is not None and
                        0 <= expired_seconds <= 3 * 24 * 3600
                    )
                    
                    if retention_mode != 'off' and recently_expired:
                        retention_ok = _check_user_retention(
                            user, now, retention_mode,
                            retention_checkin_days, retention_checkin_cost,
                            retention_watch_days, retention_watch_minutes,
                            retention_renew_days, coin_name
                        )
                        if retention_ok:
                            retention_count += 1
                            continue  # 已自动续期，跳过禁用/删除
                    # ==================== 保号检查结束 ====================
                    
                    # 如果配置了删除天数，且过期超过该天数，则删除 Emby 账号
                    if delete_days > 0 and user.ex and days_expired >= delete_days:
                        user_name = user.emby_name or user.name
                        user_tg = user.tg
                        emby_id = user.embyid
                        
                        # 删除 Emby 账号
                        if emby_id and emby_client.is_enabled():
                            try:
                                emby_client.delete_user(emby_id)
                                emby_deleted_count += 1
                                app.logger.info(f'[订阅检查] 已删除Emby账号: {user_name}')
                            except Exception as e:
                                app.logger.warning(f'[订阅检查] 删除Emby账号失败: {e}')
                        
                        # 如果配置了同时删除网站账号
                        if delete_web_account:
                            # 删除相关记录
                            # 先删除播放记录（有外键引用 user_devices 和 emby）
                            PlaybackRecord.query.filter_by(user_tg=user_tg).delete(synchronize_session=False)
                            UserDevice.query.filter_by(user_tg=user_tg).delete()
                            Subscription.query.filter_by(user_tg=user_tg).delete()
                            Order.query.filter_by(user_tg=user_tg).delete()
                            # 删除下载任务（先删除，因为有外键引用 movie_requests）
                            request_ids = [r.id for r in MovieRequest.query.filter_by(user_tg=user_tg).all()]
                            if request_ids:
                                DownloadTask.query.filter(DownloadTask.request_id.in_(request_ids)).delete(synchronize_session=False)
                            MovieRequest.query.filter_by(user_tg=user_tg).delete()
                            # 删除工单（先删除工单消息）
                            ticket_ids = [t.id for t in SupportTicket.query.filter_by(user_tg=user_tg).all()]
                            if ticket_ids:
                                TicketMessage.query.filter(TicketMessage.ticket_id.in_(ticket_ids)).delete(synchronize_session=False)
                            SupportTicket.query.filter_by(user_tg=user_tg).delete()
                            InviteRecord.query.filter((InviteRecord.inviter_tg == user_tg) | (InviteRecord.invitee_tg == user_tg)).delete(synchronize_session=False)
                            UserActivityLog.query.filter_by(user_tg=user_tg).delete()
                            # 删除签到记录
                            CheckInRecord.query.filter_by(user_tg=user_tg).delete()
                            # 删除积分交易记录
                            CoinTransaction.query.filter_by(user_tg=user_tg).delete()
                            # 删除兑换记录
                            ExchangeRecord.query.filter_by(user_tg=user_tg).delete()
                            # 清除兑换码使用者引用
                            RedeemCode.query.filter_by(used_by=user_tg).update({'used_by': None}, synchronize_session=False)
                            
                            # 删除用户
                            db.session.delete(user)
                            web_deleted_count += 1
                            app.logger.info(f'[订阅检查] 已删除网站账号: {user_name} (过期{days_expired}天)')
                        else:
                            # 只清除 Emby 绑定信息，保留网站账号（网站用户名 name 保持不变）
                            user.embyid = None
                            user.emby_name = None
                            user.pwd2 = None
                            app.logger.info(f'[订阅检查] 已解绑Emby账号: {user_name} (过期{days_expired}天)，网站账号保留')
                        
                        db.session.commit()
                    
                    # 否则只禁用账号（如果启用了自动禁用）
                    elif auto_disable:
                        if emby_client.is_enabled() and emby_client.disable_user(user.embyid):
                            # 同时踢出该用户的所有播放会话
                            emby_client.kill_user_sessions(user.embyid)
                            disabled_count += 1
                            app.logger.info(f'[订阅检查] 已禁用过期用户Emby账号: {user.emby_name or user.name} (过期时间: {user.ex})')
                            
                except Exception as e:
                    db.session.rollback()
                    app.logger.error(f'[订阅检查] 处理用户 {user.emby_name or user.name} 失败: {e}')
            
            if disabled_count > 0:
                app.logger.info(f'[订阅检查] 本次共禁用 {disabled_count} 个过期用户的Emby账号')
            if emby_deleted_count > 0:
                app.logger.info(f'[订阅检查] 本次共删除 {emby_deleted_count} 个Emby账号')
            if web_deleted_count > 0:
                app.logger.info(f'[订阅检查] 本次共删除 {web_deleted_count} 个网站账号')
            if retention_count > 0:
                app.logger.info(f'[订阅检查] 本次保号自动续期 {retention_count} 个用户')
                
        except Exception as e:
            db.session.rollback()
            app.logger.error(f'[订阅检查] 检查过期订阅失败: {e}')
        finally:
            db.session.remove()


def _check_user_retention(user, now, mode, checkin_days, checkin_cost,
                          watch_days, watch_minutes, renew_days, coin_name):
    """检查用户是否满足保号条件，满足则自动续期并扣费
    
    Args:
        user: User 对象
        now: 当前时间
        mode: 'checkin' / 'watch' / 'both'
        checkin_days: （已弃用，保留兼容）
        checkin_cost: 积分保号自动扣除的积分（积分足够即可续期）
        watch_days: 观看保号检查的天数范围
        watch_minutes: 观看保号要求的累计观看分钟数
        renew_days: 续期天数
        coin_name: 货币名称
    
    Returns:
        True 如果保号成功（已续期），False 如果不满足条件
    """
    user_name = user.emby_name or user.name
    
    try:
        # 并发保护：对用户行加锁，避免多线程/多进程重复保号导致重复扣分
        try:
            locked_user = (
                User.query.filter_by(tg=user.tg)
                .with_for_update()
                .populate_existing()
                .first()
            )
        except Exception:
            # 某些数据库（如 SQLite）不支持 FOR UPDATE，回退普通查询
            locked_user = User.query.filter_by(tg=user.tg).first()

        if not locked_user:
            return False

        user = locked_user
        user_name = user.emby_name or user.name

        # 二次校验：并发场景下，其他线程可能已完成续期
        if not user.ex or user.ex > now:
            return False
        expired_seconds = (now - user.ex).total_seconds()
        if expired_seconds < 0 or expired_seconds > 3 * 24 * 3600:
            return False

        # ===== 签到保号检查 =====
        checkin_ok = False
        if mode in ('checkin', 'both'):
            # 只检查积分是否足够，不再要求签到天数
            if (user.coins or 0) >= checkin_cost:
                checkin_ok = True
            else:
                app.logger.info(f'[保号] {user_name}: {coin_name}不足({user.coins or 0}<{checkin_cost})，不续期')
                if mode == 'checkin':
                    return False
        
        # ===== 观看保号检查 =====
        watch_ok = False
        if mode in ('watch', 'both'):
            from datetime import timedelta
            watch_since = now - timedelta(days=watch_days)
            
            # 查询观看时长（秒）
            # play_duration 存的是播放位置，同一媒体多条记录会重复累加
            # 对每个 emby_item_id 取 MAX(play_duration)，再求和
            from sqlalchemy import func
            duration_rows = db.session.query(
                func.max(PlaybackRecord.play_duration)
            ).filter(
                PlaybackRecord.user_tg == user.tg,
                PlaybackRecord.started_at >= watch_since
            ).group_by(
                PlaybackRecord.emby_item_id
            ).all()
            total_seconds = sum(r[0] or 0 for r in duration_rows)
            
            total_minutes = total_seconds / 60
            
            if total_minutes >= watch_minutes:
                watch_ok = True
            else:
                app.logger.info(f'[保号] {user_name}: 观看{total_minutes:.0f}分钟 < 要求{watch_minutes}分钟，不续期')
                if mode == 'watch':
                    return False
        
        # ===== 判断最终结果 =====
        if mode == 'checkin' and checkin_ok:
            pass  # 满足签到保号
        elif mode == 'watch' and watch_ok:
            pass  # 满足观看保号
        elif mode == 'both' and checkin_ok and watch_ok:
            pass  # 满足双保
        else:
            if mode == 'both':
                app.logger.info(f'[保号] {user_name}: 双保条件不同时满足（签到:{checkin_ok}, 观看:{watch_ok}），不续期')
            return False
        
        # ===== 执行续期 =====
        from datetime import timedelta
        # 从过期时间起续期（而不是从当前时间），保证不丢天数
        new_ex = (user.ex or now) + timedelta(days=renew_days)
        user.ex = new_ex
        
        # 同步更新 Subscription 表中的 end_date（修复网页显示负数天数的问题）
        active_sub = Subscription.query.filter_by(
            user_tg=user.tg, status='active'
        ).order_by(Subscription.end_date.desc()).first()
        if active_sub:
            active_sub.end_date = new_ex
            active_sub.updated_at = now
        
        # 签到保号需要扣积分
        if mode in ('checkin', 'both') and checkin_cost > 0:
            user.coins = (user.coins or 0) - checkin_cost
            # 记录积分交易
            try:
                coin_tx = CoinTransaction(
                    user_tg=user.tg,
                    amount=-checkin_cost,
                    balance_after=user.coins,
                    trans_type='retention',
                    description=f'保号自动续期{renew_days}天，扣除{checkin_cost}{coin_name}',
                    created_at=now
                )
                db.session.add(coin_tx)
            except Exception:
                pass  # 积分记录失败不影响续期
        
        db.session.commit()
        
        # 保号续期成功后，重新启用 Emby 账号（可能在之前的检查周期中被禁用）
        if user.embyid and emby_client.is_enabled():
            try:
                if emby_client.enable_user(user.embyid):
                    app.logger.info(f'[保号] {user_name}: 已重新启用Emby账号')
            except Exception as e:
                app.logger.warning(f'[保号] {user_name}: 重新启用Emby账号失败: {e}')
        
        cost_info = f'，扣除{checkin_cost}{coin_name}' if mode in ('checkin', 'both') and checkin_cost > 0 else ''
        app.logger.info(f'[保号] ✅ {user_name}: 保号成功，续期{renew_days}天至{new_ex.strftime("%Y-%m-%d")}{cost_info}')
        return True
        
    except Exception as e:
        db.session.rollback()
        app.logger.error(f'[保号] {user_name}: 保号检查异常: {e}')
        return False


@app.before_request
def ensure_background_tasks():
    global last_ticket_check_time, last_subscription_check_time, last_expire_remind_time
    bootstrap_background_tasks()
    
    # 轻量级授权状态检查（不发起网络请求，仅检查缓存状态）
    if not is_license_valid():
        # 仅对 API 和页面请求返回错误，静态资源放行
        if not request.path.startswith('/static/'):
            _v, _r = check_license()
            if not _v:
                if request.path.startswith('/api/'):
                    return jsonify({'success': False, 'error': '系统授权异常'}), 503
    
    now = datetime.now()
    
    # 每小时检查一次工单自动关闭（避免频繁检查）
    if last_ticket_check_time is None or (now - last_ticket_check_time).total_seconds() > 3600:
        last_ticket_check_time = now
        # 在后台线程中执行，避免阻塞请求
        from threading import Thread
        Thread(target=auto_close_inactive_tickets, daemon=True).start()
    
    # 每1小时检查一次订阅过期（禁用Emby账号）
    if last_subscription_check_time is None or (now - last_subscription_check_time).total_seconds() > 3600:
        last_subscription_check_time = now
        from threading import Thread
        Thread(target=check_expired_subscriptions, daemon=True).start()
    
    # 每6小时检查一次订阅到期提醒
    if last_expire_remind_time is None or (now - last_expire_remind_time).total_seconds() > 21600:
        last_expire_remind_time = now
        from threading import Thread
        Thread(target=check_subscription_expiry_reminders, daemon=True).start()


# ==================== 播放限制调试 API ====================
@app.route('/api/admin/debug/stream-limit', methods=['GET'])
@admin_required
def debug_stream_limit():
    """调试：查看播放限制配置和所有用户的实际 Emby Policy"""
    try:
        config = load_system_config()
        max_streams = config.get('telegram', {}).get('max_streams', 0)
        
        result = {
            'config_max_streams': max_streams,
            'emby_enabled': emby_client.is_enabled(),
            'users': []
        }
        
        if not emby_client.is_enabled():
            return jsonify({'success': True, **result}), 200
        
        # 获取所有有 embyid 的用户
        users = User.query.filter(User.embyid.isnot(None), User.embyid != '').limit(50).all()
        params = {'api_key': emby_client.api_key}
        
        for user in users:
            user_data = {
                'name': user.name,
                'embyid': user.embyid,
                'lv': user.lv,
                'policy': None,
                'error': None
            }
            try:
                url = f"{emby_client.base_url}/Users/{user.embyid}"
                response = emby_client.session.get(url, params=params, timeout=10)
                if response.status_code == 200:
                    user_info = response.json()
                    policy = user_info.get('Policy', {})
                    user_data['policy'] = {
                        'SimultaneousStreamLimit': policy.get('SimultaneousStreamLimit', '未设置'),
                        'MaxActiveSessions': policy.get('MaxActiveSessions', '未设置'),
                        'IsDisabled': policy.get('IsDisabled'),
                        'IsAdministrator': policy.get('IsAdministrator'),
                    }
                    # 列出 Policy 中所有包含 Stream/Session/Limit 的键
                    user_data['policy']['_all_stream_keys'] = {
                        k: v for k, v in policy.items() 
                        if any(word in k.lower() for word in ['stream', 'session', 'limit', 'simultaneous', 'max'])
                    }
                else:
                    user_data['error'] = f'HTTP {response.status_code}'
            except Exception as e:
                user_data['error'] = str(e)
            
            result['users'].append(user_data)
        
        return jsonify({'success': True, **result}), 200
    except Exception as e:
        return jsonify({'success': False, 'error': str(e)}), 500


@app.route('/api/admin/debug/stream-limit/sync', methods=['GET', 'POST'])
@admin_required
def debug_stream_limit_sync():
    """调试：手动触发同步播放限制到所有 Emby 用户（支持 GET/POST）"""
    try:
        config = load_system_config()
        max_streams = config.get('telegram', {}).get('max_streams', 0)
        
        if not max_streams or max_streams <= 0:
            return jsonify({'success': False, 'error': f'当前 max_streams={max_streams}，未设置限制'}), 400
        
        sync_result = emby_client.sync_all_users_stream_limit(max_streams)
        
        return jsonify({
            'success': True,
            'max_streams': max_streams,
            'sync_result': sync_result,
            'message': f'已同步 max_streams={max_streams} 到 {sync_result["success"]}/{sync_result["total"]} 个用户'
        }), 200
    except Exception as e:
        return jsonify({'success': False, 'error': str(e)}), 500


@app.route('/api/admin/debug/stream-limit/sessions', methods=['GET'])
@admin_required
def debug_stream_limit_sessions():
    """调试：查看当前所有正在播放的 Emby 会话
    
    用于确认 Webhook 限流逻辑是否正常工作：
    - 如果有4个会话在播放而 max_streams=2，说明 Webhook 没有触发
    - 检查 Emby 是否正确配置了 playback Webhook
    """
    try:
        if not emby_client.is_enabled():
            return jsonify({'success': False, 'error': 'Emby 未启用'}), 400
        
        config = load_system_config()
        max_streams = config.get('telegram', {}).get('max_streams', 0)
        
        # 获取所有活跃会话
        url = f"{emby_client.base_url}/Sessions"
        params = {'api_key': emby_client.api_key}
        response = emby_client.session.get(url, params=params, timeout=10)
        
        if response.status_code != 200:
            return jsonify({'success': False, 'error': f'Emby API 返回 {response.status_code}'}), 500
        
        sessions = response.json()
        playing = []
        idle = []
        
        for s in sessions:
            info = {
                'session_id': s.get('Id'),
                'user_name': s.get('UserName', '未知'),
                'user_id': s.get('UserId', ''),
                'device_name': s.get('DeviceName', '未知'),
                'client': s.get('Client', '未知'),
                'last_activity': s.get('LastActivityDate', ''),
                'remote_ip': s.get('RemoteEndPoint', ''),
            }
            now_playing = s.get('NowPlayingItem')
            if now_playing:
                info['now_playing'] = now_playing.get('Name', '未知')
                info['play_state'] = s.get('PlayState', {})
                playing.append(info)
            else:
                idle.append(info)
        
        # 按用户分组统计正在播放数
        user_playing_count = {}
        for p in playing:
            uid = p['user_id']
            uname = p['user_name']
            if uid not in user_playing_count:
                user_playing_count[uid] = {'name': uname, 'count': 0, 'sessions': []}
            user_playing_count[uid]['count'] += 1
            user_playing_count[uid]['sessions'].append(f"{p['device_name']}({p['client']})")
        
        # 找出超限用户
        over_limit = []
        if max_streams > 0:
            for uid, info in user_playing_count.items():
                if info['count'] > max_streams:
                    over_limit.append({
                        'user': info['name'],
                        'playing': info['count'],
                        'limit': max_streams,
                        'devices': info['sessions']
                    })
        
        return jsonify({
            'success': True,
            'config_max_streams': max_streams,
            'total_sessions': len(sessions),
            'playing_count': len(playing),
            'idle_count': len(idle),
            'playing_sessions': playing,
            'user_summary': user_playing_count,
            'over_limit_users': over_limit,
            'webhook_hint': '如果有用户超限但没有被限流，说明 Emby 的 playback Webhook 没有正确配置。'
                           '请确保 Emby 通知中添加了 Webhook，URL 为 /api/webhook/emby/playback，'
                           '事件类型勾选了 Playback Start 和 Playback Progress。'
        }), 200
    except Exception as e:
        return jsonify({'success': False, 'error': str(e)}), 500


# ==================== 设备黑名单管理 API ====================
@app.route('/api/admin/device-blacklist', methods=['GET'])
@admin_required
def get_device_blacklist():
    """获取所有黑名单规则"""
    try:
        rules = DeviceBlacklist.query.order_by(DeviceBlacklist.created_at.desc()).all()
        return jsonify({
            'success': True,
            'rules': [rule.to_dict() for rule in rules]
        }), 200
    except Exception as e:
        app.logger.error(f'获取黑名单规则失败: {e}')
        return jsonify({'success': False, 'error': str(e)}), 500


@app.route('/api/admin/device-blacklist', methods=['POST'])
@admin_required
def create_blacklist_rule():
    """创建黑名单规则"""
    try:
        data = request.json
        
        rule = DeviceBlacklist(
            rule_name=data.get('rule_name', ''),
            client_pattern=data.get('client_pattern', ''),
            device_name_pattern=data.get('device_name_pattern', ''),
            action=data.get('action', 'stop_only'),
            is_enabled=data.get('is_enabled', True),
            description=data.get('description', '')
        )
        
        db.session.add(rule)
        db.session.commit()
        
        app.logger.info(f'创建黑名单规则: {rule.rule_name}')
        
        return jsonify({
            'success': True,
            'rule': rule.to_dict()
        }), 200
    except Exception as e:
        app.logger.error(f'创建黑名单规则失败: {e}')
        db.session.rollback()
        return jsonify({'success': False, 'error': str(e)}), 500


@app.route('/api/admin/device-blacklist/<int:rule_id>', methods=['PUT'])
@admin_required
def update_blacklist_rule(rule_id):
    """更新黑名单规则"""
    try:
        rule = db.session.get(DeviceBlacklist, rule_id)
        if not rule:
            return jsonify({'success': False, 'error': '规则不存在'}), 404
        
        data = request.json
        rule.rule_name = data.get('rule_name', rule.rule_name)
        rule.client_pattern = data.get('client_pattern', rule.client_pattern)
        rule.device_name_pattern = data.get('device_name_pattern', rule.device_name_pattern)
        rule.action = data.get('action', rule.action)
        rule.is_enabled = data.get('is_enabled', rule.is_enabled)
        rule.description = data.get('description', rule.description)
        
        db.session.commit()
        
        app.logger.info(f'更新黑名单规则: {rule.rule_name}')
        
        return jsonify({
            'success': True,
            'rule': rule.to_dict()
        }), 200
    except Exception as e:
        app.logger.error(f'更新黑名单规则失败: {e}')
        db.session.rollback()
        return jsonify({'success': False, 'error': str(e)}), 500


@app.route('/api/admin/device-blacklist/<int:rule_id>', methods=['DELETE'])
@admin_required
def delete_blacklist_rule(rule_id):
    """删除黑名单规则"""
    try:
        rule = db.session.get(DeviceBlacklist, rule_id)
        if not rule:
            return jsonify({'success': False, 'error': '规则不存在'}), 404
        
        rule_name = rule.rule_name
        db.session.delete(rule)
        db.session.commit()
        
        app.logger.info(f'删除黑名单规则: {rule_name}')
        
        return jsonify({'success': True}), 200
    except Exception as e:
        app.logger.error(f'删除黑名单规则失败: {e}')
        db.session.rollback()
        return jsonify({'success': False, 'error': str(e)}), 500


if __name__ == '__main__':
    init_db()
    
    # 初始化管理员配置（首次启动会生成默认配置）
    admin_config = init_admin_config()
    secret_path = admin_config.get('admin', {}).get('secret_path')
    if secret_path:
        print(f"[INFO] 管理后台入口: /{secret_path}")
    
    bootstrap_background_tasks()
    # 从环境变量读取运行配置
    debug_mode = os.getenv('FLASK_DEBUG', 'False').lower() == 'true'
    host = os.getenv('FLASK_HOST', '0.0.0.0')
    port = int(os.getenv('FLASK_PORT', 5000))
    
    app.logger.info(f'Emby Request v{APP_VERSION} 启动开发服务器: {host}:{port} (Debug={debug_mode})')
    print(f'\n  🎬 Emby Request v{APP_VERSION}')
    print(f'  🌐 http://{host}:{port}\n')
    app.run(debug=debug_mode, host=host, port=port)
else:
    # Gunicorn 等 WSGI 服务器启动时的初始化
    print(f'\n  🎬 Emby Request v{APP_VERSION}')
    init_db()
    admin_config = init_admin_config()
    secret_path = admin_config.get('admin', {}).get('secret_path')
    if secret_path:
        print(f"[INFO] 管理后台入口: /{secret_path}")
    # 在 Gunicorn 导入阶段不启动后台线程，避免 --preload 下线程在 master 进程提前启动。
    # 后台任务会在 before_request 中按需启动。
    app.logger.info('跳过 Gunicorn 导入阶段后台线程启动，等待首个请求后启动')
    app.logger.info(f'Emby Request v{APP_VERSION} (Gunicorn) 启动完成')
